class CursorWrapper:
    def __init__(self, cursor):
        self._cursor = cursor

    def execute(self, query, params=None):
        if params is not None:
            self._cursor.execute(query, params)
        else:
            self._cursor.execute(query)
        return self

    def fetchone(self):
        return self._cursor.fetchone()

    def fetchall(self):
        return self._cursor.fetchall()
        
    @property
    def description(self):
        return self._cursor.description
        
    def close(self):
        self._cursor.close()

class ConnectionWrapper:
    def __init__(self, conn):
        self._conn = conn

    def cursor(self):
        return CursorWrapper(self._conn.cursor(cursor_factory=DictCursor))

    def execute(self, query, params=None):
        cur = self.cursor()
        cur.execute(query, params)
        return cur
        
    def commit(self):
        self._conn.commit()
        
    def close(self):
        self._conn.close()
def parse_lang_tag(lang_raw):
    """Smarter splitting: handle lang:filename OR filename.ext"""
    lang = lang_raw
    filename = ""
    if ":" in lang_raw:
        lang, filename = lang_raw.split(":", 1)
    elif "." in lang_raw:
        filename = lang_raw
        ext = lang_raw.split(".")[-1].lower()
        ext_map = {
            "py": "python", "js": "javascript", "html": "html", "css": "css", 
            "md": "markdown", "sql": "sql", "sh": "bash", "json": "json",
            "yml": "yaml", "yaml": "yaml", "c": "c", "cpp": "cpp", "java": "java",
            "rb": "ruby", "go": "go", "rs": "rust", "ts": "typescript"
        }
        lang = ext_map.get(ext, ext)
    return lang, filename

class database:
    @staticmethod
    def get_db_connection():
        database_url = os.environ.get("DATABASE_URL", "").strip()
        if not database_url:
            raise RuntimeError("DATABASE_URL is required.")
        if not psycopg2:
            raise RuntimeError("psycopg2/psycopg2-binary is required for PostgreSQL.")
        conn = psycopg2.connect(database_url, sslmode='require')
        return ConnectionWrapper(conn)

