import requests, json
from html.parser import HTMLParser

class DDGParser(HTMLParser):
    def __init__(self):
        super().__init__()
        self.results = []
        self.current_result = {}
        self.in_result_title = False
        self.in_result_snippet = False
        self.a_href = None
    
    def handle_starttag(self, tag, attrs):
        attrs = dict(attrs)
        if tag == "a" and "class" in attrs and "result-link" in attrs["class"]:
            self.a_href = attrs.get("href", "")
            self.in_result_title = True
            self.current_result["url"] = self.a_href
        elif tag == "td" and "class" in attrs and "result-snippet" in attrs["class"]:
            self.in_result_snippet = True
    
    def handle_data(self, data):
        if self.in_result_title:
            self.current_result["title"] = self.current_result.get("title", "") + data.strip()
        elif self.in_result_snippet:
            self.current_result["snippet"] = self.current_result.get("snippet", "") + data.strip() + " "
    
    def handle_endtag(self, tag):
        if tag == "a" and self.in_result_title:
            self.in_result_title = False
        elif tag == "td" and self.in_result_snippet:
            self.in_result_snippet = False
            if "title" in self.current_result and "url" in self.current_result:
                self.results.append(self.current_result)
            self.current_result = {}

