    @staticmethod
    def get_public_bots(search='', tag='', sort='featured', limit=24, offset=0):
        bots = [b for b in database.get_bots().values() if b.get('is_public')]
        search = (search or '').strip().lower()
        tag = (tag or '').strip().lower()
        if search:
            def _matches(bot):
                haystack = " ".join([
                    bot.get('name') or '',
                    bot.get('tagline') or '',
                    bot.get('description') or '',
                    bot.get('tags') or '',
                    bot.get('creator_name') or '',
                ]).lower()
                return search in haystack
            bots = [b for b in bots if _matches(b)]
        if tag:
            bots = [
                b for b in bots
                if tag in [t.strip().lower() for t in (b.get('tags') or '').split(',') if t.strip()]
            ]

        if sort == 'popular':
            bots.sort(key=lambda b: (int(b.get('chat_count') or 0), b.get('name') or ''), reverse=True)
        elif sort == 'new':
            bots.sort(key=lambda b: (b.get('created_at') or '', b.get('name') or ''), reverse=True)
        else:
            bots.sort(
                key=lambda b: (
                    int(b.get('featured') or 0),
                    int(b.get('chat_count') or 0),
                    b.get('name') or ''
                ),
                reverse=True
            )
        return bots[offset:offset + limit]

    @staticmethod
    def get_featured_public_bots(limit=8):
        bots = [b for b in database.get_bots().values() if b.get('is_public')]
        featured = [b for b in bots if b.get('featured')]
        featured.sort(key=lambda b: (int(b.get('chat_count') or 0), b.get('name') or ''), reverse=True)
        if len(featured) < limit:
            used_ids = {b['id'] for b in featured}
            fillers = [b for b in bots if b['id'] not in used_ids]
            fillers.sort(key=lambda b: (int(b.get('chat_count') or 0), b.get('name') or ''), reverse=True)
            featured.extend(fillers[:max(0, limit - len(featured))])
        return featured[:limit]

    @staticmethod
    def get_public_tag_counts(limit=12):
        counts = {}
        for bot in database.get_bots().values():
            if not bot.get('is_public'):
                continue
            for raw_tag in (bot.get('tags') or '').split(','):
                tag = raw_tag.strip()
                if not tag:
                    continue
                counts[tag] = counts.get(tag, 0) + 1
        ranked = sorted(counts.items(), key=lambda item: (-item[1], item[0].lower()))
        return [{"tag": tag, "count": count, "query": quote(tag)} for tag, count in ranked[:limit]]

    @staticmethod
    def get_related_public_bots(bot_id, limit=6):
        source = database.get_bot(bot_id)
        if not source:
            return []
        source_tags = {t.strip().lower() for t in (source.get('tags') or '').split(',') if t.strip()}
        candidates = [
            b for b in database.get_bots().values()
            if b.get('is_public') and b.get('id') != bot_id
        ]
        def _score(bot):
            tags = {t.strip().lower() for t in (bot.get('tags') or '').split(',') if t.strip()}
            overlap = len(source_tags.intersection(tags))
            return (overlap, int(bot.get('chat_count') or 0), bot.get('name') or '')
        candidates.sort(key=_score, reverse=True)
        if source_tags:
            candidates = [b for b in candidates if _score(b)[0] > 0] + [b for b in candidates if _score(b)[0] == 0]
        return candidates[:limit]

