    @staticmethod
    def get_conversation(conv_id):
        conn = database.get_db_connection()
        row = conn.execute("""
            SELECT c.*, b.instructions as system_prompt, b.photo as bot_photo, b.name as bot_name 
            FROM conversations c 
            LEFT JOIN bots b ON c.bot_id = b.id 
            WHERE c.id = %s
        """, (conv_id,)).fetchone()

        if row:
            conv = dict(row)
            branches = conn.execute("SELECT * FROM branches WHERE conversation_id = %s", (conv_id,)).fetchall()
            conv['branches'] = {b['name']: dict(b) for b in branches}
            for b in conv['branches'].values():
                b['history'] = json.loads(b['history']) if b['history'] else []
            conn.close()
            return conv
        conn.close()
        return None

    @staticmethod
    def get_user_conversations(user_id, chat_type=None):
        conn = database.get_db_connection()
        if chat_type:
            rows = conn.execute("""
                SELECT c.*, b.instructions as system_prompt, b.photo as bot_photo, b.name as bot_name
                FROM conversations c
                LEFT JOIN bots b ON c.bot_id = b.id
                WHERE c.user_id = %s AND (c.chat_type = %s OR (c.chat_type IS NULL AND %s = 'chat'))
                ORDER BY c.updated_at DESC
            """, (user_id, chat_type, chat_type)).fetchall()
        else:
            rows = conn.execute("""
                SELECT c.*, b.instructions as system_prompt, b.photo as bot_photo, b.name as bot_name
                FROM conversations c
                LEFT JOIN bots b ON c.bot_id = b.id
                WHERE c.user_id = %s
                ORDER BY c.updated_at DESC
            """, (user_id,)).fetchall()

        res = {}
        for r in rows:
            conv = dict(r)
            branches = conn.execute("SELECT * FROM branches WHERE conversation_id = %s", (conv['id'],)).fetchall()
            conv['branches'] = {b['name']: dict(b) for b in branches}
            for b in conv['branches'].values():
                b['history'] = json.loads(b['history']) if b['history'] else []
            res[conv['id']] = conv
        conn.close()
        return res

