    @staticmethod
    def delete_conversation(cid):
        conn = database.get_db_connection()
        # 1. Clean up associated attachments (DB and Disk)
        row = conn.execute("SELECT chat_code FROM conversations WHERE id = %s", (cid,)).fetchone()
        if row and row['chat_code']:
            chat_code = row['chat_code']
            # Get paths for physical deletion
            att_rows = conn.execute("SELECT path FROM attachments WHERE chat_code = %s", (chat_code,)).fetchall()
            for att_r in att_rows:
                if att_r['path'] and os.path.exists(att_r['path']):
                    try:
                        os.remove(att_r['path'])
                    except Exception as e:
                        print(f"Error deleting file {att_r['path']}: {e}")
            # Delete attachment entries
            conn.execute("DELETE FROM attachments WHERE chat_code = %s", (chat_code,))

        # 2. Delete branches and conversation
        conn.execute("DELETE FROM branches WHERE conversation_id = %s", (cid,))
        conn.execute("DELETE FROM conversations WHERE id = %s", (cid,))
        conn.commit()
        conn.close()

