    @staticmethod
    def update_canvas_content(cid, content):
        conn = database.get_db_connection()
        # 1. Update global conversation state (Current View)
        conn.execute("UPDATE conversations SET canvas_content = %s WHERE id = %s", (content, cid))
        
        # 2. Update the ACTIVE branch's canvas content (History Persistence)
        row = conn.execute("SELECT active_branch FROM conversations WHERE id = %s", (cid,)).fetchone()
        if row:
            active_branch = row['active_branch']
            conn.execute("UPDATE branches SET canvas_content = %s WHERE conversation_id = %s AND name = %s", 
                         (content, cid, active_branch))
            
        conn.commit()
        conn.close()

    @staticmethod
    def save_canvas_artifact(art_id, conv_id, branch_name, title, art_type, content, lang=None):
        import json
        import re
        
        # Extract title from OAI([title here])OAI if present (TEXT ONLY)
        if art_type == "text":
            title_match = re.search(r'OAI\((.*?)\)OAI', content)
            if title_match:
                title = title_match.group(1).strip()
                print(f"[DB DEBUG] OAI Title Override (Text): {title}")

        # Don't save if content is basically empty or just a prompt
        stripped = content.strip()
        if not stripped:
            print(f"[DB DEBUG] Skipping save for empty/whitespace-only artifact: {art_id}")
            return None
            
        # Common terminal prompts to ignore
        prompt_patterns = [r'^❯\s*$', r'^\$\s*$', r'^>\s*$']
        if any(re.match(p, stripped) for p in prompt_patterns):
            print(f"[DB DEBUG] Skipping save for prompt-only artifact: {art_id} content={repr(stripped)}")
            return None

        conn = database.get_db_connection()
        surplus = None
        
        # Check if artifact exists to append to history, else create new
        row = conn.execute("SELECT history_json FROM canvas_artifacts WHERE id = %s", (art_id,)).fetchone()
        if row and row['history_json']:
            try:
                history = json.loads(row['history_json'])
                if history:
                    last_version = history[-1]
                    if content.startswith(last_version) and content != last_version:
                        # Polluted artifact detected! It's a super-string of the previous version.
                        surplus = content[len(last_version):]
                        print(f"[DB DEBUG] Pollution detected for {art_id}. Surplus: {repr(surplus)}")
                        # We do NOT append the polluted version to history.
                    elif last_version != content:
                        history.append(content)
                else:
                    history = [content]
            except Exception as e:
                print(f"[DB DEBUG] Error processing history for {art_id}: {e}")
                history = [content]
        else:
            history = [content]
            
        history_json = json.dumps(history)
        
        print(f"[DB DEBUG] save_canvas_artifact: id={art_id}, conv={conv_id}, title={title}, type={art_type}, len={len(content)}")
        try:
            conn.execute("""
                INSERT INTO canvas_artifacts (id, conversation_id, branch_name, title, type, lang, history_json)
                VALUES (%s, %s, %s, %s, %s, %s, %s)
                ON CONFLICT(id) DO UPDATE SET 
                    history_json = excluded.history_json,
                    updated_at = CURRENT_TIMESTAMP,
                    title = excluded.title,
                    lang = excluded.lang
            """, (art_id, conv_id, branch_name, title, art_type, lang, history_json))
            conn.commit()
            print(f"[DB DEBUG] save_canvas_artifact: SUCCESS for {art_id}")
        except Exception as e:
            print(f"[DB DEBUG] save_canvas_artifact: ERROR saving {art_id}: {e}")
        finally:
            conn.close()
        return surplus

    @staticmethod
    def apply_str_replace(conv_id, title, old_str, new_str):
        import json
        import re
        conv_id = (conv_id or "").strip()
        print(f"[STR_REPLACE DEBUG] DB-Driven. conv_id={conv_id!r}, title={title!r}")
        
        conn = database.get_db_connection()
        
        # Find the most recently updated artifact for this conversation matching the title
        if title:
            search_title = title.strip().lower()
            safe_title = search_title.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
            
            row = conn.execute(
                """SELECT * FROM canvas_artifacts 
                   WHERE LOWER(conversation_id) = LOWER(%s) 
                   AND (LOWER(title) = %s OR LOWER(title) = %s) 
                   ORDER BY updated_at DESC LIMIT 1""",
                (conv_id, search_title, safe_title)
            ).fetchone()
            
            # Fallback: Try matching without extension or as base name
            if not row:
                # If search_title is "hello_world" and artifact is "hello_world.py"
                search_pattern = search_title + ".%"
                row = conn.execute(
                    """SELECT * FROM canvas_artifacts 
                       WHERE LOWER(conversation_id) = LOWER(%s) 
                       AND (LOWER(title) LIKE %s OR LOWER(title) = %s OR LOWER(title) = %s) 
                       ORDER BY updated_at DESC LIMIT 1""",
                    (conv_id, search_pattern.lower(), search_title, safe_title)
                ).fetchone()
                
                # If search_title is "hello_world.py" and artifact is "hello_world"
                if not row and "." in search_title:
                    base_title = search_title.rsplit('.', 1)[0]
                    safe_base = base_title.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
                    row = conn.execute(
                        """SELECT * FROM canvas_artifacts 
                           WHERE LOWER(conversation_id) = LOWER(%s) 
                           AND (LOWER(title) = %s OR LOWER(title) = %s) 
                           ORDER BY updated_at DESC LIMIT 1""",
                        (conv_id, base_title.lower(), safe_base.lower())
                    ).fetchone()
        else:
            row = conn.execute(
                "SELECT * FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) ORDER BY updated_at DESC LIMIT 1",
                (conv_id,)
            ).fetchone()
        
        if not row:
            conn.close()
            return None, None, f"No artifact found to edit (title: {title})"
            
        art_id = row['id']
        art_title = row['title']
        history_json_str = row['history_json']
        
        try:
            history = json.loads(history_json_str) if history_json_str else []
        except Exception:
            history = []
            
        if not history:
            conn.close()
            return None, None, "Artifact has no content history"
            
        current_text = history[-1]
        
        # Exact matching logic
        if old_str not in current_text:
            # 2. Fuzzy matching (Handling whitespace, MathJax markers, and special chars)
            tokens = re.findall(r'\w+|[^\w\s]', old_str, re.UNICODE)
            if tokens:
                # Fuzzy gap allows whitespace and common MathJax/Internal markers
                fuzzy_gap = r'(?:\s+|%MMATH_INLINE_[a-zA-Z0-9]*u[0-9a-fA-F]{4})*'
                
                def get_token_pattern(token):
                    escaped = re.escape(token)
                    # Handle dashes (match any dash or internal dash marker)
                    if token in ['-', '\u2013', '\u2014']:
                        return r'(?:[-\u2013\u2014]|%MMATH_INLINE_[a-zA-Z0-9]*u201[34])'
                    # Handle quotes
                    if token in ['"', '“', '”']:
                        return r'["“”]'
                    if token in ["'", '‘', '’']:
                        return r"['‘’]"
                    return escaped
                
                try:
                    pattern_str = fuzzy_gap.join(get_token_pattern(t) for t in tokens)
                    match = re.search(pattern_str, current_text)
                    if match:
                        new_history_text = current_text[:match.start()] + new_str + current_text[match.end():]
                        history.append(new_history_text)
                        
                        # Check for OAI Title update (TEXT ONLY)
                        if row['type'] == 'text':
                            title_match = re.search(r'OAI\((.*?)\)OAI', new_history_text)
                            if title_match:
                                new_title = title_match.group(1).strip()
                                conn.execute("UPDATE canvas_artifacts SET history_json = %s, title = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s", 
                                             (json.dumps(history), new_title, art_id))
                                print(f"[STR_REPLACE DEBUG] OAI Title Updated (Fuzzy) to: {new_title}")
                                art_title = new_title
                            else:
                                conn.execute("UPDATE canvas_artifacts SET history_json = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s", (json.dumps(history), art_id))
                        else:
                            conn.execute("UPDATE canvas_artifacts SET history_json = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s", (json.dumps(history), art_id))
                        
                        conn.commit()
                        conn.close()
                        print(f"[STR_REPLACE DEBUG] SUCCESS via Robust Fuzzy Match. match_range=({match.start()}, {match.end()})")
                        return art_title, new_history_text, None
                except Exception as e:
                    print(f"[STR_REPLACE DEBUG] Error during fuzzy match: {e}")
            
            conn.close()
            print(f"[STR_REPLACE DEBUG] ERROR: old_str not found in current_text. old_str={old_str!r}")
            return None, None, f"Text not found in artifact \"{art_title}\". Please ensure you are providing a unique and identifying snippet."
            
        new_history_text = current_text.replace(old_str, new_str)
        history.append(new_history_text)
        
        # Check for OAI Title update (TEXT ONLY)
        if row['type'] == 'text':
            title_match = re.search(r'OAI\((.*?)\)OAI', new_history_text)
            if title_match:
                new_title = title_match.group(1).strip()
                conn.execute("UPDATE canvas_artifacts SET history_json = %s, title = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s", 
                             (json.dumps(history), new_title, art_id))
                print(f"[STR_REPLACE DEBUG] OAI Title Updated to: {new_title}")
                art_title = new_title
            else:
                conn.execute("UPDATE canvas_artifacts SET history_json = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s", (json.dumps(history), art_id))
        else:
            conn.execute("UPDATE canvas_artifacts SET history_json = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s", (json.dumps(history), art_id))
            
        conn.commit()
        conn.close()
        
        print(f"[STR_REPLACE DEBUG] SUCCESS! Replaced {old_str!r} with {new_str!r} in artifact '{art_title}'")
        return art_title, new_history_text, None

