    @staticmethod
    def find_user_attachment_by_name(user_id, filename):
        """Search ALL of a user's attachments by display_name or filename (case-insensitive)."""
        if not user_id or not filename:
            return None
        conn = database.get_db_connection()
        fname_lower = filename.strip().lower()
        # Get all attachments for this user and search in Python (more reliable than SQLite LOWER())
        rows = conn.execute(
            "SELECT * FROM attachments WHERE user_id = %s",
            (user_id,)
        ).fetchall()
        conn.close()

        # Search by exact match on display_name or filename (case-insensitive)
        for row in rows:
            item = dict(row)
            dn = (item.get('display_name') or '').strip().lower()
            fn = (item.get('filename') or '').strip().lower()
            if dn == fname_lower or fn == fname_lower:
                # Also check basename match (ignore path prefix)
                if item.get('metadata'):
                    try: item.update(json.loads(item['metadata']))
                    except: pass
                return item

        # Fallback: try basename match (in case full path was passed)
        basename = os.path.basename(filename).lower()
        for row in rows:
            item = dict(row)
            dn = (item.get('display_name') or '').strip().lower()
            fn = (item.get('filename') or '').strip().lower()
            if os.path.basename(dn) == basename or os.path.basename(fn) == basename:
                if item.get('metadata'):
                    try: item.update(json.loads(item['metadata']))
                    except: pass
                return item

        return None

