_rate_limit_lock = threading.Lock()
_rate_limit_window = {}


def _validate_hosted_configuration():
    required_env = {
        "DATABASE_URL": os.environ.get("DATABASE_URL", "").strip(),
        "SECRET_KEY": os.environ.get("SECRET_KEY", "").strip() or os.environ.get("FLASK_SECRET_KEY", "").strip(),
        "LLM_BASE_URL": os.environ.get("LLM_BASE_URL", "").strip(),
        "LLM_API_KEY": os.environ.get("LLM_API_KEY", "").strip(),
        "LLM_MODEL": os.environ.get("LLM_MODEL", "").strip(),
    }
    missing = [key for key, value in required_env.items() if not value]
    if missing:
        raise RuntimeError(
            "Hosted mode is misconfigured. Missing required environment variables: "
            + ", ".join(missing)
        )


def is_admin_user(user):
    if not user:
        return False
    username = (user.get("username") or "").strip().lower()
    user_id = user.get("id")
    return username in ADMIN_USERS or user_id in ADMIN_USER_IDS


def current_user():
    uid = session.get("user_id")
    if not uid:
        return None
    return database.get_user(uid)


def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        user = current_user()
        if not user:
            return jsonify({"error": "Unauthorized"}), 401
        if not is_admin_user(user):
            return jsonify({"error": "Admin access required"}), 403
        return f(*args, **kwargs)
    return decorated_function


def workspace_feature_enabled_for_user(user):
    if not WORKSPACE_FEATURES_ENABLED:
        return False
    if not WORKSPACE_OWNER_ONLY:
        return True
    return is_admin_user(user)


def hosted_route_disabled(message):
    return jsonify({"error": message}), 403


def rate_limit(scope, limit, period_seconds):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            if not ENABLE_RATE_LIMITS:
                return f(*args, **kwargs)
            uid = session.get("user_id") or request.remote_addr or "anonymous"
            now = time.time()
            bucket_key = (scope, uid)
            with _rate_limit_lock:
                bucket = _rate_limit_window.get(bucket_key, [])
                bucket = [ts for ts in bucket if now - ts < period_seconds]
                if len(bucket) >= limit:
                    return jsonify({"error": "Rate limit exceeded"}), 429
                bucket.append(now)
                _rate_limit_window[bucket_key] = bucket
            return f(*args, **kwargs)
        return wrapped
    return decorator


# --- THREAD-SAFE STREAMING STATUS ---
# Key: (user_id, conv_id), Value: {"should_stop": bool, "timestamp": float}
_streaming_lock = threading.Lock()
streaming_status = {}

def get_streaming_status(user_id, conv_id):
    """Thread-safe getter for streaming status."""
    with _streaming_lock:
        return streaming_status.get((user_id, conv_id), {}).copy()

def set_streaming_status(user_id, conv_id, should_stop=False):
    """Thread-safe setter for streaming status."""
    with _streaming_lock:
        streaming_status[(user_id, conv_id)] = {
            "should_stop": should_stop,
            "timestamp": time.time()
        }

def clear_streaming_status(user_id, conv_id):
    """Thread-safe cleanup of streaming status."""
    with _streaming_lock:
        streaming_status.pop((user_id, conv_id), None)

def mark_stream_stopped(user_id, conv_id):
    """Thread-safe way to set should_stop flag to True."""
    with _streaming_lock:
        if (user_id, conv_id) in streaming_status:
            streaming_status[(user_id, conv_id)]["should_stop"] = True
            return True
        return False

def cleanup_stale_streams(max_age_seconds=300):
    """Remove streaming entries older than max_age_seconds (called periodically)."""
    current_time = time.time()
    with _streaming_lock:
        stale_keys = [
            key for key, val in streaming_status.items()
            if current_time - val.get("timestamp", 0) > max_age_seconds
        ]
        for key in stale_keys:
            del streaming_status[key]

