def get_openai_client():
    """Return the configured hosted model client."""
    env_base_url = os.environ.get("LLM_BASE_URL", "").strip()
    env_api_key = os.environ.get("LLM_API_KEY", "").strip()
    env_model_name = os.environ.get("LLM_MODEL", "").strip()
    base_url = env_base_url or database.get_setting("cloud_model_base_url") or "https://openrouter.ai/api/v1"
    api_key = env_api_key or database.get_setting("cloud_model_api_key") or ""
    model_name = env_model_name or database.get_setting("cloud_model_name") or ""
    if not api_key or not model_name:
        raise RuntimeError("Hosted model configuration is incomplete. Set LLM_API_KEY and LLM_MODEL.")
    return OpenAI(base_url=base_url, api_key=api_key), model_name

# Initialize Database
database.init_db()


def _resolve_conversation_id(payload=None):
    if isinstance(payload, dict):
        conv_id = payload.get("conversation_id") or payload.get("conv_id")
        if conv_id:
            return conv_id
    return session.get("conversation_id")


def _get_owned_conversation(conv_id, user_id):
    conversation = database.get_conversation(conv_id)
    if not conversation:
        return None
    if conversation.get("user_id") != user_id:
        return None
    return conversation


def _ensure_workspace_access(user):
    if not workspace_feature_enabled_for_user(user):
        if HOSTED_MODE and not WORKSPACE_FEATURES_ENABLED:
            raise WorkspaceRuntimeError("Workspace access is disabled for the hosted beta.")
        raise WorkspaceRuntimeError("Workspace access is restricted to owner/admin accounts in hosted mode.")


def _ensure_workspace(conv_id, user_id):
    conversation = _get_owned_conversation(conv_id, user_id)
    if not conversation:
        raise WorkspaceRuntimeError("Conversation not found or access denied.")
    user = database.get_user(user_id)
    _ensure_workspace_access(user)
    existing = database.get_workspace_by_conversation(conv_id)
    workspace_id = existing["id"] if existing else str(uuid.uuid4())
    root_path = workspace_runtime.ensure_workspace(workspace_id)
    workspace_id = database.upsert_workspace(
        workspace_id=workspace_id,
        conversation_id=conv_id,
        owner_user_id=user_id,
        sandbox_backend=workspace_runtime.backend,
        root_path_or_handle=root_path,
        status="active",
    )
    database.touch_workspace(workspace_id, status="active")
    return database.get_workspace_by_conversation(conv_id)


def _workspace_root_for_conversation(conv_id, user_id):
    workspace = _ensure_workspace(conv_id, user_id)
    return workspace["root_path_or_handle"], workspace


def _execute_workspace_command_for_tool(conv_id, user_id, args_input):
    workspace = _ensure_workspace(conv_id, user_id)
    if isinstance(args_input, dict):
        payload = args_input
    else:
        try:
            payload = json.loads(args_input)
        except Exception:
            payload = {}
    command = payload.get("command", "")
    working_dir = payload.get("working_dir", "")
    result = workspace_runtime.run_command(workspace["id"], command, working_dir)
    process_id = str(uuid.uuid4())
    database.add_workspace_process(
        process_id,
        workspace["id"],
        command,
        working_dir,
        result.get("backend", workspace_runtime.backend),
        status=result.get("status", "completed"),
    )
    database.update_workspace_process(process_id, result.get("status", "completed"), result.get("exit_code"))
    database.touch_workspace(workspace["id"])
    output = result.get("output", "")
    exit_code = result.get("exit_code")
    if exit_code is None:
        return output or f"Status: {result.get('status', 'unknown')}"
    return f"Exit code: {exit_code}\n{output}" if output.strip() else f"Exit code: {exit_code}\n(no output)"


def _safe_next_url(candidate, default="/app"):
    candidate = (candidate or "").strip()
    if not candidate.startswith("/"):
        return default
    if candidate.startswith("//"):
        return default
    return candidate


def _parse_chat_starters(raw_value):
    if not raw_value:
        return []
    if isinstance(raw_value, list):
        return [str(item).strip() for item in raw_value if str(item).strip()]
    try:
        parsed = json.loads(raw_value)
        if isinstance(parsed, list):
            return [str(item).strip() for item in parsed if str(item).strip()]
    except Exception:
        pass
    lines = []
    for item in str(raw_value).splitlines():
        value = item.strip().lstrip("-").strip()
        if value:
            lines.append(value)
    return lines


def _serialize_chat_starters(raw_value):
    starters = _parse_chat_starters(raw_value)
    return json.dumps(starters)


def _prepare_public_bot(bot):
    if not bot:
        return None
    clone = dict(bot)
    clone["tag_list"] = [t.strip() for t in (clone.get("tags") or "").split(",") if t.strip()]
    clone["tag_links"] = [{"label": t, "query": quote(t)} for t in clone["tag_list"]]
    clone["starter_list"] = _parse_chat_starters(clone.get("chat_starters"))
    clone["profile_url"] = f"/characters/{clone['id']}"
    clone["chat_url"] = f"/characters/{clone['id']}/chat"
    clone["chat_login_url"] = f"/login?next={quote(clone['chat_url'])}"
    clone["image_url"] = f"/storage/bots/{clone['photo']}" if clone.get("photo") else ""
    clone["display_tagline"] = clone.get("tagline") or clone.get("description") or "A character waiting to be discovered."
    clone["creator_display"] = clone.get("creator_name") or "community"
    clone["first_tag_query"] = clone["tag_links"][0]["query"] if clone["tag_links"] else ""
    return clone


def _render_chat_app():
    user_id = session['user_id']
    user = database.get_user(user_id)
    if not user:
        session.pop('user_id', None)
        return redirect('/login')

    user_conversations = database.get_user_conversations(user_id)
    user_tools = database.get_tools()
    user_photo = f"/storage/profiles/{user['photo']}" if user and user.get('photo') else ''
    assistant_pfp = database.get_setting('assistant_pfp', '/static/pfp/omniai_logo.png')
    assistant_prompt = database.get_setting('assistant_prompt', "You are Omni.ai, a helpful and advanced AI assistant.")

    return render_template_string(
        html_template,
        page='chat',
        conversations=user_conversations,
        username=session.get('username', user_id),
        current_conversation_id=session.get("conversation_id", ""),
        tools=list(user_tools.values()),
        assistant_pfp=assistant_pfp,
        assistant_prompt=assistant_prompt,
        user_photo=user_photo,
    )


def _create_conversation_for_bot(bot_id, user_id):
    bot = database.get_bot(bot_id)
    if not bot:
        return None, {"success": False, "error": "Bot not found"}, 404
    if not bot.get("is_public") and bot.get("owner_id") != user_id:
        return None, {"success": False, "error": "Bot not found"}, 404

    conv_id = str(uuid.uuid4())
    chat_code = f"{random.randint(100000, 999999)}"
    bot_name = bot.get('name') or "AI"
    title = f"Chat with {bot_name}"
    database.add_conversation(conv_id, user_id, bot_id, title, chat_code)
    session["conversation_id"] = conv_id

    greeting = (bot.get('greeting_message') or '').strip()
    if greeting:
        try:
            conv = database.get_conversation(conv_id)
            branch = conv['branches']['main']
            branch['history'].append({
                'sender': 'bot',
                'text': greeting,
                'versions': [greeting],
                'active_version': 0,
                'unique_id': str(random.randint(100000, 999999)),
                'profile_photo': f"/storage/bots/{bot.get('photo', '')}" if bot.get('photo') else '',
                'tool_trace': []
            })
            database.update_history(conv_id, 'main', branch['history'])
        except Exception as exc:
            print(f"[start_bot_chat] Could not inject greeting: {exc}")

    try:
        conn = database.get_db_connection()
        conn.execute("UPDATE bots SET chat_count = chat_count + 1 WHERE id = %s", (bot_id,))
        conn.commit()
        conn.close()
    except Exception as exc:
        print(f"[start_bot_chat] Could not increment chat_count: {exc}")

    return bot, {"success": True, "conversation_id": conv_id, "chat_code": chat_code}, 200


