# --- MCP (Model Context Protocol) MANAGER ---

class MCPManager:
    """Lightweight synchronous MCP client manager.
    
    Speaks the MCP JSON-RPC protocol directly over subprocess stdin/stdout
    for stdio servers, and HTTP POST for web/SSE servers.
    No async dependencies required.
    """
    
    def __init__(self):
        self._servers = {}      # name -> {process, config, tools, status, error}
        self._request_id = 0
        self._lock = threading.Lock()
    
    def _next_id(self):
        self._request_id += 1
        return self._request_id
    
    # --- Config I/O ---
    def load_config(self):
        """Load MCP server config from database settings."""
        try:
            raw = database.get_setting("mcp_config", "{}")
            data = json.loads(raw)
            return data.get("mcpServers", {})
        except Exception as e:
            print(f"⚠️ MCP: Failed to load config: {e}")
            return {}
    
    def save_config(self, servers_dict):
        """Save the mcpServers dict to database settings."""
        try:
            database.set_setting("mcp_config", json.dumps({"mcpServers": servers_dict}))
            print("💾 MCP: Config saved.")
        except Exception as e:
            print(f"⚠️ MCP: Failed to save config: {e}")
    
    def get_raw_config(self):
        """Return the full raw JSON config string."""
        try:
            return database.get_setting("mcp_config", json.dumps({"mcpServers": {}}, indent=2))
        except:
            return json.dumps({"mcpServers": {}}, indent=2)
    
    def save_raw_config(self, raw_json_str):
        """Save raw JSON string to database. Returns (success, error)."""
        try:
            data = json.loads(raw_json_str)
            if "mcpServers" not in data:
                return False, "JSON must contain a 'mcpServers' key"
            database.set_setting("mcp_config", raw_json_str)
            return True, None
        except json.JSONDecodeError as e:
            return False, f"Invalid JSON: {e}"
        except Exception as e:
            return False, str(e)
    
    # --- JSON-RPC over stdio ---
    def _send_jsonrpc(self, process, method, params=None):
        """Send a JSON-RPC request over stdin and read the response from stdout."""
        req = {
            "jsonrpc": "2.0",
            "id": self._next_id(),
            "method": method,
        }
        if params is not None:
            req["params"] = params
        
        msg_body = json.dumps(req)
        # MCP uses the LSP-style framing: Content-Length header + body
        # Note: The Node.js SDK strictly requires a trailing newline after the JSON body!
        full_msg = f"Content-Length: {len(msg_body)}\r\n\r\n{msg_body}\r\n"
        
        try:
            process.stdin.write(full_msg.encode('utf-8'))
            process.stdin.flush()
        except Exception as e:
            raise RuntimeError(f"Failed to write to MCP server stdin: {e}")
        
        # Read response with Content-Length framing
        return self._read_jsonrpc_response(process)
    
    def _read_jsonrpc_response(self, process, timeout=30, expected_id=None):
        """Read a JSON-RPC response with Content-Length or JSON Lines framing from stdout.
        
        Handles both protocols and skips server-initiated notifications (no 'id' field).
        """
        import select
        
        stdout_fd = process.stdout.fileno()
        deadline = time.time() + timeout
        
        while time.time() < deadline:
            content_length = None
            header_buf = b""
            is_raw_json = False
            
            # Read one message (either Content-Length framed or JSON Lines)
            while time.time() < deadline:
                ready, _, _ = select.select([stdout_fd], [], [], 0.5)
                if not ready:
                    if process.poll() is not None:
                        raise RuntimeError("MCP server process died")
                    continue
                
                chunk = process.stdout.read(1)
                if not chunk:
                    if process.poll() is not None:
                        raise RuntimeError("MCP server process died")
                    continue
                header_buf += chunk
                
                # Detect JSON Lines format (no headers, starts directly with '{')
                if len(header_buf) == 1 and header_buf == b"{":
                    is_raw_json = True
                    
                if is_raw_json:
                    # Read until newline for JSON lines
                    if header_buf.endswith(b"\n"):
                        try:
                            msg = json.loads(header_buf.decode('utf-8'))
                        except json.JSONDecodeError as e:
                            raise RuntimeError(f"Invalid JSON lines from MCP server: {e}. Raw: {repr(header_buf[:200])}")
                        
                        # Skip notifications (no 'id' field) — keep reading for the actual response
                        if "id" not in msg:
                            log_data = msg.get("params", {}).get("data", "")
                            print(f"    📨 MCP notification: {msg.get('method', '?')}: {str(log_data)[:100]}")
                            break  # Break inner loop to read next message
                        return msg
                else:
                    # Check for end of headers (Content-Length framing)
                    if header_buf.endswith(b"\r\n\r\n"):
                        header_str = header_buf.decode('utf-8', errors='replace')
                        for line in header_str.strip().split("\r\n"):
                            if line.lower().startswith("content-length:"):
                                content_length = int(line.split(":", 1)[1].strip())
                                break
                        break  # Break inner loop to read body
            
            if is_raw_json:
                # If we're here with is_raw_json, we skipped a notification — continue outer loop
                continue
        
            if content_length is None:
                if time.time() >= deadline:
                    raise RuntimeError(f"Timeout reading MCP response. Got: {repr(header_buf[:200])}")
                raise RuntimeError(f"No Content-Length in MCP response. Got: {repr(header_buf)}")
            
            # Read exactly content_length bytes
            body = b""
            while len(body) < content_length and time.time() < deadline:
                ready, _, _ = select.select([stdout_fd], [], [], 0.5)
                if ready:
                    remaining = content_length - len(body)
                    chunk = process.stdout.read(remaining)
                    if chunk:
                        body += chunk
                if process.poll() is not None and len(body) < content_length:
                    raise RuntimeError("MCP server process died mid-response")
            
            if len(body) < content_length:
                raise RuntimeError("Timeout reading MCP response body")
            
            try:
                msg = json.loads(body.decode('utf-8'))
            except json.JSONDecodeError as e:
                raise RuntimeError(f"Invalid JSON from MCP server: {e}. Raw: {repr(body[:200])}")
            
            # Skip notifications even in Content-Length mode
            if "id" not in msg:
                print(f"    📨 MCP notification: {msg.get('method', '?')}")
                continue
            return msg
        
        raise RuntimeError("Timeout waiting for MCP response (all received messages were notifications)")
    

    def _send_notification(self, process, method, params=None):
        """Send a JSON-RPC notification (no id, no response expected)."""
        notif = {
            "jsonrpc": "2.0",
            "method": method,
        }
        if params is not None:
            notif["params"] = params
        msg_body = json.dumps(notif)
        full_msg = f"Content-Length: {len(msg_body)}\r\n\r\n{msg_body}\r\n"
        try:
            process.stdin.write(full_msg.encode('utf-8'))
            process.stdin.flush()
        except:
            pass
    
    # --- Server Lifecycle ---
    def start_server(self, name):
        """Start a single MCP server by name from config."""
        config = self.load_config()
        if name not in config:
            return False, f"Server '{name}' not found in config"
        
        server_cfg = config[name]
        
        # Stop if already running
        if name in self._servers and self._servers[name].get("process"):
            self.stop_server(name)
        
        # Determine transport type
        if "url" in server_cfg:
            # Web/SSE server — no subprocess needed
            return self._connect_web_server(name, server_cfg)
        elif "command" in server_cfg:
            return self._start_stdio_server(name, server_cfg)
        else:
            self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": "No 'command' or 'url' in config"}
            return False, "No 'command' or 'url' in server config"
    
    def _start_stdio_server(self, name, server_cfg):
        """Start a stdio-based MCP server subprocess."""
        import shutil
        
        command = server_cfg["command"]
        args = server_cfg.get("args", [])
        
        env = os.environ.copy()
        if server_cfg.get("env"):
            env.update(server_cfg["env"])
        
        # Resolve command path — needed for nvm/pyenv/etc which set PATH in shell profiles
        resolved_cmd = shutil.which(command)
        if resolved_cmd:
            cmd = [resolved_cmd] + args
            use_shell = False
        else:
            # Fallback: try running through shell to pick up shell profile PATH
            cmd_str = command + " " + " ".join(args)
            cmd = cmd_str
            use_shell = True
        
        print(f"🔌 MCP: Starting server '{name}': {cmd}")
        try:
            proc = subprocess.Popen(
                cmd,
                stdin=subprocess.PIPE,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                env=env,
                bufsize=0,
                shell=use_shell
            )
            
            # Give it time to start (npx/uvx may need to download packages on first run)
            time.sleep(10)
            if proc.poll() is not None:
                err_bytes = proc.stderr.read() if proc.stderr else b""
                stderr = err_bytes.decode('utf-8', errors='replace')
                self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": f"Process exited immediately: {stderr[:300]}"}
                print(f"❌ MCP: Server '{name}' died on startup: {stderr[:200]}")
                return False, f"Server process exited: {stderr[:200]}"

            # Now send initialize — retry a few times since server may still be booting
            init_resp = None
            last_err = None
            for attempt in range(3):
                if proc.poll() is not None:
                    err_bytes = proc.stderr.read() if proc.stderr else b""
                    stderr = err_bytes.decode('utf-8', errors='replace')
                    last_err = f"Server process died: {stderr[:200]}"
                    break
                try:
                    init_resp = self._send_jsonrpc(proc, "initialize", {
                        "protocolVersion": "2024-11-05",
                        "capabilities": {},
                        "clientInfo": {"name": "OmniAI Chat", "version": "1.0.0"}
                    })
                    break  # Success
                except RuntimeError as e:
                    last_err = str(e)
                    print(f"⏳ MCP: Initialize attempt {attempt+1}/3 for '{name}' failed: {e}")
                    if attempt < 2:
                        time.sleep(5)  # Wait before retry
            
            if init_resp is None:
                proc.kill()
                err = f"Initialize failed after 3 attempts: {last_err}"
                self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": err}
                print(f"❌ MCP: {err}")
                return False, err
            
            if "error" in init_resp:
                proc.kill()
                err = init_resp["error"].get("message", str(init_resp["error"]))
                self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": err}
                return False, err
            
            # Send initialized notification
            self._send_notification(proc, "notifications/initialized")
            
            # List tools
            tools_resp = self._send_jsonrpc(proc, "tools/list", {})
            tools = []
            if "result" in tools_resp:
                tools = tools_resp["result"].get("tools", [])
            
            self._servers[name] = {
                "process": proc,
                "config": server_cfg,
                "tools": tools,
                "status": "connected",
                "error": None,
                "transport": "stdio"
            }
            
            print(f"✅ MCP: Server '{name}' connected with {len(tools)} tools: {[t['name'] for t in tools]}")
            return True, None
            
        except FileNotFoundError:
            err = f"Command not found: {server_cfg['command']}"
            self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": err}
            print(f"❌ MCP: {err}")
            return False, err
        except Exception as e:
            self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": str(e)}
            print(f"❌ MCP: Failed to start server '{name}': {e}")
            return False, str(e)
    
    def _connect_web_server(self, name, server_cfg):
        """Connect to a web/SSE MCP server via HTTP."""
        url = server_cfg["url"]
        headers = server_cfg.get("headers", {})
        
        print(f"🌐 MCP: Connecting to web server '{name}': {url}")
        try:
            # For SSE servers, we need to POST to the URL to get tool list
            # Try the standard MCP HTTP endpoint
            base_url = url.rstrip("/")
            if base_url.endswith("/sse"):
                base_url = base_url[:-4]  # Remove /sse suffix for API calls
            
            msg_url = base_url + "/message" if not base_url.endswith("/message") else base_url
            
            # Send initialize
            init_req = {
                "jsonrpc": "2.0",
                "id": self._next_id(),
                "method": "initialize",
                "params": {
                    "protocolVersion": "2024-11-05",
                    "capabilities": {},
                    "clientInfo": {"name": "OmniAI Chat", "version": "1.0.0"}
                }
            }
            resp = requests.post(msg_url, json=init_req, headers=headers, timeout=10)
            
            if resp.status_code != 200:
                err = f"HTTP {resp.status_code}: {resp.text[:200]}"
                self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": err, "transport": "web", "msg_url": msg_url, "headers": headers}
                return False, err
            
            # List tools
            tools_req = {
                "jsonrpc": "2.0",
                "id": self._next_id(),
                "method": "tools/list",
                "params": {}
            }
            resp = requests.post(msg_url, json=tools_req, headers=headers, timeout=10)
            tools = []
            if resp.status_code == 200:
                data = resp.json()
                tools = data.get("result", {}).get("tools", [])
            
            self._servers[name] = {
                "process": None,
                "config": server_cfg,
                "tools": tools,
                "status": "connected",
                "error": None,
                "transport": "web",
                "msg_url": msg_url,
                "headers": headers
            }
            
            print(f"✅ MCP: Web server '{name}' connected with {len(tools)} tools")
            return True, None
            
        except Exception as e:
            self._servers[name] = {"process": None, "config": server_cfg, "tools": [], "status": "error", "error": str(e), "transport": "web"}
            print(f"❌ MCP: Failed to connect to web server '{name}': {e}")
            return False, str(e)
    
    def stop_server(self, name):
        """Stop a running MCP server."""
        if name not in self._servers:
            return
        
        server = self._servers[name]
        proc = server.get("process")
        if proc and proc.poll() is None:
            print(f"🛑 MCP: Stopping server '{name}'...")
            try:
                proc.terminate()
                proc.wait(timeout=5)
            except subprocess.TimeoutExpired:
                proc.kill()
            except:
                pass
            print(f"✅ MCP: Server '{name}' stopped.")
        
        server["status"] = "stopped"
        server["process"] = None
        server["tools"] = []
    
    def start_all(self):
        """Start all configured MCP servers."""
        config = self.load_config()
        for name in config:
            try:
                self.start_server(name)
            except Exception as e:
                print(f"⚠️ MCP: Error starting '{name}': {e}")
    
    def stop_all(self):
        """Stop all running MCP servers."""
        for name in list(self._servers.keys()):
            self.stop_server(name)
    
    def reload_all(self):
        """Stop all servers and restart from config."""
        self.stop_all()
        self._servers.clear()
        self.start_all()
    
    # --- Tool Discovery ---
    def get_all_tools(self):
        """Return a dict of all discovered MCP tools across all connected servers.
        
        Returns: {tool_name: {server, name, description, inputSchema}}
        """
        all_tools = {}
        for server_name, server_info in self._servers.items():
            if server_info.get("status") != "connected":
                continue
            for tool in server_info.get("tools", []):
                key = f"mcp__{server_name}__{tool['name']}"
                all_tools[key] = {
                    "server": server_name,
                    "name": tool["name"],
                    "description": tool.get("description", ""),
                    "inputSchema": tool.get("inputSchema", {"type": "object", "properties": {}})
                }
        return all_tools
    
    # --- Tool Execution ---
    def call_tool(self, server_name, tool_name, arguments):
        """Call an MCP tool on the specified server. Returns dict: {text, images}."""
        if server_name not in self._servers:
            return f"MCP server '{server_name}' not found"
        
        server = self._servers[server_name]
        if server.get("status") != "connected":
            return f"MCP server '{server_name}' is not connected"
        
        # Ensure arguments is a dict
        if isinstance(arguments, str):
            try:
                arguments = json.loads(arguments)
            except:
                arguments = {"input": arguments}
        
        if server.get("transport") == "web":
            return self._call_tool_web(server, tool_name, arguments)
        else:
            return self._call_tool_stdio(server, tool_name, arguments)
    
    def _call_tool_stdio(self, server, tool_name, arguments):
        """Call a tool via stdio JSON-RPC."""
        proc = server.get("process")
        if not proc or proc.poll() is not None:
            server["status"] = "error"
            server["error"] = "Process not running"
            return "MCP server process is not running"
        
        try:
            resp = self._send_jsonrpc(proc, "tools/call", {
                "name": tool_name,
                "arguments": arguments
            })
            
            if "error" in resp:
                return f"MCP Error: {resp['error'].get('message', str(resp['error']))}"
            
            result = resp.get("result", {})
            content = result.get("content", [])
            
            # Extract text and media from content blocks
            text_parts = []
            images = []
            for block in content:
                btype = block.get("type")
                if btype == "text":
                    text_parts.append(block.get("text", ""))
                elif btype == "image":
                    mime = block.get("mimeType", "image/jpeg")
                    data = block.get("data", "")
                    if data:
                        images.append(f"data:{mime};base64,{data}")
                    else:
                        text_parts.append("[Image: no data]")
                elif btype == "resource":
                    resource = block.get("resource", {})
                    if resource.get("text"):
                        text_parts.append(resource["text"])
                    elif resource.get("blob"):
                        mime = resource.get("mimeType", "application/octet-stream")
                        if mime.startswith("image/"):
                            images.append(f"data:{mime};base64,{resource['blob']}")
                        else:
                            text_parts.append(f"[Resource: {mime}]")
                else:
                    text_parts.append(str(block))

            return {"text": "\n".join(text_parts), "images": images}
            
        except Exception as e:
            return f"MCP call error: {str(e)}"
    
    def _call_tool_web(self, server, tool_name, arguments):
        """Call a tool via HTTP POST."""
        try:
            req = {
                "jsonrpc": "2.0",
                "id": self._next_id(),
                "method": "tools/call",
                "params": {
                    "name": tool_name,
                    "arguments": arguments
                }
            }
            resp = requests.post(
                server["msg_url"],
                json=req,
                headers=server.get("headers", {}),
                timeout=30
            )
            
            if resp.status_code != 200:
                return f"MCP HTTP Error: {resp.status_code}"
            
            data = resp.json()
            if "error" in data:
                return f"MCP Error: {data['error'].get('message', '')}"
            
            result = data.get("result", {})
            content = result.get("content", [])
            text_parts = []
            images = []
            for block in content:
                btype = block.get("type")
                if btype == "text":
                    text_parts.append(block.get("text", ""))
                elif btype == "image":
                    mime = block.get("mimeType", "image/jpeg")
                    raw = block.get("data", "")
                    if raw:
                        images.append(f"data:{mime};base64,{raw}")
                    else:
                        text_parts.append("[Image: no data]")
                elif btype == "resource":
                    resource = block.get("resource", {})
                    if resource.get("text"):
                        text_parts.append(resource["text"])
                    elif resource.get("blob"):
                        mime = resource.get("mimeType", "application/octet-stream")
                        if mime.startswith("image/"):
                            images.append(f"data:{mime};base64,{resource['blob']}")
                        else:
                            text_parts.append(f"[Resource: {mime}]")
                else:
                    text_parts.append(str(block))
            return {"text": "\n".join(text_parts), "images": images}
            
        except Exception as e:
            return f"MCP web call error: {str(e)}"
    
    # --- Status ---
    def get_status(self):
        """Return status for all servers."""
        config = self.load_config()
        status = {}
        for name, cfg in config.items():
            if name in self._servers:
                s = self._servers[name]
                status[name] = {
                    "status": s.get("status", "unknown"),
                    "tools_count": len(s.get("tools", [])),
                    "tools": [{"name": t["name"], "description": t.get("description", "")} for t in s.get("tools", [])],
                    "error": s.get("error"),
                    "transport": s.get("transport", "stdio")
                }
            else:
                transport = "web" if "url" in cfg else "stdio"
                status[name] = {
                    "status": "stopped",
                    "tools_count": 0,
                    "tools": [],
                    "error": None,
                    "transport": transport
                }
        return status
    
    def add_server(self, name, config_dict):
        """Add a new server to config and optionally start it."""
        servers = self.load_config()
        servers[name] = config_dict
        self.save_config(servers)
    
    def remove_server(self, name):
        """Stop and remove a server from config."""
        self.stop_server(name)
        servers = self.load_config()
        servers.pop(name, None)
        self.save_config(servers)
        self._servers.pop(name, None)


# Initialize MCP Manager and start configured servers in background
mcp_manager = MCPManager()
def _mcp_startup():
    try:
        mcp_manager.start_all()
    except Exception as e:
        print(f"⚠️ MCP: Failed to start servers on startup: {e}")
threading.Thread(target=_mcp_startup, daemon=True).start()

# Register MCP cleanup on exit
def _cleanup_mcp():
    mcp_manager.stop_all()
atexit.register(_cleanup_mcp)


