CODE_MODE_INSTRUCTIONS = """
[CODE MODE — ACTIVE]
You are a coding agent. Work within the uploaded project directory using the terminal.

WORKFLOW:
1. Use `view` to read files before modifying them.
2. Use `run_terminal` for ALL file creation, editing, installation, and execution.
3. Use `str_replace(title, old_txt, new_txt)` for precise targeted edits when terminal is impractical.
4. Use `present_file(filename)` to display a file in canvas for the user to review or download.

MANDATORY EDIT WORKFLOW — follow these steps every single time you edit a file:
  Step 1: view(filename)          — read the current file content
  Step 2: str_replace(...)        — apply the targeted edit
  Step 3: present_file(filename)  — display the updated file in canvas

Never skip step 3. The canvas does NOT update automatically after str_replace; you MUST call present_file.

RULES:
- Prefer terminal for everything: create files with echo/cat/tee/python, edit with sed or inline scripts.
- Always read files with `view` before editing.
- After completing changes, briefly summarize — never repeat file contents verbatim.
- CRITICAL: `present_file` ALREADY presents the file to the user as an artifact card. Do NOT output a code block with the file contents after calling present_file — this creates a duplicate artifact. Write only a short plain-text summary.
- NEVER call present_file more than ONCE for the same file in one response. One call is enough — calling it again creates a duplicate. The edit workflow is: str_replace → present_file → DONE. Stop there.
- IMAGE/CHART CREATION: When asked to create graphs, charts, or visual output, save as PNG using matplotlib/PIL/etc via run_terminal, then call present_file(filename.png) to display the image in canvas. Add print('[IMAGE SAVED] filename.png') for logging.

"""


def _execute_code_mode(execute_hybrid_tool_fn, code, description=""):
    """Cloudflare Code Mode: execute AI-written Python with pre-bound tool functions.
    Takes execute_hybrid_tool_fn as a parameter so it can be used from any request context.
    """
    import io, sys, traceback as _tb

    tool_results_text = []
    last_image_path = [None]

    def _bt(cmd, arg=""):
        r = execute_hybrid_tool_fn(f"browser_{cmd}", arg)
        if isinstance(r, dict):
            if r.get("text"): tool_results_text.append(r["text"])
            if r.get("image_path"): last_image_path[0] = r["image_path"]
            return r.get("text", "")
        tool_results_text.append(str(r))
        return str(r)

    class _BrowserProxy:
        def click(self, el_id): return _bt("click", str(el_id))
        def type(self, el_id, text): return _bt("type", f"{el_id} {text}")
        def go(self, url): return _bt("go", url)
        def scroll(self, direction="down"): return _bt("scroll", direction)
        def chain(self, *actions): return _bt("chain", " ".join(str(a) for a in actions))
        def screenshot(self): return _bt("vision", "")
        def submit(self, el_id): return _bt("submit", str(el_id))
        def press(self, key): return _bt("press", key)
        def hover(self, el_id): return _bt("hover", str(el_id))
        def back(self): return _bt("back", "")
        def forward(self): return _bt("forward", "")
        def reload(self): return _bt("reload", "")
        def wait(self, secs=1): return _bt("wait", str(secs))

    def _create_artifact(name, content, art_type="code"):
        r = execute_hybrid_tool_fn("create_artifact", {"name": f"OAI({name})OAI", "content": content, "type": art_type})
        tool_results_text.append(str(r) if not isinstance(r, dict) else r.get("text", str(r)))
        return r

    def _str_replace(title, old_txt, new_txt):
        r = execute_hybrid_tool_fn("str_replace", {"title": title, "old_txt": old_txt, "new_txt": new_txt})
        tool_results_text.append(str(r) if not isinstance(r, dict) else r.get("text", str(r)))
        return r

    def _read_canvas(title):
        r = execute_hybrid_tool_fn("read_canvas", {"title": title})
        tool_results_text.append(str(r) if not isinstance(r, dict) else r.get("text", str(r)))
        return r

    def _mcp_call(server, tool_name, args=None):
        r = mcp_manager.call_tool(server, tool_name, args or {})
        tool_results_text.append(str(r) if not isinstance(r, dict) else r.get("text", str(r)))
        return r

    builtins_mod = __builtins__ if isinstance(__builtins__, dict) else vars(__builtins__)
    safe_builtins = {k: v for k, v in builtins_mod.items()
                     if k not in ('exec', 'eval', 'compile', 'open', '__import__', 'breakpoint')}
    safe_builtins['__import__'] = __import__

    namespace = {
        "__builtins__": safe_builtins,
        "browser": _BrowserProxy(),
        "create_artifact": _create_artifact,
        "str_replace": _str_replace,
        "read_canvas": _read_canvas,
        "mcp_call": _mcp_call,
        "result": None,
        "json": __import__("json"),
        "re": __import__("re"),
    }

    stdout_capture = io.StringIO()
    old_stdout = sys.stdout
    try:
        sys.stdout = stdout_capture
        exec(compile(code, "<code_mode>", "exec"), namespace)
    except Exception:
        sys.stdout = old_stdout
        return {"text": f"Code execution error:\n{_tb.format_exc()}", "image_path": None}
    finally:
        sys.stdout = old_stdout

    printed = stdout_capture.getvalue()
    result_val = namespace.get("result")
    parts = [t for t in tool_results_text if t]
    if printed: parts.append(printed)
    if result_val is not None: parts.append(str(result_val))
    return {"text": "\n".join(parts) or "Code executed successfully.", "image_path": last_image_path[0]}


# ---------------------------------------------------------------------------
# Format tool arguments for display in Tool Activity panel
# ---------------------------------------------------------------------------
def _format_tool_args_display(tool_name, args_input):
    """Format tool call arguments as readable JSON for the Tool Activity panel.
    Output is HTML-escaped for safe use in innerHTML."""
    import html as _html
    try:
        if isinstance(args_input, str):
            parsed = json.loads(args_input)
        else:
            parsed = args_input
        if not isinstance(parsed, dict):
            return _html.escape(json.dumps(parsed, indent=2), quote=False)
        # For create_project, truncate file contents for readability
        if tool_name == "create_project" and "files" in parsed:
            display = {}
            for k, v in parsed.items():
                if k == "files" and isinstance(v, list):
                    display["files"] = []
                    for f in v:
                        if isinstance(f, dict):
                            df = dict(f)
                            if "content" in df and isinstance(df["content"], str) and len(df["content"]) > 150:
                                df["content"] = df["content"][:150] + f"... ({len(f['content'])} chars)"
                            display["files"].append(df)
                        else:
                            display["files"].append(f)
                else:
                    display[k] = v
            return _html.escape(json.dumps(display, indent=2), quote=False)
        # For other tools, truncate very long string values
        display = {}
        for k, v in parsed.items():
            if isinstance(v, str) and len(v) > 500:
                display[k] = v[:500] + f"... ({len(v)} chars)"
            else:
                display[k] = v
        return _html.escape(json.dumps(display, indent=2), quote=False)
    except Exception:
        return _html.escape(str(args_input)[:1000], quote=False) if args_input else ""


# ---------------------------------------------------------------------------
# Build file tree for a project directory (shared helper)
# ---------------------------------------------------------------------------
def _build_project_tree(directory):
    """Recursively build a file tree structure for a project directory."""
    def _walk(d, base):
        tree = []
        try:
            entries = sorted(os.listdir(d), key=lambda x: (os.path.isfile(os.path.join(d, x)), x.lower()))
        except PermissionError:
            return tree
        for entry in entries:
            if entry.startswith('.') or entry in ('__pycache__', 'node_modules', '.git'):
                continue
            fp = os.path.join(d, entry)
            rel = os.path.relpath(fp, base)
            if os.path.isdir(fp):
                tree.append({"name": entry, "type": "dir", "path": rel, "children": _walk(fp, base)})
            else:
                tree.append({"name": entry, "type": "file", "path": rel})
        return tree
    return _walk(directory, directory)


# ---------------------------------------------------------------------------
# Workspace tool handler (shared across all 3 inference-loop closures)
# ---------------------------------------------------------------------------
def _handle_workspace_tool(name, args_input, conv_id, user_id, branch_name, artifact_counter, unique_id):
    """Handle view, create_file, and present_file workspace tools.
    Returns a result value (str or dict) if the tool was handled, else None.
    """
    alias_map = {
        "workspace_list_files": "view",
        "workspace_read_file": "view",
        "workspace_write_file": "create_file",
        "workspace_download_artifact": "present_file",
    }
    name = alias_map.get(name, name)

    def _get_arg(key, fallback=None):
        if isinstance(args_input, dict):
            return args_input.get(key, fallback)
        try:
            parsed = json.loads(args_input)
            return parsed.get(key, fallback)
        except Exception:
            return fallback

    # ---- view ---------------------------------------------------------------
    if name == "view":
        path = _get_arg("path", "") or ""
        # List workspace if no path given
        if not path or path.strip() in (".", "/", "./", ""):
            runtime_lines = []
            try:
                _, workspace = _workspace_root_for_conversation(conv_id, user_id)
                runtime_files = workspace_runtime.list_files(workspace["id"])
                for entry in runtime_files:
                    runtime_lines.append(f"  - {entry['path']} ({entry['type']})")
            except Exception:
                runtime_lines = []
            ws_files = database.get_workspace_files(conv_id or "")
            # Also include all user attachments (PDFs, images) not already in ws_files
            seen_ids = {f.get("id") for f in ws_files}
            all_user_pdfs = database.load_user_attachments(user_id, 'pdf')
            all_user_imgs = database.load_user_attachments(user_id, 'image')
            for att in all_user_pdfs + all_user_imgs:
                if att.get("id") not in seen_ids:
                    ws_files.append(att)
                    seen_ids.add(att.get("id"))
            if not ws_files:
                return "Workspace is empty. No files have been uploaded."
            lines = ["Workspace files:"]
            lines.extend(runtime_lines)
            for f in ws_files:
                dn = f.get("display_name") or f.get("filename") or f.get("name") or "?"
                ft = f.get("file_type", "?")
                lines.append(f"  - {dn} ({ft})")
            return "\n".join(lines)

        # Check canvas artifact FIRST for text files — canvas has the latest version after str_replace edits
        _is_binary = any(path.lower().endswith(ext) for ext in ('.png', '.jpg', '.jpeg', '.gif', '.webp', '.pdf'))
        if not _is_binary and conv_id:
            _cv_conn = database.get_db_connection()
            _cv_row = _cv_conn.execute(
                "SELECT * FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
                (conv_id.strip(), path.strip().lower())
            ).fetchone()
            _cv_conn.close()
            if _cv_row:
                try:
                    _cv_hist = json.loads(_cv_row['history_json']) if _cv_row['history_json'] else []
                except Exception:
                    _cv_hist = []
                if _cv_hist:
                    return f"[Content of '{_cv_row['title']}']:\n{_cv_hist[-1]}"

        # Find file in workspace by display_name
        ws_files = database.get_workspace_files(conv_id or "")
        target = None
        for f in ws_files:
            dn = f.get("display_name") or f.get("filename", "")
            if dn.lower() == path.lower() or os.path.basename(dn).lower() == path.lower():
                target = f
                break
        # Fallback: search ALL user attachments by name (file may have been uploaded globally)
        if not target:
            target = database.find_user_attachment_by_name(user_id, path)

        if target:
            fpath = target.get("path")
            if not fpath or not os.path.exists(fpath):
                return f"Error: '{path}' found in workspace but file is missing from disk."
            ft = target.get("file_type", "")
            # Image → return as vision dict
            if ft == "image" or any(path.lower().endswith(ext) for ext in ('.png', '.jpg', '.jpeg', '.gif', '.webp')):
                try:
                    with open(fpath, "rb") as imgf:
                        img_b64 = base64.b64encode(imgf.read()).decode('utf-8')
                    ext_lower = os.path.splitext(fpath)[1].lower().lstrip('.')
                    mime_map = {"png": "image/png", "jpg": "image/jpeg", "jpeg": "image/jpeg",
                                "gif": "image/gif", "webp": "image/webp"}
                    mime = mime_map.get(ext_lower, "image/jpeg")
                    return {"text": f"[Image: {path}]", "images": [f"data:{mime};base64,{img_b64}"]}
                except Exception as e:
                    return f"Error reading image '{path}': {e}"
            # PDF → extract text
            if ft == "pdf" or path.lower().endswith('.pdf'):
                pages = extract_text_from_pdf(fpath)
                if pages:
                    return f"[Content of {path}]:\n" + "\n".join(pages)
                return f"Error: Could not extract text from '{path}'."
            # Text/generated → read raw
            try:
                with open(fpath, "r", encoding="utf-8", errors="replace") as tf:
                    return f"[Content of {path}]:\n{tf.read()}"
            except Exception as e:
                return f"Error reading '{path}': {e}"

        # Fallback: try canvas artifact
        if conv_id:
            try:
                _, workspace = _workspace_root_for_conversation(conv_id, user_id)
                try:
                    content = workspace_runtime.read_file(workspace["id"], path)
                    return f"[Content of {path}]:\n{content}"
                except WorkspaceRuntimeError:
                    pass
            except Exception:
                pass
        rc_conn = database.get_db_connection()
        rc_row = rc_conn.execute(
            "SELECT * FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
            ((conv_id or "").strip(), path.strip().lower())
        ).fetchone()
        rc_conn.close()
        if rc_row:
            try:
                rc_hist = json.loads(rc_row['history_json']) if rc_row['history_json'] else []
            except Exception:
                rc_hist = []
            if rc_hist:
                return f"[Canvas Content for '{rc_row['title']}']:\n{rc_hist[-1]}"
        return f"Error: File '{path}' not found in workspace or canvas."

    # ---- create_file --------------------------------------------------------
    if name == "create_file":
        cf_filename = _get_arg("filename") or _get_arg("name") or _get_arg("path") or ""
        cf_content  = _get_arg("content") or ""
        cf_type     = _get_arg("type") or "text"
        if not cf_filename:
            return "Error: create_file requires a 'filename' parameter."
        if not cf_content:
            return "Error: create_file requires a 'content' parameter."

        # Check if there's an active project — if so, write into it
        ws_files = database.get_workspace_files(conv_id or "")
        active_project = None
        for f in ws_files:
            if f.get("file_type") == "code_project":
                active_project = f
                break

        if active_project:
            # --- PROJECT MODE: write file into project directory ---
            meta = active_project.get("metadata") or {}
            if isinstance(meta, str):
                try: meta = json.loads(meta)
                except: meta = {}
            proj_ws_dir = active_project.get("path") or meta.get("ws_dir", "")
            if not proj_ws_dir or not os.path.isdir(proj_ws_dir):
                return "Error: Project directory not found."

            # Path traversal protection
            full_path = os.path.realpath(os.path.join(proj_ws_dir, cf_filename))
            if not full_path.startswith(os.path.realpath(proj_ws_dir)):
                return "Error: Invalid file path."

            # Create subdirectories if needed (e.g. css/style.css)
            os.makedirs(os.path.dirname(full_path), exist_ok=True)
            try:
                with open(full_path, "w", encoding="utf-8") as wf:
                    wf.write(cf_content)
            except Exception as e:
                return f"Error saving file '{cf_filename}': {e}"

            # Rebuild file tree and update DB
            file_tree = _build_project_tree(proj_ws_dir)
            project_id = meta.get("project_id", "")
            meta["file_tree"] = file_tree
            try:
                conn = database.get_db_connection()
                conn.execute(
                    "UPDATE attachments SET metadata = %s WHERE id = %s",
                    (json.dumps(meta), active_project["id"])
                )
                conn.commit()
                conn.close()
            except Exception as e:
                print(f"⚠️ create_file (project): Failed to update project tree: {e}")

            proj_data = json.dumps({
                "project_name": active_project.get("display_name") or active_project.get("filename", ""),
                "project_id": project_id,
                "file_tree": file_tree,
                "ws_dir": proj_ws_dir
            })
            return f"__PROJECT_UPDATE__|{proj_data}|File '{cf_filename}' created successfully."

        # --- STANDALONE MODE: original behavior (no active project) ---
        ws_dir, workspace = _workspace_root_for_conversation(conv_id or "default", user_id) if conv_id else (os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default")), None)
        os.makedirs(ws_dir, exist_ok=True)
        safe_fname = secure_filename(cf_filename) or "file.txt"
        ws_path = os.path.join(ws_dir, safe_fname)
        if os.path.exists(ws_path):
            base, ext = os.path.splitext(safe_fname)
            counter = 1
            while os.path.exists(ws_path):
                ws_path = os.path.join(ws_dir, f"{base}_{counter}{ext}")
                counter += 1
            safe_fname = os.path.basename(ws_path)
        try:
            with open(ws_path, "w", encoding="utf-8") as wf:
                wf.write(cf_content)
        except Exception as e:
            return f"Error saving file '{cf_filename}': {e}"

        chat_code = None
        if conv_id:
            conv_rec = database.get_conversation(conv_id)
            if conv_rec:
                chat_code = conv_rec.get("chat_code")
        database.save_user_attachment(user_id, safe_fname, "generated", chat_code,
                                      path=ws_path, display_name=cf_filename)

        # Also surface in Canvas — reuse existing artifact ID if same title exists
        if conv_id:
            _conn = database.get_db_connection()
            _existing = _conn.execute(
                "SELECT id FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
                (conv_id, safe_fname.lower())
            ).fetchone()
            _conn.close()
            if _existing:
                art_id = _existing['id']
            else:
                artifact_counter[0] += 1
                art_id = f"{unique_id}-{artifact_counter[0]}"
            database.save_canvas_artifact(art_id, conv_id, branch_name, safe_fname, cf_type, cf_content)
        else:
            artifact_counter[0] += 1
            art_id = f"{unique_id}-{artifact_counter[0]}"
        safe_title   = safe_fname.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
        safe_content = cf_content.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
        type_attr    = ' data-type="code"' if cf_type == "code" else ""
        artifact_html = f'<artifact-card data-id="{art_id}" data-title="{safe_title}" data-content="{safe_content}"{type_attr}></artifact-card>'
        return f"__ARTIFACT_CREATE__|{artifact_html}"

    # ---- present_file -------------------------------------------------------
    if name == "present_file":
        pf_filename = _get_arg("filename") or _get_arg("name") or ""
        if not pf_filename:
            return "Error: present_file requires a 'filename' parameter."

        _IMAGE_EXTS = {'.png', '.jpg', '.jpeg', '.gif', '.webp', '.bmp', '.svg'}

        def _present_image_file(file_path, display_name):
            """Handle image files: copy to IMAGE_STORAGE and return image artifact marker."""
            import shutil
            safe_name = secure_filename(display_name) or "image.png"
            dest_name = f"{unique_id}_{safe_name}"
            dest_path = os.path.join(IMAGE_STORAGE, dest_name)
            try:
                shutil.copy2(file_path, dest_path)
                print(f"[PRESENT_FILE] Image copied: {file_path} → {dest_path}")
            except Exception as e:
                return f"Error copying image: {e}"
            img_url = f"/storage/images/{dest_name}"
            artifact_counter[0] += 1
            art_id = f"{unique_id}-img-{artifact_counter[0]}"
            if conv_id:
                database.save_canvas_artifact(art_id, conv_id, branch_name, display_name, "image", img_url)
            safe_title = display_name.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
            safe_url = img_url.replace('&', '&amp;').replace('"', '&quot;')
            artifact_html = f'<artifact-card data-id="{art_id}" data-title="{safe_title}" data-content="{safe_url}" data-type="image"></artifact-card>'
            print(f"[PRESENT_FILE] Image artifact created: id={art_id}, title={display_name}, url={img_url}")
            return f"__ARTIFACT_CREATE__|{artifact_html}"

        def _load_into_canvas_and_download(file_path, display_name):
            """Read file from disk, save canvas artifact, return __ARTIFACT_CREATE__ marker."""
            try:
                with open(file_path, "r", encoding="utf-8", errors="replace") as _f:
                    pf_content = _f.read()
            except Exception as e:
                return f"Error reading file for canvas: {e}"
            ext = os.path.splitext(display_name)[1].lower()
            art_type = "html" if ext == ".html" else "code" if ext in (".py", ".js", ".ts", ".css", ".java", ".c", ".cpp", ".go", ".rs", ".sh", ".json", ".yaml", ".yml", ".toml", ".xml") else "text"
            # Reuse existing artifact ID if same title exists for this conversation
            if conv_id:
                _conn = database.get_db_connection()
                _existing = _conn.execute(
                    "SELECT id, history_json FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
                    (conv_id, display_name.lower())
                ).fetchone()
                _conn.close()
                if _existing:
                    art_id = _existing['id']
                    # Use DB's latest version as canonical content (str_replace edits DB, not disk)
                    try:
                        _db_hist = json.loads(_existing['history_json']) if _existing['history_json'] else []
                        if _db_hist:
                            pf_content = _db_hist[-1]
                            print(f"[PRESENT_FILE] Using DB content for '{display_name}' (len={len(pf_content)})")
                            # Sync disk file to match DB so future reads aren't stale
                            try:
                                with open(file_path, "w", encoding="utf-8") as _wf:
                                    _wf.write(pf_content)
                            except Exception:
                                pass
                    except Exception:
                        pass
                else:
                    artifact_counter[0] += 1
                    art_id = f"{unique_id}-pf-{artifact_counter[0]}"
                database.save_canvas_artifact(art_id, conv_id, branch_name, display_name, art_type, pf_content)
            else:
                artifact_counter[0] += 1
                art_id = f"{unique_id}-pf-{artifact_counter[0]}"
            safe_title   = display_name.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
            safe_content = pf_content.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
            type_attr    = f' data-type="{art_type}"' if art_type != "text" else ""
            artifact_html = f'<artifact-card data-id="{art_id}" data-title="{safe_title}" data-content="{safe_content}"{type_attr}></artifact-card>'
            return f"__ARTIFACT_CREATE__|{artifact_html}"

        # 1. Search workspace attachments
        ws_files = database.get_workspace_files(conv_id or "")
        target_att = None
        for f in ws_files:
            dn = f.get("display_name") or f.get("filename", "")
            if dn.lower() == pf_filename.lower() or os.path.basename(dn).lower() == pf_filename.lower():
                target_att = f
                break
        if not target_att:
            target_att = database.find_user_attachment_by_name(user_id, pf_filename)

        if target_att and target_att.get("path") and os.path.isfile(target_att["path"]):
            dn = target_att.get("display_name") or target_att.get("filename", pf_filename)
            if os.path.splitext(dn)[1].lower() in _IMAGE_EXTS:
                return _present_image_file(target_att["path"], dn)
            return _load_into_canvas_and_download(target_att["path"], dn)

        # 2. Fallback: file created by run_terminal in per-chat workspace dir
        try:
            per_chat_dir, _workspace = _workspace_root_for_conversation(conv_id or "default", user_id) if conv_id else (os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default")), None)
        except Exception:
            per_chat_dir = os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default"))
        terminal_path = os.path.join(per_chat_dir, pf_filename)
        if not os.path.isfile(terminal_path):
            # Search one level deep
            for root, dirs, files in os.walk(per_chat_dir):
                for fname in files:
                    if fname.lower() == pf_filename.lower() or fname.lower() == os.path.basename(pf_filename).lower():
                        terminal_path = os.path.join(root, fname)
                        break
                break
        if os.path.isfile(terminal_path):
            os.makedirs(per_chat_dir, exist_ok=True)
            pf_chat_code = None
            if conv_id:
                conv_rec = database.get_conversation(conv_id)
                if conv_rec:
                    pf_chat_code = conv_rec.get("chat_code")
            safe_fname = secure_filename(os.path.basename(terminal_path)) or "file.txt"
            database.save_user_attachment(user_id, safe_fname, "generated", pf_chat_code,
                                          path=terminal_path, display_name=pf_filename)
            if os.path.splitext(pf_filename)[1].lower() in _IMAGE_EXTS:
                return _present_image_file(terminal_path, pf_filename)
            return _load_into_canvas_and_download(terminal_path, pf_filename)

        # 3. Fallback: materialise existing canvas artifact to disk and re-present
        rc_conn = database.get_db_connection()
        rc_row = rc_conn.execute(
            "SELECT * FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
            ((conv_id or "").strip(), pf_filename.strip().lower())
        ).fetchone()
        rc_conn.close()
        if rc_row:
            try:
                rc_hist = json.loads(rc_row['history_json']) if rc_row['history_json'] else []
            except Exception:
                rc_hist = []
            if rc_hist:
                art_content = rc_hist[-1]
                try:
                    ws_dir, _workspace = _workspace_root_for_conversation(conv_id or "default", user_id) if conv_id else (os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default")), None)
                except Exception:
                    ws_dir = os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default"))
                os.makedirs(ws_dir, exist_ok=True)
                safe_fname = secure_filename(rc_row['title'] or pf_filename) or "file.txt"
                ws_path = os.path.join(ws_dir, safe_fname)
                try:
                    with open(ws_path, "w", encoding="utf-8") as wf:
                        wf.write(art_content)
                except Exception as e:
                    return f"Error preparing file: {e}"
                return _load_into_canvas_and_download(ws_path, rc_row['title'] or pf_filename)

        return f"Error: File '{pf_filename}' not found in workspace or terminal directory."

    # ---- create_project ------------------------------------------------------
    if name == "create_project":
        proj_name = _get_arg("name") or _get_arg("project_name") or ""
        if not proj_name:
            return "Error: create_project requires a 'name' parameter."

        project_id = str(uuid.uuid4())[:8]
        safe_proj_name = secure_filename(proj_name) or "project"
        ws_dir = os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default"), "code_projects", f"{safe_proj_name}_{project_id}")
        os.makedirs(ws_dir, exist_ok=True)

        file_tree = []  # Empty — files added via create_file

        chat_code = None
        if conv_id:
            conv_rec = database.get_conversation(conv_id)
            if conv_rec:
                chat_code = conv_rec.get("chat_code")

        database.save_user_attachment(
            user_id, safe_proj_name, 'code_project', chat_code,
            None, 0, 1, ws_dir,
            {"project_id": project_id, "file_tree": file_tree},
            display_name=proj_name
        )

        # Return special marker so frontend opens the project in canvas
        proj_data = json.dumps({
            "project_name": proj_name,
            "project_id": project_id,
            "file_tree": file_tree,
            "ws_dir": ws_dir
        })
        return f"__PROJECT_CREATE__|{proj_data}"

    # ---- remove_file ---------------------------------------------------------
    if name == "remove_file":
        rf_path = _get_arg("path") or _get_arg("filename") or ""
        if not rf_path:
            return "Error: remove_file requires a 'path' parameter."

        # Find the active project for this conversation
        ws_files = database.get_workspace_files(conv_id or "")
        active_project = None
        for f in ws_files:
            if f.get("file_type") == "code_project":
                meta = f.get("metadata") or {}
                if isinstance(meta, str):
                    try: meta = json.loads(meta)
                    except: meta = {}
                active_project = f
                break

        if not active_project:
            return "Error: No active project found. Use create_project first."

        meta = active_project.get("metadata") or {}
        if isinstance(meta, str):
            try: meta = json.loads(meta)
            except: meta = {}
        proj_ws_dir = active_project.get("path") or meta.get("ws_dir", "")
        if not proj_ws_dir or not os.path.isdir(proj_ws_dir):
            return "Error: Project directory not found."

        # Path traversal protection
        full_path = os.path.realpath(os.path.join(proj_ws_dir, rf_path))
        if not full_path.startswith(os.path.realpath(proj_ws_dir)):
            return "Error: Invalid file path."

        if not os.path.exists(full_path):
            return f"Error: File '{rf_path}' does not exist in the project."

        try:
            os.remove(full_path)
            # Clean up empty parent dirs
            parent = os.path.dirname(full_path)
            while parent != os.path.realpath(proj_ws_dir):
                if os.path.isdir(parent) and not os.listdir(parent):
                    os.rmdir(parent)
                    parent = os.path.dirname(parent)
                else:
                    break
        except Exception as e:
            return f"Error removing file: {e}"

        # Rebuild file tree and update DB
        file_tree = _build_project_tree(proj_ws_dir)
        project_id = meta.get("project_id", "")
        meta["file_tree"] = file_tree
        try:
            conn = database.get_db_connection()
            conn.execute(
                "UPDATE attachments SET metadata = %s WHERE id = %s",
                (json.dumps(meta), active_project["id"])
            )
            conn.commit()
            conn.close()
        except Exception as e:
            print(f"⚠️ remove_file: Failed to update project tree: {e}")

        proj_data = json.dumps({
            "project_name": active_project.get("display_name") or active_project.get("filename", ""),
            "project_id": project_id,
            "file_tree": file_tree,
            "ws_dir": proj_ws_dir
        })
        return f"__PROJECT_UPDATE__|{proj_data}|File '{rf_path}' removed successfully."

    # ---- edit_file -----------------------------------------------------------
    if name == "edit_file":
        ef_project = _get_arg("project_name") or _get_arg("project") or ""
        ef_filename = _get_arg("filename") or _get_arg("path") or ""
        ef_old_str  = _get_arg("old_str") or _get_arg("old_string") or ""
        ef_new_str  = _get_arg("new_str") or _get_arg("new_string") or ""
        ef_content  = _get_arg("content") or ""

        if not ef_filename:
            return "Error: edit_file requires a 'filename' parameter."
        if not ef_old_str and not ef_content:
            return "Error: edit_file requires either 'old_str'+'new_str' or 'content' parameter."

        # Find the project — by name if given, else fall back to active project
        ws_files = database.get_workspace_files(conv_id or "")
        active_project = None
        for f in ws_files:
            if f.get("file_type") == "code_project":
                if ef_project:
                    pname = f.get("display_name") or f.get("filename", "")
                    if pname.lower() == ef_project.lower() or pname.lower().startswith(ef_project.lower()):
                        active_project = f
                        break
                else:
                    active_project = f
                    break

        if not active_project:
            return f"Error: Project '{ef_project}' not found. Use create_project to create it first." if ef_project else "Error: No active project found."

        meta = active_project.get("metadata") or {}
        if isinstance(meta, str):
            try: meta = json.loads(meta)
            except: meta = {}
        proj_ws_dir = active_project.get("path") or meta.get("ws_dir", "")
        if not proj_ws_dir or not os.path.isdir(proj_ws_dir):
            return "Error: Project directory not found."

        # Path traversal protection
        full_path = os.path.realpath(os.path.join(proj_ws_dir, ef_filename))
        if not full_path.startswith(os.path.realpath(proj_ws_dir)):
            return "Error: Invalid file path."

        if not os.path.exists(full_path):
            return f"Error: File '{ef_filename}' does not exist in the project. Use create_file to create it first."

        try:
            with open(full_path, "r", encoding="utf-8") as rf:
                current_content = rf.read()
        except Exception as e:
            return f"Error reading file '{ef_filename}': {e}"

        if ef_content:
            new_content = ef_content
        else:
            if ef_old_str not in current_content:
                return f"Error: The specified old_str was not found in '{ef_filename}'. Use the view tool to read the current content first."
            occurrences = current_content.count(ef_old_str)
            if occurrences > 1:
                return f"Error: old_str appears {occurrences} times in '{ef_filename}'. Provide more surrounding context to make it unique."
            new_content = current_content.replace(ef_old_str, ef_new_str, 1)

        try:
            with open(full_path, "w", encoding="utf-8") as wf:
                wf.write(new_content)
        except Exception as e:
            return f"Error writing file '{ef_filename}': {e}"

        # Rebuild file tree and update DB
        file_tree = _build_project_tree(proj_ws_dir)
        project_id = meta.get("project_id", "")
        meta["file_tree"] = file_tree
        try:
            conn = database.get_db_connection()
            conn.execute(
                "UPDATE attachments SET metadata = %s WHERE id = %s",
                (json.dumps(meta), active_project["id"])
            )
            conn.commit()
            conn.close()
        except Exception as e:
            print(f"⚠️ edit_file: Failed to update project tree: {e}")

        proj_data = json.dumps({
            "project_name": active_project.get("display_name") or active_project.get("filename", ""),
            "project_id": project_id,
            "file_tree": file_tree,
            "ws_dir": proj_ws_dir,
            "active_file": ef_filename
        })
        return f"__PROJECT_UPDATE__|{proj_data}|File '{ef_filename}' edited successfully."

    return None  # Not a workspace tool


def build_system_prompt(conversation, file_list_str, direct_read_mode, code_mode_enabled, workspace_files=None):
    """Build the complete system prompt for a chat request."""
    # Base prompt: from bot instructions or user's assistant_prompt setting
    system_prompt = str(conversation.get("system_prompt") or "")
    if not system_prompt and (not conversation.get("bot_id") or conversation.get("bot_id") == ""):
        system_prompt = database.get_setting('assistant_prompt', "You are Omni.ai, a helpful and advanced AI assistant.")

    # File convention (simplified — terminal-first)
    artifact_convention = (
        "### FILE CONVENTION ###\n"
        "- Use `run_terminal` to create or edit files (shell commands: echo, cat, tee, python -c, etc.)\n"
        "- Use `present_file(filename)` to load a file into canvas AND give the user a download link. "
        "This is the ONLY way to display content — do NOT output raw file contents in chat.\n"
        "- MANDATORY EDIT WORKFLOW: view(filename) → str_replace(...) → present_file(filename). "
        "The canvas does NOT update automatically after str_replace — you MUST call present_file explicitly.\n"
        "- IMPORTANT: Each str_replace call modifies the file. NEVER repeat the same str_replace in one response — "
        "the old_string no longer exists after the first call, so a second call WILL fail. "
        "Perform the edit workflow exactly ONCE per edit.\n"
        "- NEVER call present_file more than ONCE for the same file in one response. One call is enough — "
        "calling it again creates a duplicate. The edit workflow is: str_replace → present_file → DONE. Stop there.\n"
        "- For visualizations/interactive content: create a self-contained HTML file via `run_terminal`, then call `present_file`.\n"
        "- IMAGE/CHART CREATION: When asked to create graphs, charts, diagrams, or any visual output:\n"
        "  1. Use `run_terminal` to run Python code (matplotlib, seaborn, PIL, etc.) that saves the output as a PNG file.\n"
        "  2. Save the image to the current working directory (it auto-resolves to the conversation workspace).\n"
        "  3. Add `print('[IMAGE SAVED] filename.png')` in your script for debug logging.\n"
        "  4. Call `present_file(filename.png)` to display the image in the canvas for the user.\n"
        "  5. Example: `run_terminal(command='python3 -c \"import matplotlib.pyplot as plt; plt.plot([1,2,3],[4,5,6]); plt.savefig(\\\"chart.png\\\", dpi=150, bbox_inches=\\\"tight\\\"); print(\\\"[IMAGE SAVED] chart.png\\\")\"')`\n"
        "- Use `view(path)` to read any workspace file before editing.\n"
        "- After `present_file` or `create_file`, write a brief plain-text description — NEVER repeat or echo the file content as a code block in your response. "
        "The artifact chip already provides the file. Writing the same code again as a markdown code block creates ugly duplicates.\n"
        "- CRITICAL: `present_file` ALREADY presents the file to the user as an artifact card. "
        "Do NOT output a code block containing the file content after calling present_file — that creates a second duplicate artifact. "
        "Just write a short plain-text sentence describing what was done.\n"
        "- IMPORTANT: Do NOT call present_file on a file you just created with create_file or run_terminal in this same response. "
        "The create_file tool already displays the artifact. Only use present_file for files created in a PREVIOUS message or that already exist.\n"
        "### END ###\n\n"
    )
    if not code_mode_enabled:
        system_prompt = artifact_convention + system_prompt
    else:
        system_prompt = CODE_MODE_INSTRUCTIONS + system_prompt

    # Uploaded file list
    system_prompt += f"\n\n[SYSTEM DATA]: Uploaded Files: {file_list_str}"

    # Workspace files (uploaded + generated files the model can act on)
    if workspace_files:
        ws_lines = "\n".join(
            f"  - {f.get('display_name') or f.get('filename', '?')} ({f.get('file_type', '?')})"
            for f in workspace_files
        )
        system_prompt += (
            "\n\n## File Workspace\n"
            "These files are available in this conversation's workspace:\n"
            f"{ws_lines}\n"
            "Use `view(path)` to read a file, `run_terminal` to create or edit files, "
            "and `present_file(filename)` to load a file into canvas and give the user a download link."
        )
        # Include code project details if any
        for f in workspace_files:
            if f.get('file_type') == 'code_project':
                meta = f.get('metadata') or {}
                if isinstance(meta, str):
                    try: meta = json.loads(meta)
                    except: meta = {}
                file_tree = meta.get('file_tree', [])
                if file_tree:
                    proj_name = f.get('display_name') or f.get('filename', 'project')
                    def _tree_to_str(tree, indent=0):
                        lines = []
                        for item in tree:
                            prefix = '  ' * indent
                            if item['type'] == 'dir':
                                lines.append(f"{prefix}{item['name']}/")
                                lines.extend(_tree_to_str(item.get('children', []), indent + 1))
                            else:
                                lines.append(f"{prefix}{item['name']}")
                        return lines
                    tree_str = "\n".join(_tree_to_str(file_tree))
                    ws_dir = f.get('path', '')
                    system_prompt += (
                        f"\n\n## Code Project: {proj_name}\n"
                        f"Project directory: {ws_dir}\n"
                        f"File tree:\n{tree_str}\n"
                        "You can read any file using `view(path)` with the relative path from the project. "
                        "To edit project files, use `create_project` to regenerate, or read the file content and use the workspace tools."
                    )

    # Canvas document context
    raw_content = conversation.get("canvas_content", "")
    canvas_text = ""
    c_data = None
    if isinstance(raw_content, dict):
        c_data = raw_content
    elif isinstance(raw_content, str) and raw_content.strip():
        canvas_text = raw_content
        if raw_content.strip().startswith('{'):
            try:
                c_data = json.loads(raw_content)
            except Exception:
                pass

    canvas_title = ""
    if c_data and isinstance(c_data, dict):
        active_id = c_data.get('activeId')
        artifacts = c_data.get('artifacts', {})
        if active_id and active_id in artifacts:
            canvas_title = artifacts[active_id].get('title', '') or ''
            hist = artifacts[active_id].get('history', [])
            if hist:
                canvas_text = hist[-1]

    if canvas_text and canvas_text.strip():
        title_hint = f" (filename: '{canvas_title}')" if canvas_title else ""
        title_rule = f"  Always use title='{canvas_title}' when calling str_replace.\n" if canvas_title else "  ALWAYS specify 'title', 'old_txt', and 'new_txt'.\n"
        read_rule = ""
        system_prompt += (
            "\n[CANVAS DOCUMENT AVAILABLE]:\n"
            f"CURRENT CANVAS CONTENT{title_hint}:\n\"\"\"\n{canvas_text}\n\"\"\"\n\n"
            "RULES:\n"
            f"{read_rule}"
            "- MANDATORY EDIT WORKFLOW: view(filename) → str_replace(title, old_txt, new_txt) → present_file(filename).\n"
            f"{title_rule}"
            "- The canvas does NOT update automatically after str_replace — you MUST call present_file to show the result.\n"
        )

    # Direct read mode
    if direct_read_mode:
        system_prompt += "\n\n[INSTRUCTION]: The user has attached full PDF text in their message. Read carefully and answer directly."


    return system_prompt


def get_openai_tools(code_mode_enabled=False):
    openai_tools = []

    if code_mode_enabled:
        # ── CODE MODE ────────────────────────────────────────────────────────
        # Terminal-first workflow: run_terminal + str_replace + view + present_file

        # view
        openai_tools.append({
            "type": "function",
            "function": {
                "name": "view",
                "description": "Read a file from the project or workspace. Omit path to list all files.",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "path": {"type": "string", "description": "File path to read, or omit to list all files."}
                    },
                    "required": []
                }
            }
        })

        # run_terminal
        openai_tools.append({
            "type": "function",
            "function": {
                "name": "run_terminal",
                "description": (
                    "Execute a shell command in the project directory. "
                    "Use for creating/editing files, running tests, installing packages, building, linting, git commands. "
                    "Timeout: 30 seconds."
                ),
                "parameters": {
                    "type": "object",
                    "properties": {
                        "command": {"type": "string", "description": "REQUIRED: The shell command to run."},
                        "working_dir": {"type": "string", "description": "Optional subdirectory within the project to run from."}
                    },
                    "required": ["command"]
                }
            }
        })

        # str_replace (for precise targeted edits)
        openai_tools.append({
            "type": "function",
            "function": {
                "name": "str_replace",
                "description": "Replace an exact string in a presented canvas file. Use for precise targeted edits when terminal is impractical. ALWAYS specify title, old_txt, and new_txt.",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "title": {"type": "string", "description": "REQUIRED: The exact filename of the canvas file to edit."},
                        "old_txt": {"type": "string", "description": "REQUIRED: The exact text to find and replace."},
                        "new_txt": {"type": "string", "description": "REQUIRED: The replacement text."}
                    },
                    "required": ["title", "old_txt", "new_txt"]
                }
            }
        })

        # present_file
        openai_tools.append({
            "type": "function",
            "function": {
                "name": "present_file",
                "description": "Load a file into the canvas and give the user a download link. Call after creating or editing a file to show it.",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "filename": {"type": "string", "description": "REQUIRED: The filename to present."}
                    },
                    "required": ["filename"]
                }
            }
        })

        # Browser, user-defined, and MCP tools still available in code mode
        try:
            openai_tools.extend(get_browser_tools())
        except Exception as e:
            print(f"⚠️ Error loading browser tools: {e}")

        tools = database.get_tools()
        for t_id, t_data in tools.items():
            safe_name = t_data['name'].replace(" ", "_")
            openai_tools.append({
                "type": "function",
                "function": {
                    "name": safe_name,
                    "description": t_data['initial_prompt'],
                    "parameters": {
                        "type": "object",
                        "properties": {"input_args": {"type": "string", "description": "The arguments to pass to the code."}},
                        "required": ["input_args"]
                    }
                }
            })

        try:
            mcp_tools = mcp_manager.get_all_tools()
            for key, tool_info in mcp_tools.items():
                openai_tools.append({
                    "type": "function",
                    "function": {
                        "name": key,
                        "description": tool_info.get('description', ''),
                        "parameters": tool_info.get('inputSchema', {"type": "object", "properties": {}})
                    }
                })
        except Exception as e:
            print(f"⚠️ MCP: Error loading MCP tools for OpenAI: {e}")

        return openai_tools

    # ── CHAT MODE ─────────────────────────────────────────────────────────────
    # view + run_terminal + str_replace + present_file

    # str_replace (edit canvas files)
    openai_tools.append({
        "type": "function",
        "function": {
            "name": "str_replace",
            "description": "Replace an exact string in a canvas file. Use for precise targeted edits. ALWAYS specify title, old_txt, and new_txt.",
            "parameters": {
                "type": "object",
                "properties": {
                    "title": {"type": "string", "description": "REQUIRED: The exact filename of the canvas file to edit."},
                    "old_txt": {"type": "string", "description": "REQUIRED: The exact text to find and replace."},
                    "new_txt": {"type": "string", "description": "REQUIRED: The replacement text."}
                },
                "required": ["title", "old_txt", "new_txt"]
            }
        }
    })

    # view
    openai_tools.append({
        "type": "function",
        "function": {
            "name": "view",
            "description": "Read a file from the workspace, or list all files if no path given.",
            "parameters": {
                "type": "object",
                "properties": {
                    "path": {"type": "string", "description": "The filename to read. Omit to list all workspace files."}
                },
                "required": []
            }
        }
    })

    # run_terminal
    openai_tools.append({
        "type": "function",
        "function": {
            "name": "run_terminal",
            "description": (
                "Execute a shell command in this conversation's workspace directory. "
                "Use to create or edit files (echo, cat, python -c, etc.), run scripts, or perform any shell operation. "
                "Timeout: 30 seconds."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "command": {"type": "string", "description": "REQUIRED: The shell command to run."},
                    "working_dir": {"type": "string", "description": "Optional subdirectory to run from."}
                },
                "required": ["command"]
            }
        }
    })

    # present_file
    openai_tools.append({
        "type": "function",
        "function": {
            "name": "present_file",
            "description": "Load a file into canvas and give the user a download link. This is the ONLY way to display file content — always call this after creating or editing a file.",
            "parameters": {
                "type": "object",
                "properties": {
                    "filename": {"type": "string", "description": "REQUIRED: The name of the file to present."}
                },
                "required": ["filename"]
            }
        }
    })


    # 1. Browser Tools
    try:
        openai_tools.extend(get_browser_tools())
    except Exception as e:
        print(f"⚠️ Error loading browser tools: {e}")

    # 2. User-Defined Tools
    tools = database.get_tools()
    for t_id, t_data in tools.items():

        safe_name = t_data['name'].replace(" ", "_")
        openai_tools.append({
            "type": "function",
            "function": {
                "name": safe_name,
                "description": t_data['initial_prompt'],
                "parameters": {
                    "type": "object",
                    "properties": {
                        "input_args": {
                            "type": "string",
                            "description": "The arguments to pass to the code."
                        }
                    },
                    "required": ["input_args"]
                }
            }
        })
    
    # 3. MCP Tools
    try:
        mcp_tools = mcp_manager.get_all_tools()
        for key, tool_info in mcp_tools.items():
            openai_tools.append({
                "type": "function",
                "function": {
                    "name": key,
                    "description": tool_info.get('description', ''),
                    "parameters": tool_info.get('inputSchema', {"type": "object", "properties": {}})
                }
            })
    except Exception as e:
        print(f"⚠️ MCP: Error loading MCP tools for OpenAI: {e}")
    
    return openai_tools

# Helper to safely execute tool code
def execute_tool_code(code, input_args, user_id=None):
    import ast
    import sys
    import importlib
    import builtins
    
    # 1. Parse Input Args (JSON/Dict strings)
    if isinstance(input_args, str):
        try:
            import json
            parsed_args = json.loads(input_args)
            if isinstance(parsed_args, dict):
                input_args = parsed_args
        except Exception:
            try:
                parsed_args = ast.literal_eval(input_args)
                if isinstance(parsed_args, dict):
                    input_args = parsed_args
            except Exception:
                pass
    
    if not isinstance(input_args, dict):
        input_args = {}

    # 2. AST Sandbox (Block Dangerous Imports)
    blocked_imports = {'os', 'sys', 'subprocess', 'shutil', 'pty', 'socket', 'urllib', 'multiprocessing', 'builtins'}
    try:
        tree = ast.parse(code)
    except SyntaxError as e:
        return f"Syntax Error in Tool Code: {str(e)}"
        
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                base_module = alias.name.split('.')[0]
                if base_module in blocked_imports:
                    return f"Security Restriction: Importing '{alias.name}' is prohibited."
        elif isinstance(node, ast.ImportFrom):
            if node.module:
                base_module = node.module.split('.')[0]
                if base_module in blocked_imports:
                    return f"Security Restriction: Importing from '{node.module}' is prohibited."
        # Block dunder manipulation (__class__, __subclasses__) for sandbox escapes
        elif isinstance(node, ast.Attribute):
            if node.attr.startswith('__') and node.attr.endswith('__'):
                if node.attr not in ('__init__', '__name__'): # allow common safe dunders
                    return f"Security Restriction: Accessing '{node.attr}' is prohibited."

    # 3. Setup Per-User Dependency Injection Space
    original_path = sys.path.copy()
    user_lib_path = None
    if user_id:
        user_lib_path = os.path.join(RESOURCE_ROOT, 'storage', 'envs', user_id, 'lib')
        if os.path.exists(user_lib_path):
            sys.path.insert(0, user_lib_path)
            
    # 4. Strip Dangerous Built-ins from Globals
    safe_builtins = __builtins__.copy() if isinstance(__builtins__, dict) else __builtins__.__dict__.copy()
    dangerous_builtins = ['open', 'eval', 'exec', 'compile', '__import__', 'input', 'memoryview']
    for b in dangerous_builtins:
        safe_builtins.pop(b, None)
        
    # Provide a safe __import__ that still honors the AST checks (double-guard)
    original_import = builtins.__import__
    def safe_import(name, globals=None, locals=None, fromlist=(), level=0):
        base_module = name.split('.')[0]
        if base_module in blocked_imports:
            raise ImportError(f"Security Restriction: Module '{name}' is prohibited.")
        return original_import(name, globals, locals, fromlist, level)
    
    safe_builtins['__import__'] = safe_import

    restricted_globals = {
        "__builtins__": safe_builtins,
        "__name__": "__main__",
    }
    
    local_scope = {"input_args": input_args, "result": None}
    
    # 5. Execute Sandboxed Code
    try:
        exec(code, restricted_globals, local_scope)
        return str(local_scope.get("result", "No 'result' variable set in tool code."))
    except ImportError as e:
        return f"Execution Error: {str(e)}\n\nYou may need to open the Tools menu and Install this package to your User Environment."
    except Exception as e:
        return f"Execution Error: {str(e)}"
    finally:
        # Restore original sys.path safely
        if user_lib_path and user_lib_path in sys.path:
            sys.path.remove(user_lib_path)
        sys.path = original_path

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({"error": "Unauthorized"}), 401
        
        # Verify user still exists in DB (Critical for bundled app migrations)
        user = database.get_user(session['user_id'])
        if not user:
            session.clear()
            return jsonify({"error": "User not found. Please log in again."}), 401
            
        return f(*args, **kwargs)
    return decorated_function


# --- WORKSPACE DOWNLOAD ROUTE ---
@app.route('/workspace/download/<attachment_id>')
@login_required
def workspace_download(attachment_id):
    """Serve a workspace file as a download."""
    att = database.get_attachment_by_id(attachment_id)
    if not att:
        return jsonify({"error": "File not found"}), 404
    if att.get('user_id') != session.get('user_id'):
        return jsonify({"error": "Forbidden"}), 403
    fpath = att.get('path')
    if not fpath or not os.path.exists(fpath):
        return jsonify({"error": "File missing from disk"}), 404
    download_name = att.get('display_name') or att.get('filename') or os.path.basename(fpath)
    return send_file(fpath, as_attachment=True, download_name=download_name)


