@app.route("/api/mcp/servers/add", methods=["POST"])
@login_required
@admin_required
def mcp_add_server():
    if HOSTED_MODE:
        return hosted_route_disabled("MCP server management is disabled in hosted mode.")
    data = request.get_json()
    name = data.get("name", "").strip()
    if not name:
        return jsonify({"success": False, "error": "Server name is required"}), 400
    
    server_config = {}
    transport = data.get("transport", "stdio")
    
    if transport == "web":
        url = data.get("url", "").strip()
        if not url:
            return jsonify({"success": False, "error": "URL is required for web servers"}), 400
        server_config["url"] = url
        headers = data.get("headers", {})
        if headers:
            server_config["headers"] = headers
    else:
        command = data.get("command", "").strip()
        if not command:
            return jsonify({"success": False, "error": "Command is required for stdio servers"}), 400
        server_config["command"] = command
        args = data.get("args", [])
        if isinstance(args, str):
            args = [a.strip() for a in args.split() if a.strip()]
        server_config["args"] = args
        env_str = data.get("env", {})
        if isinstance(env_str, str) and env_str.strip():
            try:
                server_config["env"] = json.loads(env_str)
            except:
                pass
        elif isinstance(env_str, dict) and env_str:
            server_config["env"] = env_str
    
    mcp_manager.add_server(name, server_config)
    
    # Auto-start
    auto_start = data.get("auto_start", True)
    if auto_start:
        success, error = mcp_manager.start_server(name)
        if not success:
            return jsonify({"success": True, "warning": f"Server added but failed to start: {error}", "servers": mcp_manager.get_status()})
    
    return jsonify({"success": True, "servers": mcp_manager.get_status()})


# --- PER-USER PYTHON PACKAGE MANAGEMENT ---
@app.route("/api/packages/install", methods=["POST"])
@login_required
def api_install_package():
    if HOSTED_MODE:
        return hosted_route_disabled("Host-level package installation is disabled in hosted mode. Use workspace runtimes instead.")
    user_id = session['user_id']
    data = request.get_json()
    package_name = data.get("package")
    
    if not package_name or not package_name.strip():
        return jsonify({"success": False, "error": "Package name required"})
        
    # Sanitize package name (prevent command injection)
    import re
    if not re.match(r"^[a-zA-Z0-9_\-\.]+$", package_name):
        return jsonify({"success": False, "error": "Invalid package name format"})

    env_dir = os.path.join(RESOURCE_ROOT, 'storage', 'envs', user_id, 'lib')
    os.makedirs(env_dir, exist_ok=True)
    
    try:
        import subprocess
        # Run pip install securely to the target user directory
        result = subprocess.run(
            [sys.executable, "-m", "pip", "install", package_name, "-t", env_dir],
            capture_output=True, text=True, timeout=60
        )
        if result.returncode == 0:
            return jsonify({"success": True, "message": f"Successfully installed {package_name}"})
        else:
            return jsonify({"success": False, "error": result.stderr})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)})

@app.route("/api/packages/list", methods=["GET"])
@login_required
def api_list_packages():
    if HOSTED_MODE:
        return jsonify({"success": True, "packages": []})
    user_id = session['user_id']
    env_dir = os.path.join(RESOURCE_ROOT, 'storage', 'envs', user_id, 'lib')
    
    if not os.path.exists(env_dir):
        return jsonify({"success": True, "packages": []})
        
    packages = set()
    for item in os.listdir(env_dir):
        # Very basic parsing of installed top-level namespaces / dist-info
        if item.endswith(".dist-info"):
            pkg = item.split("-")[0]
            if pkg: packages.add(pkg)
            
    return jsonify({"success": True, "packages": sorted(list(packages))})
