@app.route("/api/resolve_image/<path:filename>")
@login_required
def resolve_image(filename):
    """Resolve an image filename to its actual storage path and serve it."""
    user_id = session.get("user_id")
    # 1. Check storage/images
    direct = os.path.join(IMAGE_STORAGE, filename)
    if os.path.isfile(direct):
        return send_file(direct)
    # 2. Look up in attachments DB
    images = database.load_user_attachments(user_id, 'image')
    for img in images:
        if img.get('name') == filename or img.get('display_name') == filename:
            fpath = img.get('path')
            if fpath and os.path.isfile(fpath):
                return send_file(fpath)
            # Try -x variant
            name, ext = os.path.splitext(fpath or "")
            xpath = f"{name}-x{ext}"
            if os.path.isfile(xpath):
                return send_file(xpath)
    # 3. Search workspace dirs for this user — match on display_name, stem, or secure name
    # Strip the chat_code suffix if present (e.g. "photo-abc123.png" → "photo.png")
    import re as _re
    stem_no_code = _re.sub(r'-[a-f0-9]{6,8}(\.[^.]+)$', r'\1', filename)
    user_ws = os.path.join(WORKSPACE_STORAGE, str(user_id))
    if os.path.isdir(user_ws):
        for root, dirs, files in os.walk(user_ws):
            for f in files:
                if f == filename or f == secure_filename(filename) or f == stem_no_code or f == secure_filename(stem_no_code):
                    return send_file(os.path.join(root, f))
    return "", 404

@app.route("/upload_image", methods=["POST"])
@login_required
def upload_image():
    user_id = session['user_id']
    if 'image' not in request.files:
        return jsonify({"success": False, "error": "No image provided"}), 400
    
    image_file = request.files['image']
    if image_file.filename == '':
        return jsonify({"success": False, "error": "No file selected"}), 400
    
    if not image_file.filename.lower().endswith(('.png', '.jpg', '.jpeg', '.gif')):
        return jsonify({"success": False, "error": "Only image files are allowed"}), 400
    
    # Get the chat code
    conv_id = session.get("conversation_id")
    chat_code = None
    if conv_id:
        conversation = database.get_conversation(conv_id)
        if conversation:
            chat_code = conversation.get("chat_code")

            
    # Create the new filename
    original_filename = image_file.filename
    display_filename = original_filename
    if chat_code:
        name, ext = os.path.splitext(original_filename)
        display_filename = f"{name}-{chat_code}{ext}"

    # Save to workspace dir (per-user, per-conversation)
    ws_dir = os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default"))
    os.makedirs(ws_dir, exist_ok=True)
    ws_fname = secure_filename(original_filename)
    if not ws_fname:
        ws_fname = display_filename
    ws_path = os.path.join(ws_dir, ws_fname)
    # Deduplicate if name already exists
    if os.path.exists(ws_path):
        base, ext = os.path.splitext(ws_fname)
        counter = 1
        while os.path.exists(ws_path):
            ws_path = os.path.join(ws_dir, f"{base}_{counter}{ext}")
            counter += 1
        ws_fname = os.path.basename(ws_path)
    image_file.save(ws_path)
    file_path = ws_path

    images = database.load_user_attachments(user_id, 'image')

    if images:
        last_number = max(img.get('number', 0) for img in images)
        new_number = last_number + 1
    else:
        new_number = 1

    database.save_user_attachment(user_id, display_filename, 'image', chat_code, None, 0, 0, file_path, {"number": new_number}, display_name=original_filename)


    # --- NEW: SESSION TRACKING (MATCHING PDF LOGIC) ---
    if 'just_uploaded_images' not in session:
        session['just_uploaded_images'] = []
    session['just_uploaded_images'].append(display_filename)
    session.modified = True
    # --------------------------------------------------

    # --- GENERATE WEB PATH FOR THUMBNAIL ---
    # Convert absolute storage path to a web path relative to our /storage/ route
    web_path = "/storage/" + os.path.relpath(file_path, STORAGE_DIR).replace("\\", "/")
    
    return jsonify({
        "success": True, 
        "filename": display_filename, 
        "imageNumber": new_number,
        "chat_code": chat_code,
        "web_path": web_path # <--- This is required for the thumbnail
    })

