@app.route("/toggle_image", methods=["POST"])
@login_required 
def toggle_image():
    user_id = session['user_id']
    data = request.get_json()
    image_name = data.get("image_name")
    active = data.get("active")
    
    if image_name is None or active is None:
        return jsonify({"success": False, "error": "Missing parameters"}), 400
    
    images = load_user_images(user_id)
    target_image = None
    images = database.load_user_attachments(user_id, 'image')
    for img in images:
        if img["name"] == image_name:
            target_image = img
            break
        name, ext = os.path.splitext(img["name"])
        if name.endswith("-x"):
            original_guess = name[:-2] + ext
            if original_guess == image_name:
                target_image = img
                break
    
    if target_image:
        database.update_attachment_status(user_id, target_image["name"], 'image', target_image.get('package_id'), target_image.get('sent', 0), active)
        return jsonify({"success": True})

    
    return jsonify({"success": False, "error": f"Image '{image_name}' not found"}), 404

@app.route("/delete_image", methods=["POST"])
@login_required
def delete_image():
    user_id = session['user_id']
    data = request.get_json()
    image_name = data.get("image_name")
    
    if image_name is None:
        return jsonify({"success": False, "error": "Missing image_name parameter"}), 400
    
    images = load_user_images(user_id)
    image_to_delete = next((img for img in images if img["name"] == image_name), None)
    
    if not image_to_delete:
        return jsonify({"success": False, "error": "Image not found"}), 404
    
    # Remove the file from the filesystem
    image_path = image_to_delete["path"]
    if os.path.exists(image_path):
        os.remove(image_path)
    
    # Remove the image from the user's list
    # For now, we don't have a specific delete_attachment by filename, so we can use a generic query if needed
    # or just rely on database consistency.
    conn = database.get_db_connection()
    conn.execute("DELETE FROM attachments WHERE user_id = %s AND filename = %s AND file_type = 'image'", (user_id, image_name))
    conn.commit()
    conn.close()

    
    return jsonify({"success": True})


