def format_text(text):
    return re.sub(r'\*(.*?)\*', r'<em>\1</em>', text)

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({"error": "Unauthorized"}), 401
        
        # Verify user still exists in DB (Critical for bundled app migrations)
        user = database.get_user(session['user_id'])
        if not user:
            session.clear()
            return jsonify({"error": "User not found. Please log in again."}), 401
            
        return f(*args, **kwargs)
    return decorated_function

def _strip_div_class(text, div_class):
    """Remove all outermost <div class="div_class...">...</div> blocks, handling nesting."""
    marker = f'<div class="{div_class}'
    while marker in text:
        start_idx = text.find(marker)
        div_count = 0
        i = start_idx
        end_idx = -1
        while i < len(text):
            if text.startswith('<div', i):
                div_count += 1
                i += 4
            elif text.startswith('</div', i):
                div_count -= 1
                i += 5
                if div_count == 0:
                    close_ang = text.find('>', i)
                    end_idx = (close_ang + 1) if close_ang != -1 else i
                    break
            else:
                i += 1
        if end_idx != -1:
            text = text[:start_idx] + text[end_idx:]
        else:
            text = text[:start_idx] + text[start_idx + len(marker):]
    return text

def strip_tool_blocks(text):
    """Safely and precisely removes all tool UI HTML from the AI's memory context."""
    if not text:
        return text
    for cls in ("tool-code-block", "tool-activity-group"):
        text = _strip_div_class(text, cls)
    # Remove any stray remnant tags from partial writes
    text = re.sub(r'<div class="tool-flow[^"]*"[^>]*>[\s\S]*?</div>', '', text)
    text = re.sub(r'<div class="tool-activity[^"]*"[^>]*>', '', text)
    text = re.sub(r'<div class="tg-[^"]*"[^>]*>', '', text)
    return text.strip()

def strip_tool_html_from_message(msg):
    """Strip all tool UI HTML from a history message dict in-place (text + versions)."""
    if not isinstance(msg, dict) or msg.get('sender') != 'bot':
        return
    if msg.get('text'):
        msg['text'] = strip_tool_blocks(msg['text'])
    if isinstance(msg.get('versions'), list):
        msg['versions'] = [strip_tool_blocks(v) if isinstance(v, str) else v for v in msg['versions']]

def run_strip_db(label=""):
    """Scan every branch in the DB and strip all tool UI HTML from bot message text/versions."""
    try:
        _conn = database.get_db_connection()
        rows = _conn.execute("SELECT id, history FROM branches WHERE history IS NOT NULL").fetchall()
        total = 0
        for row in rows:
            try:
                hist = json.loads(row['history'])
            except Exception:
                continue
            changed = False
            for msg in hist:
                if msg.get('sender') != 'bot':
                    continue
                orig_text = msg.get('text', '') or ''
                clean_text = strip_tool_blocks(orig_text)
                if clean_text != orig_text:
                    msg['text'] = clean_text
                    changed = True
                    total += 1
                if isinstance(msg.get('versions'), list):
                    for i, v in enumerate(msg['versions']):
                        if isinstance(v, str):
                            cv = strip_tool_blocks(v)
                            if cv != v:
                                msg['versions'][i] = cv
                                changed = True
                                total += 1
            if changed:
                _conn.execute("UPDATE branches SET history = %s WHERE id = %s",
                              (json.dumps(hist, ensure_ascii=False), row['id']))
        _conn.commit()
        _conn.close()
        tag = f" [{label}]" if label else ""
        print(f"[STRIP DB]{tag} Cleaned {total} message field(s) across {len(rows)} branch(es).")
    except Exception as e:
        print(f"[STRIP DB] ERROR: {e}")

def run_fix_polluted_artifacts(label=""):
    """Fix polluted artifact versions where a version is a superset of the previous one.
    Removes polluted versions from canvas_artifacts history and cleans them from branch messages."""
    def _html_escape(s):
        return s.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
    try:
        _conn = database.get_db_connection()
        artifacts = _conn.execute(
            "SELECT id, conversation_id, history_json FROM canvas_artifacts"
        ).fetchall()
        total_fixed = 0
        for art in artifacts:
            art_id = art['id']
            conv_id = art['conversation_id']
            try:
                history = json.loads(art['history_json'])
            except Exception:
                continue
            if not history or len(history) < 2:
                continue
            new_history = [history[0]]
            modified = False
            for i in range(1, len(history)):
                prev_version = history[i - 1]
                curr_version = history[i]
                if curr_version.startswith(prev_version) and curr_version != prev_version:
                    surplus = curr_version[len(prev_version):]
                    modified = True
                    total_fixed += 1
                    branch_rows = _conn.execute(
                        "SELECT id, history FROM branches WHERE conversation_id = %s AND history IS NOT NULL",
                        (conv_id,)
                    ).fetchall()
                    for b_row in branch_rows:
                        try:
                            messages = json.loads(b_row['history'])
                        except Exception:
                            continue
                        branch_modified = False
                        for msg in messages:
                            if 'text' not in msg:
                                continue
                            text = msg.get('text', '') or ''
                            if curr_version in text:
                                msg['text'] = text.replace(curr_version, prev_version)
                                if surplus.strip() and not msg['text'].endswith(surplus.strip()):
                                    msg['text'] += f"\n\n{surplus.strip()}"
                                branch_modified = True
                            else:
                                esc_curr = _html_escape(curr_version)
                                esc_prev = _html_escape(prev_version)
                                if esc_curr in text:
                                    msg['text'] = text.replace(esc_curr, esc_prev)
                                    branch_modified = True
                        if branch_modified:
                            _conn.execute(
                                "UPDATE branches SET history = %s WHERE id = %s",
                                (json.dumps(messages, ensure_ascii=False), b_row['id'])
                            )
                else:
                    new_history.append(curr_version)
            if modified:
                _conn.execute(
                    "UPDATE canvas_artifacts SET history_json = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s",
                    (json.dumps(new_history), art_id)
                )
        _conn.commit()
        _conn.close()
        tag = f" [{label}]" if label else ""
        print(f"[FIX POLLUTED]{tag} Fixed {total_fixed} polluted version(s) across {len(artifacts)} artifact(s).")
    except Exception as e:
        print(f"[FIX POLLUTED] ERROR: {e}")

def run_deduplicate_db(label=""):
    """Remove duplicate versions within artifact histories and delete entirely duplicate artifacts."""
    try:
        _conn = database.get_db_connection()
        artifacts = _conn.execute(
            "SELECT id, title, history_json, conversation_id FROM canvas_artifacts ORDER BY updated_at DESC"
        ).fetchall()
        versions_purged = 0
        artifacts_deleted = 0
        # 1. Deduplicate versions within each artifact
        for art in artifacts:
            art_id = art['id']
            try:
                history = json.loads(art['history_json'])
            except Exception:
                continue
            if not history:
                continue
            seen = set()
            new_history = []
            changed = False
            for version in history:
                if version in seen:
                    changed = True
                    versions_purged += 1
                    continue
                if new_history and version.startswith(new_history[-1]) and version != new_history[-1]:
                    changed = True
                    versions_purged += 1
                    continue
                new_history.append(version)
                seen.add(version)
            if changed:
                _conn.execute(
                    "UPDATE canvas_artifacts SET history_json = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s",
                    (json.dumps(new_history), art_id)
                )
        # 2. Remove duplicate artifacts (same conversation_id + title + history_json)
        seen_artifacts = {}
        to_delete = []
        for art in artifacts:
            key = (art['conversation_id'], art['title'], art['history_json'])
            if key in seen_artifacts:
                to_delete.append(art['id'])
            else:
                seen_artifacts[key] = art['id']
        for art_id in to_delete:
            _conn.execute("DELETE FROM canvas_artifacts WHERE id = %s", (art_id,))
            artifacts_deleted += 1
        _conn.commit()
        _conn.close()
        tag = f" [{label}]" if label else ""
        print(f"[DEDUP DB]{tag} Purged {versions_purged} duplicate version(s), deleted {artifacts_deleted} duplicate artifact(s).")
    except Exception as e:
        print(f"[DEDUP DB] ERROR: {e}")

def format_messages_for_openai(internal_history):
    """
    Converts internal {role, content, images:[]} format 
    to OpenAI {role, content: [{type:text}, {type:image_url}]} format.
    """
    formatted = []
    for msg in internal_history:
        # 1. Handle Assistant Tool Calls (Pass through)
        if "tool_calls" in msg and msg.get("role") == "assistant":
            formatted.append(msg)
            continue
            
        # 2. Handle Text + Images (User/Assistant/Tool)
        new_msg = {"role": msg["role"]}
        if msg.get("role") == "tool":
            if "tool_call_id" in msg:
                new_msg["tool_call_id"] = msg["tool_call_id"]
            if "name" in msg:
                new_msg["name"] = msg["name"]
                
        content_text = msg.get("content", "") or ""
        images = msg.get("images", [])
        
        if images:
            # Vision Format
            content_parts = []
            if content_text:
                content_parts.append({"type": "text", "text": content_text})
            
            for img_b64 in images:
                # Ensure header is present for OpenAI compatibility
                src = f"data:image/jpeg;base64,{img_b64}" if "data:" not in img_b64 else img_b64
                content_parts.append({
                    "type": "image_url",
                    "image_url": {"url": src}
                })
            new_msg["content"] = content_parts
        else:
            # Standard Text
            new_msg["content"] = content_text
            
        formatted.append(new_msg)
    return formatted

def extract_text_from_pdf(pdf_path):
    try:
        with open(pdf_path, 'rb') as file:
            pdf_reader = PyPDF2.PdfReader(file)
            documents = []
            for page in pdf_reader.pages:
                text = page.extract_text()
                if text and text.strip():
                    documents.append(text.strip())
            return documents
    except Exception as e:
        app.logger.error(f"Error processing PDF: {str(e)}")
        return []

@app.route("/chat", methods=["POST"])
@login_required
@rate_limit("chat", 60, 60)
def chat():
    import glob
    import base64
    import re
    
    try:
        user_id = session['user_id']
        data = request.get_json()
        if not data or "message" not in data:
            return jsonify({"error": "Invalid request format"}), 400
            
        user_message = data["message"]
        attachments = data.get("attachments", [])
        direct_read_mode = data.get("direct_read_mode", False)
        is_canvas_active = data.get("canvas_mode", False)

        canvas_version_index = data.get("canvas_version_index")
        
        conv_id = session.get("conversation_id")
        if not conv_id:
            return jsonify({"error": "Start a conversation first"}), 400

        conversation = database.get_conversation(conv_id)
        if not conversation:
            return jsonify({"error": "Conversation not found"}), 404

        urgent_context_instruction = ""
        file_list_str = "None"
        updated_attachments_for_history = []
        current_package_id = str(uuid.uuid4())
        
        user_record = database.get_user(user_id)
        user_pdfs = database.load_user_attachments(user_id, 'pdf')
        user_images = database.load_user_attachments(user_id, 'image')
        image_lookup = {img['name']: img['path'] for img in user_images}

        if attachments:
            for attachment_info in attachments:
                original_filename = attachment_info.get("filename")
                file_type = attachment_info.get("type")
                file_list = user_pdfs if file_type == 'pdf' else user_images
                file_record = next((f for f in file_list if f["name"] == original_filename), None)
                hist_entry = {"filename": original_filename, "type": file_type or "unknown"}
                if file_record:
                    database.update_attachment_status(user_id, file_record['name'], file_type, current_package_id, 1, 0)
                    hist_entry["filename"] = file_record["name"]
                    # Store web path for image rendering
                    if file_record.get("path") and file_type == "image":
                        try:
                            hist_entry["src"] = "/storage/" + os.path.relpath(file_record["path"], STORAGE_DIR).replace("\\", "/")
                        except ValueError:
                            pass
                # Preserve frontend-provided src as fallback
                if not hist_entry.get("src") and attachment_info.get("src"):
                    hist_entry["src"] = attachment_info.get("src")
                updated_attachments_for_history.append(hist_entry)
            user_pdfs = database.load_user_attachments(user_id, 'pdf')
            user_images = database.load_user_attachments(user_id, 'image')
            image_lookup = {img['name']: img['path'] for img in user_images}

        active_branch = conversation.get("active_branch", "main")
        branch = conversation["branches"][active_branch]
        history = branch["history"]
        current_chat_code = conversation.get('chat_code')

        relevant_pdfs = [p for p in user_pdfs if p.get('chat_code') == current_chat_code or p.get('chat_code') is None]
        if relevant_pdfs:
            relevant_pdfs.sort(key=lambda x: x.get('number', 0))
            file_list_str = ", ".join([f"{p.get('number')}. {p['name']}" for p in relevant_pdfs])

        just_uploaded_pdfs = session.get('just_uploaded_pdfs', [])
        just_uploaded_images = session.get('just_uploaded_images', [])
        all_just_uploaded = just_uploaded_pdfs + just_uploaded_images
        
        context_parts = []
        if just_uploaded_pdfs: context_parts.append(f"PDF(s): {', '.join(just_uploaded_pdfs)}")
        if just_uploaded_images: context_parts.append(f"Image(s): {', '.join(just_uploaded_images)}")
        if context_parts:
            combined_list_str = " AND ".join(context_parts)
            urgent_context_instruction = f"[SYSTEM ALERT]: The user JUST uploaded: {combined_list_str}. Focus on these."

        auto_read_pdfs = []
        for att in updated_attachments_for_history:
            if att.get('type') == 'pdf': auto_read_pdfs.append(att.get('filename'))
        for fname in just_uploaded_pdfs:
            if fname not in auto_read_pdfs: auto_read_pdfs.append(fname)
        auto_read_pdfs = list(set(auto_read_pdfs))

        # --- DIRECT READ MODE PDF INJECTION ---
        prompt_pdf_context = ""
        # Build a lookup from display_name/filename -> path using DB attachment records
        _pdf_path_lookup = {}
        for p in user_pdfs:
            if p.get('path'):
                _pdf_path_lookup[p.get('display_name') or p.get('name', '')] = p['path']
                _pdf_path_lookup[p.get('name', '')] = p['path']
        if direct_read_mode and auto_read_pdfs:
            pdf_texts = []
            for fname in auto_read_pdfs:
                target_path = _pdf_path_lookup.get(fname)
                if not target_path or not os.path.exists(target_path):
                    # Legacy fallback: try PDF_STORAGE
                    possible_paths = [
                        os.path.join(PDF_STORAGE, fname),
                        os.path.join(PDF_STORAGE, f"{user_id}_{fname}")
                    ]
                    name_part, ext_part = os.path.splitext(fname)
                    if not name_part.endswith("-x"):
                        possible_paths.append(os.path.join(PDF_STORAGE, f"{name_part}-x{ext_part}"))
                    for p in possible_paths:
                        if os.path.exists(p):
                            target_path = p
                            break

                if target_path and os.path.exists(target_path):
                    extracted_pages = extract_text_from_pdf(target_path)
                    if extracted_pages:
                        full_pdf_text = "\n".join(extracted_pages)
                        pdf_texts.append(f"{fname}\n_______________________\n{full_pdf_text}\n_______________________")
            
            if pdf_texts:
                prompt_pdf_context = "\n\n" + "\n\n".join(pdf_texts)


        # --- SYSTEM PROMPT ---
        code_mode_enabled = database.get_setting('code_mode_enabled', 'false') == 'true'
        workspace_files = database.get_workspace_files(conv_id) if conv_id else []
        # Also include all user files (PDFs, images) not already in workspace_files
        _ws_seen_ids = {f.get("id") for f in workspace_files}
        for _att in user_pdfs + user_images:
            if _att.get("id") not in _ws_seen_ids:
                workspace_files.append(_att)
                _ws_seen_ids.add(_att.get("id"))
        system_prompt = build_system_prompt(
            conversation, file_list_str, direct_read_mode, code_mode_enabled,
            workspace_files=workspace_files
        )

        # Build active tools dict for text-syntax fallback detection (used inside generate())
        all_tools = database.get_tools()
        system_tools = SYSTEM_TOOLS
        assistant_tools_list = []
        if not conversation.get("bot_id") or conversation.get("bot_id") == "":
            assistant_tools_list = json.loads(database.get_setting('assistant_enabled_tools', '[]'))
            if assistant_tools_list:
                all_tools = {k: v for k, v in all_tools.items() if k in assistant_tools_list}
                system_tools = {k: v for k, v in system_tools.items() if k in assistant_tools_list}

        all_active_tools = {**all_tools, **system_tools}
        try:
            mcp_tools = mcp_manager.get_all_tools()
            for mkey, mval in mcp_tools.items():
                if not conversation.get("bot_id") or conversation.get("bot_id") == "" or mkey in assistant_tools_list:
                    all_active_tools[mkey] = {
                        "name": mkey,
                        "trigger_word": mkey,
                        "initial_prompt": f"{mval.get('description', '')} [MCP Server: {mval['server']}]"
                    }
        except:
            pass

        user_unique_id = f"{random.randint(100000, 999999)}"
        user_msg_obj = {
            "sender": "user", "text": user_message, "versions": [user_message], "active_version": 0,
            "unique_id": user_unique_id, 
            "profile_photo": f"/storage/profiles/{user_record['photo']}" if user_record and user_record.get('photo') else '',
            "attachments": updated_attachments_for_history,
            "context_files": all_just_uploaded if all_just_uploaded else [],
            "canvas_version_index": canvas_version_index
        }
        
        if just_uploaded_pdfs: session['just_uploaded_pdfs'] = []
        if just_uploaded_images: session['just_uploaded_images'] = []
        if all_just_uploaded: session.modified = True
        
        unique_id = f"{random.randint(100000, 999999)}"
        bot_msg_placeholder = {
            "sender": "bot", "text": "", "versions": [""], "active_version": 0,
            "profile_photo": f"/storage/bots/{conversation.get('bot_photo', '')}" if conversation.get('bot_photo') else '',
            "unique_id": unique_id,
            "canvas_mode": is_canvas_active,
            "tool_trace": []
        }

        history.append(user_msg_obj)
        history.append(bot_msg_placeholder)
        database.update_history(conv_id, active_branch, history)

        set_streaming_status(user_id, conv_id)

        full_message_history = [{"role": "system", "content": system_prompt}]

        for msg in history[:-2]: 
            role = "assistant" if msg['sender'] == 'bot' else "user"
            content = msg.get('text', '') or ""
            msg_images_b64 = []
            
            files_to_process = []
            if 'attachments' in msg and isinstance(msg['attachments'], list):
                for att in msg['attachments']:
                    if att.get('type') == 'image': files_to_process.append(att.get('filename'))
            if 'context_files' in msg and isinstance(msg['context_files'], list):
                for fname in msg['context_files']:
                    if fname.lower().endswith(('.png', '.jpg', '.jpeg', '.gif')):
                        if fname not in files_to_process: files_to_process.append(fname)
            
            for fname in files_to_process:
                fpath = image_lookup.get(fname)
                if not fpath:
                    name_part, ext_part = os.path.splitext(fname)
                    fpath = image_lookup.get(f"{name_part}-x{ext_part}")
                if not fpath:
                    try: matches = glob.glob(os.path.join(IMAGE_STORAGE, f"*{fname}")); fpath = matches[0] if matches else None
                    except: pass
                
                if fpath and os.path.exists(fpath):
                    try:
                        with open(fpath, "rb") as f:
                            msg_images_b64.append(base64.b64encode(f.read()).decode('utf-8'))
                    except: pass
            
            if "tool_trace" in msg and msg["tool_trace"]:
                tool_calls_data = []
                for trace_item in msg["tool_trace"]:
                    tool_calls_data.append({
                        "id": trace_item["id"],
                        "type": "function",
                        "function": {
                            "name": trace_item["name"],
                            "arguments": trace_item["arguments"]
                        }
                    })
                
                think_match = re.search(r'<think>.*?</think>', content, flags=re.DOTALL)
                think_content = think_match.group(0) if think_match else ""
                after_think_content = content.replace(think_content, "").strip()
                after_think_content = strip_tool_blocks(after_think_content).strip()

                payload_a = {
                    "role": role,
                    "content": think_content if think_content else "",
                    "tool_calls": tool_calls_data
                }
                full_message_history.append(payload_a)

                for trace_item in msg["tool_trace"]:
                   full_message_history.append({
                       "role": "tool",
                       "tool_call_id": trace_item["id"],
                       "name": trace_item["name"],
                       "content": trace_item["output"]
                   })
                
                if after_think_content:
                    payload_c = {"role": role, "content": after_think_content}
                    if msg_images_b64: payload_c["images"] = msg_images_b64
                    full_message_history.append(payload_c)
            else:
                payload = {"role": role, "content": content}
                if msg_images_b64: payload["images"] = msg_images_b64 
                full_message_history.append(payload)

        current_turn_images_b64 = []
        current_turn_files = []
        current_turn_files.extend([a['filename'] for a in updated_attachments_for_history if a['type'] == 'image'])
        for f in just_uploaded_images:
            if f not in current_turn_files: current_turn_files.append(f)
        for fname in current_turn_files:
            fpath = image_lookup.get(fname)
            if not fpath:
                name_part, ext_part = os.path.splitext(fname)
                fpath = image_lookup.get(f"{name_part}-x{ext_part}")
            if fpath and os.path.exists(fpath):
                try:
                    with open(fpath, "rb") as f:
                        current_turn_images_b64.append(base64.b64encode(f.read()).decode('utf-8'))
                except: pass

        if urgent_context_instruction:
            full_message_history.append({"role": "system", "content": urgent_context_instruction})

        current_user_payload = {"role": "user", "content": f"{user_message}{prompt_pdf_context}"}
        if current_turn_images_b64:
            current_user_payload["images"] = current_turn_images_b64
        
        def generate():
            client, current_model_name = get_openai_client()
            state = {"text": "", "buffer": "", "is_thinking": False, "has_opened_thought": False}
            current_tool_trace = []
            presented_files = set()  # Track files already presented/created in this response
            inference_messages = full_message_history[:]
            artifact_counter = [0]
            
            def _restore_artifact_to_codeblock(m):
                title = m.group(1) or 'Document'
                title = title.replace('&amp;', '&').replace('&lt;', '<').replace('&gt;', '>').replace('&quot;', '"')
                return f'[artifact: {title}]'

            for msg in inference_messages:
                if msg.get("role") == "assistant" and isinstance(msg.get("content"), str):
                    # 1. Restore artifact cards to titled placeholders (restore before strip to get the filename)
                    msg["content"] = re.sub(r'<artifact-card[^>]*data-title="([^"]*)"[^>]*data-content="([^"]*)"[^>]*>.*?</artifact-card>', _restore_artifact_to_codeblock, msg["content"], flags=re.DOTALL)
                    msg["content"] = re.sub(r'<artifact-card[^>]*data-title="([^"]*)"[^>]*data-content="([^"]*)"[^>]*/?>',  _restore_artifact_to_codeblock, msg["content"])
                    # 2. Strip any remaining unmatched artifact cards
                    msg["content"] = re.sub(r'<artifact-card[^>]*>.*?</artifact-card>', '', msg["content"], flags=re.DOTALL)
                    msg["content"] = re.sub(r'<artifact-card[^>]*>', '', msg["content"])
                    # 3. Strip tool blocks
                    msg["content"] = strip_tool_blocks(msg["content"])

            # --- Inject current canvas artifact state so the model always knows the true file contents ---
            # This prevents stale-content issues when a user edits a previous message
            try:
                _ca_conn = database.get_db_connection()
                _ca_rows = _ca_conn.execute(
                    "SELECT title, history_json FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) ORDER BY updated_at DESC",
                    ((conv_id or "").strip(),)
                ).fetchall()
                _ca_conn.close()
                _canvas_state_parts = []
                for _ca_row in _ca_rows:
                    try:
                        _ca_hist = json.loads(_ca_row['history_json']) if _ca_row['history_json'] else []
                    except Exception:
                        _ca_hist = []
                    if _ca_hist:
                        _canvas_state_parts.append(f"--- {_ca_row['title']} ---\n{_ca_hist[-1]}")
                if _canvas_state_parts:
                    _artifact_titles = [r['title'] for r in _ca_rows if r['title']]
                    print(f"[CANVAS STATE] Injecting {len(_canvas_state_parts)} artifact(s) into context: {_artifact_titles}")
                    inference_messages.append({
                        "role": "system",
                        "content": "[CANVAS STATE] The following are the CURRENT contents of the canvas artifact(s). When using str_replace, use the old_str values based on THIS content, NOT from earlier messages in the conversation.\n\n" + "\n\n".join(_canvas_state_parts)
                    })
                else:
                    print(f"[CANVAS STATE] No canvas artifacts found for conv_id={conv_id}")
            except Exception as _ca_err:
                print(f"[CANVAS STATE] Error fetching canvas state: {_ca_err}")

            inference_messages.append(current_user_payload)


            def execute_hybrid_tool(name, args_input):
                # --- Debug: Log tool call input ---
                try:
                    _in_json = json.dumps(args_input, default=str, ensure_ascii=False)[:2000] if isinstance(args_input, dict) else str(args_input)[:2000]
                except Exception:
                    _in_json = repr(args_input)[:2000]
                print(f"\n[TOOL CALL] {name}\n[TOOL INPUT] {_in_json}")

                try:
                    # --- execute_code: Code Mode (Cloudflare pattern) ---
                    if name == "execute_code":
                        if isinstance(args_input, dict):
                            code_str = args_input.get("code", "")
                            desc_str = args_input.get("description", "")
                        else:
                            try:
                                parsed = json.loads(args_input)
                                code_str = parsed.get("code", "")
                                desc_str = parsed.get("description", "")
                            except Exception:
                                code_str = str(args_input)
                                desc_str = ""
                        return _execute_code_mode(execute_hybrid_tool, code_str, desc_str)

                    # --- str_replace: Canvas editing tool ---
                    if name == "str_replace":
                        def get_param(pname, alt_name=None):
                            res = ""
                            if isinstance(args_input, dict):
                                res = args_input.get(pname, "")
                                if not res and alt_name: res = args_input.get(alt_name, "")
                            else:
                                try:
                                    parsed = json.loads(args_input)
                                    res = parsed.get(pname, "")
                                    if not res and alt_name: res = parsed.get(alt_name, "")
                                except: pass
                            return res

                        title = get_param("title")
                        old_str = get_param("old_str", "old_txt")
                        new_str = get_param("new_str", "new_txt")

                        missing = []
                        if not title: missing.append("title")
                        if not old_str: missing.append("old_str")
                        if not new_str: missing.append("new_str")

                        if missing:
                            return f"Error: str_replace requires 'title', 'old_str', and 'new_str' parameters. Missing: {', '.join(missing)}."
                        
                        # Apply logic to backend
                        new_title, new_content, err = database.apply_str_replace((conv_id or "").strip(), title, old_str, new_str)
                        if err:
                            # Auto-view the file so the model can retry with the correct old_str
                            print(f"[STR_REPLACE] Failed on '{title}': {err} — fetching current content for retry")
                            try:
                                _sr_conn = database.get_db_connection()
                                _sr_row = _sr_conn.execute(
                                    "SELECT title, history_json FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
                                    ((conv_id or "").strip(), title.strip().lower())
                                ).fetchone()
                                if not _sr_row:
                                    _sr_row = _sr_conn.execute(
                                        "SELECT title, history_json FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) ORDER BY updated_at DESC LIMIT 1",
                                        ((conv_id or "").strip(),)
                                    ).fetchone()
                                _sr_conn.close()
                                if _sr_row:
                                    _sr_hist = json.loads(_sr_row['history_json']) if _sr_row['history_json'] else []
                                    _sr_current = _sr_hist[-1] if _sr_hist else ""
                                    return (
                                        f"Error: {err}\n\n"
                                        f"[AUTO-VIEW] Here is the CURRENT content of '{_sr_row['title']}'. "
                                        f"Retry str_replace using old_str from this content:\n\n{_sr_current}"
                                    )
                            except Exception as _sr_err:
                                print(f"[STR_REPLACE] Auto-view failed: {_sr_err}")
                            return f"Error: {err}"

                        title_part = f"title={new_title}|"
                        return f"__CANVAS_EDIT__|{title_part}{old_str}|__SEP__|{new_str}"


                    # --- read_canvas: Read current artifact content ---
                    if name == "read_canvas":
                        rc_title = ""
                        if isinstance(args_input, dict):
                            rc_title = args_input.get("title", "")
                        else:
                            try:
                                parsed = json.loads(args_input)
                                rc_title = parsed.get("title", "")
                            except: rc_title = str(args_input).strip()
                        if not rc_title:
                            return "Error: read_canvas requires a 'title' parameter."
                        rc_conn = database.get_db_connection()
                        rc_search = rc_title.strip().lower()
                        rc_row = rc_conn.execute(
                            "SELECT * FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
                            ((conv_id or "").strip(), rc_search)
                        ).fetchone()
                        if not rc_row:
                            rc_row = rc_conn.execute(
                                "SELECT * FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) ORDER BY updated_at DESC LIMIT 1",
                                ((conv_id or "").strip(),)
                            ).fetchone()
                        rc_conn.close()
                        if not rc_row:
                            return f"Error: No artifact found with title '{rc_title}'."
                        try:
                            rc_hist = json.loads(rc_row['history_json']) if rc_row['history_json'] else []
                        except: rc_hist = []
                        if not rc_hist:
                            return f"Error: Artifact '{rc_title}' has no content."
                        return f"[Canvas Content for '{rc_row['title']}']:\n{rc_hist[-1]}"

                    # --- create_artifact: Create a new artifact ---
                    if name == "create_artifact":
                        def get_ca_param(pname):
                            if isinstance(args_input, dict):
                                return args_input.get(pname, "")
                            try:
                                parsed = json.loads(args_input)
                                return parsed.get(pname, "")
                            except: return ""

                        raw_name = get_ca_param("name")
                        ca_content = get_ca_param("content")
                        art_type = get_ca_param("type") or "code"

                        # Extract filename from OAI(name)OAI wrapper
                        name_match = re.search(r'OAI\((.*?)\)OAI', raw_name)
                        ca_title = name_match.group(1).strip() if name_match else raw_name.strip()
                        if not ca_title:
                            return "Error: create_artifact requires a 'name' parameter wrapped in OAI()OAI, e.g. OAI(script.py)OAI"
                        if not ca_content:
                            return "Error: create_artifact requires a 'content' parameter with the artifact content."

                        # Reuse existing artifact ID if same title exists for this conversation
                        if conv_id:
                            _conn = database.get_db_connection()
                            _existing = _conn.execute(
                                "SELECT id FROM canvas_artifacts WHERE LOWER(conversation_id) = LOWER(%s) AND LOWER(title) = %s ORDER BY updated_at DESC LIMIT 1",
                                (conv_id, ca_title.lower())
                            ).fetchone()
                            _conn.close()
                            art_id = _existing['id'] if _existing else f"{unique_id}-{artifact_counter[0] + 1}"
                            if not _existing:
                                artifact_counter[0] += 1
                            database.save_canvas_artifact(art_id, conv_id, active_branch, ca_title, art_type, ca_content)
                        else:
                            artifact_counter[0] += 1
                            art_id = f"{unique_id}-{artifact_counter[0]}"

                        safe_title = ca_title.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
                        safe_content = ca_content.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
                        tagged_content = safe_content
                        type_attr = f' data-type="{art_type}"' if art_type in ("code", "html") else ""

                        artifact_html = f'<artifact-card data-id="{art_id}" data-title="{safe_title}" data-content="{tagged_content}"{type_attr}></artifact-card>'
                        return f"__ARTIFACT_CREATE__|{artifact_html}"

                    # --- Workspace tools (view, create_file, present_file) ---
                    if name in ("view", "create_file", "present_file", "create_project", "remove_file", "edit_file"):
                        ws_result = _handle_workspace_tool(name, args_input, conv_id, user_id, active_branch, artifact_counter, unique_id)
                        if ws_result is not None:
                            return ws_result

                    # --- run_terminal: Execute shell command in project directory ---
                    if name in ("run_terminal", "workspace_exec"):
                        try:
                            return _execute_workspace_command_for_tool(conv_id, user_id, args_input)
                        except Exception as _e:
                            return f"Error running command: {_e}"

                    # --- search_project: Grep across project files ---
                    if name == "search_project":
                        import fnmatch as _fnm, re as _re
                        _args = args_input if isinstance(args_input, dict) else {}
                        if not isinstance(_args, dict):
                            try: _args = json.loads(args_input)
                            except: _args = {}
                        _pat = _args.get("pattern", "")
                        _glob = _args.get("file_glob", "*")
                        if not _pat:
                            return "Error: search_project requires a 'pattern' parameter."
                        _ws_files = database.get_workspace_files(conv_id or "")
                        _proj = next((f for f in _ws_files if f.get("file_type") == "code_project"), None)
                        if not _proj:
                            return "No active project found. Create a project first with create_project."
                        _proj_dir = _proj.get("path") or ""
                        if not os.path.isdir(_proj_dir):
                            return "Error: project directory not found."
                        try: _rx = _re.compile(_pat)
                        except Exception as _e: return f"Error: invalid pattern: {_e}"
                        _results = []
                        for _root, _dirs, _files in os.walk(_proj_dir):
                            _dirs[:] = [d for d in _dirs if not d.startswith('.')]
                            for _fname in _files:
                                if not _fnm.fnmatch(_fname, _glob): continue
                                _fpath = os.path.join(_root, _fname)
                                _rel = os.path.relpath(_fpath, _proj_dir)
                                try:
                                    with open(_fpath, encoding='utf-8', errors='ignore') as _fh:
                                        for _i, _line in enumerate(_fh, 1):
                                            if _rx.search(_line):
                                                _results.append(f"{_rel}:{_i}: {_line.rstrip()}")
                                                if len(_results) >= 50: break
                                except: pass
                                if len(_results) >= 50: break
                            if len(_results) >= 50: break
                        return "\n".join(_results) if _results else "No matches found."


                    if isinstance(args_input, dict):
                        args_str = args_input.get('input_args', str(args_input))
                        args_dict = args_input
                    else:
                        args_str = str(args_input)
                        args_dict = {'filename': args_str, 'input_args': args_str}

                    all_tools = database.get_tools()
                    for t_id, t_data in all_tools.items():
                        safe_name = t_data['name'].replace(" ", "_")
                        if safe_name == name or t_data['trigger_word'] == name:
                            return execute_tool_code(t_data['python_code'], args_str, session.get('user_id'))

                    # MCP tool check (name format: mcp__servername__toolname)
                    if name.startswith("mcp__"):
                        parts = name.split("__", 2)
                        if len(parts) == 3:
                            # Build proper args dict for MCP
                            if isinstance(args_input, dict):
                                # Already a dict from OpenAI tool call — pass directly
                                mcp_args = args_input
                            elif isinstance(args_input, str):
                                raw = args_input.strip()
                                if raw:
                                    try:
                                        parsed = json.loads(raw)
                                        mcp_args = parsed if isinstance(parsed, dict) else {"input": raw}
                                    except (json.JSONDecodeError, ValueError):
                                        mcp_args = {"input": raw}
                                else:
                                    mcp_args = {}
                            else:
                                mcp_args = {"input": str(args_input)}
                            return mcp_manager.call_tool(parts[1], parts[2], mcp_args)

                    return f"Tool '{name}' not found."

                except Exception as e: return f"Error: {e}"

            while True:
                try:
                    api_msgs = format_messages_for_openai(inference_messages)
                    stream = client.chat.completions.create(
                        model=current_model_name,
                        messages=api_msgs,
                        stream=True,
                        tools=get_openai_tools(code_mode_enabled)
                    )

                    tool_calls_accumulator = {}
                    tool_calling_signaled = set()
                    text_tool_detected = None

                    for chunk in stream:
                        if get_streaming_status(user_id, conv_id).get("should_stop", False): break

                        delta = chunk.choices[0].delta
                        reasoning = getattr(delta, 'reasoning_content', None)
                        if reasoning is None and hasattr(delta, 'model_extra') and delta.model_extra:
                            reasoning = delta.model_extra.get('reasoning_content')
                        
                        if reasoning:
                            if not state["has_opened_thought"]:
                                yield "<think>"
                                state["text"] += "<think>"
                                state["has_opened_thought"] = True
                                state["is_thinking"] = True
                            
                            yield reasoning
                            state["text"] += reasoning
                            state["buffer"] += reasoning 

                        content = delta.content or ''
                        if content:
                            if state["has_opened_thought"]:
                                yield "</think>"
                                state["text"] += "</think>"
                                state["has_opened_thought"] = False
                                state["is_thinking"] = False
                            
                            if "<think>" in content: state["is_thinking"] = True
                            if "</think>" in content: state["is_thinking"] = False
                            
                            yield content
                            state["text"] += content
                            state["buffer"] += content

                            if not state["is_thinking"]:
                                for t_word, t_obj in all_active_tools.items():
                                    if t_word == 'write_canvas': continue
                                    pattern = re.escape(t_obj['trigger_word']) + r"\s*\((.*?)\)"
                                    match = re.search(pattern, state["buffer"], re.DOTALL)
                                    if match:
                                        text_tool_detected = {
                                            "name": t_obj['name'].replace(" ", "_"),
                                            "trigger": t_obj['trigger_word'],
                                            "args": match.group(1),
                                            "full_text": match.group(0)
                                        }
                                        break
                        
                        if delta.tool_calls:
                            for tc in delta.tool_calls:
                                idx = tc.index
                                if idx not in tool_calls_accumulator:
                                    tool_calls_accumulator[idx] = {"id": tc.id, "name": "", "args": ""}
                                if tc.function.name: tool_calls_accumulator[idx]["name"] += tc.function.name
                                if tc.function.arguments: tool_calls_accumulator[idx]["args"] += tc.function.arguments
                                # Signal frontend early as soon as we know the function name
                                _fn = tool_calls_accumulator[idx]["name"]
                                if _fn and idx not in tool_calling_signaled:
                                    tool_calling_signaled.add(idx)
                                    yield f"__TOOL_CALLING__|{_fn}"
                        
                        if text_tool_detected: break

                    if state["has_opened_thought"]:
                        yield "</think>"
                        state["text"] += "</think>"
                        state["has_opened_thought"] = False

                    if text_tool_detected:
                        t_name = text_tool_detected['name']
                        full_t = text_tool_detected['full_text']
                        state["buffer"] = ""
                        state["text"] = state["text"].replace(full_t, "")
                        yield f"__ERASE__{full_t}__ERASE__"

                        # Track create_file; skip duplicate present_file
                        _t_args = text_tool_detected['args']
                        if t_name == "create_file":
                            _cf_fn = (_t_args.get("filename") or _t_args.get("name") or "").lower() if isinstance(_t_args, dict) else ""
                            if _cf_fn: presented_files.add(_cf_fn)
                        if t_name == "present_file":
                            _pf_fn = (_t_args.get("filename") or _t_args.get("name") or "").lower() if isinstance(_t_args, dict) else ""
                            if _pf_fn in presented_files:
                                print(f"[TOOL SKIP] Duplicate present_file for '{_pf_fn}' — skipping")
                                continue
                            if _pf_fn: presented_files.add(_pf_fn)

                        yield "__TOOL_START__"
                        # Show tool arguments in JSON format
                        _args_disp = _format_tool_args_display(t_name, text_tool_detected['args'])
                        if _args_disp:
                            yield f"Calling {t_name}...\n{_args_disp}\n"
                        else:
                            yield f"Calling {t_name}...\n"
                        result = execute_hybrid_tool(t_name, text_tool_detected['args'])
                        print(f"[TOOL OUTPUT] {str(result)[:2000]}")

                        result_text = result
                        mcp_images = []
                        workspace_downloads = []
                        _is_view_image = False
                        if isinstance(result, dict):
                            result_text = result.get("text", "")
                            mcp_images = result.get("images", [])
                            workspace_downloads = result.get("downloads", [])
                            # view tool returning an image → feed to model context only, don't show inline
                            if t_name == "view" and mcp_images:
                                _is_view_image = True

                        if isinstance(result_text, str) and "__CANVAS_EDIT__" in result_text:
                            yield "__TOOL_END__"
                            yield result_text
                        elif isinstance(result_text, str) and "__ARTIFACT_CREATE__" in result_text:
                            yield "__TOOL_END__"
                            artifact_html = result_text.split("__ARTIFACT_CREATE__|", 1)[1] if "|" in result_text else result_text
                            yield artifact_html
                            state["text"] += artifact_html
                        elif isinstance(result_text, str) and "__PROJECT_CREATE__" in result_text:
                            yield "__TOOL_END__"
                            proj_json = result_text.split("__PROJECT_CREATE__|", 1)[1] if "|" in result_text else ""
                            yield f"__PROJECT_CREATE__{proj_json}__PROJECT_CREATE__"
                        elif isinstance(result_text, str) and "__PROJECT_UPDATE__" in result_text:
                            yield "__TOOL_END__"
                            _pu_parts = result_text.split("|", 2)
                            _pu_json = _pu_parts[1] if len(_pu_parts) > 1 else ""
                            yield f"__PROJECT_UPDATE__{_pu_json}__PROJECT_UPDATE__"
                        else:
                            yield "__TOOL_OUTPUT_START__"
                            if not _is_view_image:
                                for img_data_url in mcp_images:
                                    try:
                                        img_ext = "png" if "image/png" in img_data_url else "gif" if "image/gif" in img_data_url else "jpg"
                                        img_fname = f"mcp_{uuid.uuid4().hex[:8]}.{img_ext}"
                                        b64_data = img_data_url.split(",", 1)[1] if "," in img_data_url else img_data_url
                                        with open(os.path.join(BROWSER_IMAGE_STORAGE, img_fname), "wb") as _f:
                                            _f.write(base64.b64decode(b64_data))
                                        yield f"__BROWSER_IMG__/browser_images/{img_fname}__BROWSER_IMG__"
                                    except Exception:
                                        pass
                            for dl in workspace_downloads:
                                yield f"__WORKSPACE_FILE__{dl['url']}|{dl['name']}__WORKSPACE_FILE__"
                            yield f"[Result]: {result_text}"
                            yield "__TOOL_OUTPUT_END__"
                            yield "__TOOL_END__"
                        if isinstance(result_text, str) and "__ARTIFACT_CREATE__" not in result_text and "__PROJECT_CREATE__" not in result_text and "__PROJECT_UPDATE__" not in result_text:
                            state["text"] += f'<div class="tool-code-block">...{result_text}</div>'
                        inference_messages.append({"role": "assistant", "content": text_tool_detected['full_text']})

                        if mcp_images:
                            inference_messages.append({"role": "user", "content": f"Tool Output: {result_text}", "images": mcp_images})
                        else:
                            inference_messages.append({"role": "user", "content": f"Tool Output: {result_text}"})

                        current_tool_trace.append({
                            "id": f"call_{uuid.uuid4()}",
                            "name": t_name,
                            "arguments": text_tool_detected['args'],
                            "output": str(result_text)
                        })
                        continue

                    elif tool_calls_accumulator:
                        native_calls = []
                        for idx, data in tool_calls_accumulator.items():
                            native_calls.append({
                                "id": data["id"] or f"call_{uuid.uuid4()}",
                                "type": "function",
                                "function": {"name": data["name"], "arguments": data["args"]}
                            })
                        inference_messages.append({"role": "assistant", "content": None, "tool_calls": native_calls})

                        for tc in native_calls:
                            fname = tc["function"]["name"]
                            try: fargs = json.loads(tc["function"]["arguments"])
                            except: fargs = tc["function"]["arguments"]

                            # Track create_file; skip duplicate present_file
                            if fname == "create_file":
                                _cf_fn = (fargs.get("filename") or fargs.get("name") or "").lower() if isinstance(fargs, dict) else ""
                                if _cf_fn: presented_files.add(_cf_fn)
                            if fname == "present_file":
                                _pf_fn = (fargs.get("filename") or fargs.get("name") or "").lower() if isinstance(fargs, dict) else ""
                                if _pf_fn in presented_files:
                                    print(f"[TOOL SKIP] Duplicate present_file for '{_pf_fn}' — skipping")
                                    inference_messages.append({"role": "tool", "tool_call_id": tc["id"], "name": fname, "content": f"Already presented '{_pf_fn}'. Skipped."})
                                    continue
                                if _pf_fn: presented_files.add(_pf_fn)

                            yield "__TOOL_START__"
                            # Show tool arguments in JSON format
                            _args_disp = _format_tool_args_display(fname, fargs)
                            if _args_disp:
                                yield f"Calling {fname}...\n{_args_disp}\n"
                            else:
                                yield f"Calling {fname}...\n"
                            result = execute_hybrid_tool(fname, fargs)
                            print(f"[TOOL OUTPUT] {str(result)[:2000]}")

                            # Handle browser tool dict result
                            result_text = result
                            mcp_images = []
                            workspace_downloads = []
                            _is_view_image = False
                            if isinstance(result, dict):
                                result_text = result.get("text", "")
                                mcp_images = result.get("images", [])
                                workspace_downloads = result.get("downloads", [])
                                if fname == "view" and mcp_images:
                                    _is_view_image = True

                            if isinstance(result_text, str) and "__CANVAS_EDIT__" in result_text:
                                yield "__TOOL_END__"
                                yield result_text
                            elif isinstance(result_text, str) and "__ARTIFACT_CREATE__" in result_text:
                                yield "__TOOL_END__"
                                artifact_html = result_text.split("__ARTIFACT_CREATE__|", 1)[1] if "|" in result_text else result_text
                                yield artifact_html
                                state["text"] += artifact_html
                            elif isinstance(result_text, str) and "__PROJECT_CREATE__" in result_text:
                                yield "__TOOL_END__"
                                proj_json = result_text.split("__PROJECT_CREATE__|", 1)[1] if "|" in result_text else ""
                                yield f"__PROJECT_CREATE__{proj_json}__PROJECT_CREATE__"
                            elif isinstance(result_text, str) and "__PROJECT_UPDATE__" in result_text:
                                yield "__TOOL_END__"
                                _pu_parts = result_text.split("|", 2)
                                _pu_json = _pu_parts[1] if len(_pu_parts) > 1 else ""
                                yield f"__PROJECT_UPDATE__{_pu_json}__PROJECT_UPDATE__"
                            else:
                                yield "__TOOL_OUTPUT_START__"
                                if not _is_view_image:
                                    for img_data_url in mcp_images:
                                        try:
                                            img_ext = "png" if "image/png" in img_data_url else "gif" if "image/gif" in img_data_url else "jpg"
                                            img_fname = f"mcp_{uuid.uuid4().hex[:8]}.{img_ext}"
                                            b64_data = img_data_url.split(",", 1)[1] if "," in img_data_url else img_data_url
                                            with open(os.path.join(BROWSER_IMAGE_STORAGE, img_fname), "wb") as _f:
                                                _f.write(base64.b64decode(b64_data))
                                            yield f"__BROWSER_IMG__/browser_images/{img_fname}__BROWSER_IMG__"
                                        except Exception:
                                            pass
                                for dl in workspace_downloads:
                                    yield f"__WORKSPACE_FILE__{dl['url']}|{dl['name']}__WORKSPACE_FILE__"
                                yield f"[Result]: {result_text}"
                                yield "__TOOL_OUTPUT_END__"
                                yield "__TOOL_END__"

                            if isinstance(result_text, str) and "__ARTIFACT_CREATE__" in result_text:
                                # Feed back a simple success message to the AI instead of the raw artifact HTML
                                artifact_feedback = "Artifact created successfully and displayed in the chat."
                                inference_messages.append({
                                    "role": "tool", "tool_call_id": tc["id"], "name": fname, "content": artifact_feedback
                                })
                                current_tool_trace.append({
                                    "id": tc["id"],
                                    "name": fname,
                                    "arguments": tc["function"]["arguments"],
                                    "output": artifact_feedback
                                })
                            elif isinstance(result_text, str) and "__PROJECT_CREATE__" in result_text:
                                project_feedback = "Project directory created and opened in the Canvas. Now use create_file to add files."
                                inference_messages.append({
                                    "role": "tool", "tool_call_id": tc["id"], "name": fname, "content": project_feedback
                                })
                            elif isinstance(result_text, str) and "__PROJECT_UPDATE__" in result_text:
                                _pu_msg = result_text.split("|", 2)[2] if result_text.count("|") >= 2 else "Project updated."
                                inference_messages.append({
                                    "role": "tool", "tool_call_id": tc["id"], "name": fname, "content": _pu_msg
                                })
                                current_tool_trace.append({
                                    "id": tc["id"],
                                    "name": fname,
                                    "arguments": tc["function"]["arguments"],
                                    "output": _pu_msg
                                })
                            elif isinstance(result_text, str) and "__CANVAS_EDIT__" in result_text:
                                try:
                                    parts = result_text.split('|__SEP__|')
                                    title_and_old = parts[0].replace('__CANVAS_EDIT__', '')
                                    # Parse title if present
                                    if title_and_old.startswith('title='):
                                        title_end_idx = title_and_old.find('|', 6)
                                        title_val = title_and_old[6:title_end_idx] if title_end_idx > 0 else title_and_old[6:]
                                        old_str_val = title_and_old[title_end_idx+1:] if title_end_idx > 0 else ''
                                    else:
                                        title_val = ''
                                        old_str_val = title_and_old[1:] if title_and_old.startswith('|') else title_and_old
                                    new_str_val = parts[1] if len(parts) > 1 else ''

                                    # Truncate for display if too long
                                    old_display = (old_str_val[:40] + '...') if len(old_str_val) > 40 else old_str_val
                                    new_display = (new_str_val[:40] + '...') if len(new_str_val) > 40 else new_str_val
                                    title_display = f'Title: "{title_val}" | ' if title_val else ''

                                    state["text"] += (
                                        f'<div class="tool-code-block">'
                                        f'<div class="tool-header"><span>Canvas Edit</span></div>'
                                        f'<div class="tool-content">'
                                        f'{title_display}Replaced "{old_display}" → "{new_display}"'
                                        f'</div></div>'
                                    )
                                except:
                                    state["text"] += '<div class="tool-code-block"><div class="tool-header"><span>Canvas Edit</span></div><div class="tool-content">Applied edit</div></div>'
                            else:
                                state["text"] += (
                                    f'<div class="tool-code-block">'
                                    f'<div class="tool-header"><span>Tool Activity</span><span class="tool-toggle-arrow">&#9660;</span></div>'
                                    f'<div class="tool-content">'
                                    f'<div class="tool-result-sep">Result:</div>'
                                    f'{result_text}'
                                    f'</div></div>'
                                )

                            # Skip inference/trace for create_artifact (already handled above)
                            if not (isinstance(result_text, str) and ("__ARTIFACT_CREATE__" in result_text or "__PROJECT_CREATE__" in result_text or "__PROJECT_UPDATE__" in result_text)):
                                # Feed image + guided prompt to vision model
                                if mcp_images:
                                    inference_messages.append({
                                        "role": "tool", "tool_call_id": tc["id"], "name": fname, "content": str(result_text)
                                    })
                                    inference_messages.append({"role": "user", "content": "The MCP tool returned the following image(s):", "images": mcp_images})
                                else:
                                    inference_messages.append({
                                        "role": "tool", "tool_call_id": tc["id"], "name": fname, "content": str(result_text)
                                    })

                                current_tool_trace.append({
                                    "id": tc["id"],
                                    "name": fname,
                                    "arguments": tc["function"]["arguments"],
                                    "output": str(result_text)
                                })
                        continue

                    break
                except Exception as e:
                    yield f"Error: {e}"
                    break

            bot_message = history[-1]
            clean_text = state["text"].replace("__TOOL_START__", "").replace("__TOOL_END__", "").replace("__TOOL_OUTPUT_START__", "").replace("__TOOL_OUTPUT_END__", "")
            
            # OAI Naming Removal: No longer extracting OAI titles from text
            
            oai_title_idx = [0]
            surpluses = []
            def artifact_replacer(match):
                lang_raw = match.group(1) or ""
                code_content = match.group(2)
                
                # Smarter splitting: handle lang:filename OR filename.ext
                lang, filename = parse_lang_tag(lang_raw)
                
                if 'tool-code-block' in code_content or '__CANVAS_EDIT__' in code_content or 'tool-header' in code_content:
                     return match.group(0)
                if '<think>' in code_content or '</think>' in code_content:
                    return match.group(0)

                title = filename or "Canvas Document"

                # Skip unnamed code blocks (no filename) — these are echoed duplicates.
                # Don't create an artifact card or save to DB; keep as a plain code block.
                if not filename:
                    return match.group(0)

                # Treat any non-tool code block as a code artifact
                clean_code = re.sub(r'\n-\d{6}$', '', code_content)
                safe_title = title.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
                artifact_counter[0] += 1
                art_id = f"{unique_id}-{artifact_counter[0]}"

                # --- Save directly to DB ---
                surplus = None
                if conv_id:
                    branch = active_branch
                    is_text_ext = title.lower().endswith(('.txt', '.md'))
                    art_type = "text" if (lang == "text" or is_text_ext) else ("code" if lang else "text")

                    print(f"[DB DEBUG] generate saving artifact: {art_id}, title={safe_title}, conv_id={conv_id}, branch={branch}, type={art_type}")
                    surplus = database.save_canvas_artifact(art_id, conv_id, branch, safe_title, art_type, clean_code)
                    if surplus:
                        surpluses.append(surplus)
                        clean_code = clean_code[:-len(surplus)]
                
                safe_content = clean_code.replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
                tagged_content = safe_content
                
                # Only use "code" type if it's NOT a text extension and has a non-text lang
                is_text_ext = title.lower().endswith(('.txt', '.md'))
                type_attr = ' data-type="code"' if (lang and lang != "text" and not is_text_ext) else ""

                return f'<artifact-card data-id="{art_id}" data-title="{safe_title}" data-content="{tagged_content}"{type_attr}></artifact-card>'
            
            clean_text = re.sub(r'```([^ \n]*)\n?(.*?)```', artifact_replacer, clean_text, flags=re.DOTALL)
            
            # Append detected surpluses to the message text
            if surpluses:
                for s in surpluses:
                    clean_text += f"\n\n{s.strip()}"
            
            clean_text = strip_tool_blocks(clean_text)
            bot_message['text'] = format_text(clean_text)
            bot_message['versions'][0] = bot_message['text']
            bot_message['tool_trace'] = current_tool_trace
            strip_tool_html_from_message(bot_message)

            database.update_history(conv_id, active_branch, history)
            run_strip_db("after message")
            clear_streaming_status(user_id, conv_id)
            yield "" # Final heartbeat to ensure generator drives cleanup

        return Response(stream_with_context(generate()), mimetype='text/plain')

        return Response(stream_with_context(generate()), mimetype='text/plain')

    except Exception as e:
        app.logger.error(f"Chat error: {str(e)}")
        return Response(f"Error: {str(e)}", mimetype='text/plain', status=500)

# New route for user profile page
@app.route('/settings/assistant')
@login_required
def assistant_settings():
    # Get Omni.ai settings from the 'settings' table
    assistant_pfp = database.get_setting('assistant_pfp', '/static/pfp/omniai_logo.png')
    assistant_prompt = database.get_setting('assistant_prompt', "You are Omni.ai, a helpful and advanced AI assistant.")
    
    # Get all tools to show in the settings
    all_tools = database.get_tools()
    system_tools = SYSTEM_TOOLS
    
    # Get MCP tools
    try:
        mcp_tools = mcp_manager.get_all_tools()
    except Exception:
        mcp_tools = {}
    
    # Check which tools are enabled for the assistant (default to all)
    assistant_tools = json.loads(database.get_setting('assistant_enabled_tools', '[]'))
    if not assistant_tools:
        assistant_tools = list(all_tools.keys()) + list(system_tools.keys()) + list(mcp_tools.keys()) + ["write_canvas"]

    # Get current user for diagnostic info
    user = database.get_user(session['user_id'])

    return render_template_string(html_template, page='assistant_settings',
                                 username=session.get('username', 'User'),
                                 assistant_pfp=assistant_pfp,
                                 assistant_prompt=assistant_prompt,
                                 all_tools=all_tools,
                                 system_tools=system_tools,
                                 mcp_tools=mcp_tools,
                                 assistant_tools=assistant_tools,
                                 user=user)

@app.route('/api/code_mode', methods=['GET', 'POST'])
@login_required
def code_mode_setting():
    """Get or toggle Code Mode (Cloudflare-style single execute_code tool)."""
    if request.method == 'GET':
        enabled = database.get_setting('code_mode_enabled', 'false') == 'true'
        return jsonify({"code_mode_enabled": enabled})
    data = request.get_json() or {}
    enabled = bool(data.get('enabled', False))
    database.set_setting('code_mode_enabled', 'true' if enabled else 'false')
    return jsonify({"success": True, "code_mode_enabled": enabled})


@app.route('/api/assistant/update', methods=['POST'])
@login_required
def update_assistant_settings():
    try:
        data = request.form
        prompt = data.get('assistant_prompt')
        enabled_tools = request.form.getlist('enabled_tools')
        
        if prompt:
            database.set_setting('assistant_prompt', prompt)
        
        database.set_setting('assistant_enabled_tools', json.dumps(enabled_tools))
        
        # Handle photo upload
        if 'photo' in request.files:
            file = request.files['photo']
            if file and file.filename:
                filename = secure_filename(f"assistant_pfp_{int(time.time())}_{file.filename}")
                file.save(os.path.join(BOT_STORAGE, filename))
                database.set_setting('assistant_pfp', f"/storage/bots/{filename}")

        return jsonify({"success": True})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)})

@app.route("/user-profile")
@login_required
def user_profile():
    user_id = session['user_id']
    user = database.get_user(user_id)
    profile_photo = f"/storage/profiles/{user['photo']}" if user and user.get('photo') else ''
    
    all_bots = database.get_bots()
    user_bots = []
    
    for b_id, b_data in all_bots.items():
        if b_data.get('owner_id') == user_id:
            bot_obj = b_data.copy()
            bot_obj['id'] = b_id
            
            # --- THE FIX: Normalize 'instructions' vs 'system_prompt' ---
            # The DB saves it as 'instructions', but the form expects 'system_prompt'
            if 'instructions' in bot_obj and not bot_obj.get('system_prompt'):
                bot_obj['system_prompt'] = bot_obj['instructions']
            
            # Ensure it's never None to prevent template errors
            if not bot_obj.get('system_prompt'):
                bot_obj['system_prompt'] = ""
                
            user_bots.append(bot_obj)
            
    return render_template_string(html_template, page='user_profile',
                                  username=user_id,
                                  profile_photo=profile_photo,
                                  my_bots=user_bots)


