# New route for uploading profile photo
@app.route("/upload-profile-photo", methods=['POST'])
@login_required
def upload_profile_photo():
    user_id = session['user_id']
    if 'photo' not in request.files:
        return jsonify({"success": False, "error": "No photo provided"}), 400
    
    photo = request.files['photo']
    if photo.filename == '':
        return jsonify({"success": False, "error": "No file selected"}), 400
    
    # Remove old photo if exists
    user = database.get_user(user_id)
    old_photo = user.get('photo') if user else None
    if old_photo and os.path.exists(os.path.join(PROFILE_STORAGE, old_photo)):
        os.remove(os.path.join(PROFILE_STORAGE, old_photo))
    
    filename = f"{user_id}_{uuid.uuid4()}.jpg"
    photo.save(os.path.join(PROFILE_STORAGE, filename))
    database.update_user_photo(user_id, filename)

    
    return jsonify({"success": True})

@app.route("/get-user-photo", methods=['GET'])
@login_required
def get_user_photo():
    user_id = session['user_id']
    user = database.get_user(user_id)
    photo = user.get('photo') if user else None
    if photo:
        return jsonify({"photo": f"/storage/profiles/{photo}"})
    return jsonify({"photo": ""})


# Authentication routes
@app.route("/login", methods=["GET", "POST"])
@rate_limit("login", 12, 60)
def login():
    if request.method == "GET":
        next_url = _safe_next_url(request.args.get("next"), "/app")
        intent_bot = None
        if next_url.startswith("/characters/") and next_url.endswith("/chat"):
            bot_id = next_url.split("/")[2]
            intent_bot = database.get_bot(bot_id)
        return render_template_string(
            AUTH_TEMPLATE,
            css=PUBLIC_SITE_CSS,
            next_url=next_url,
            intent_bot=intent_bot,
        )

    data = request.get_json() or {}
    username = data.get("username")
    password = data.get("password")
    user = database.get_user_by_username(username)
    if not user or not check_password_hash(user['password'], password):
        return jsonify({"success": False, "error": "Invalid credentials"}), 401
    session['user_id'] = user['id'] # Use the original user_id (id)
    session['username'] = user.get('username', user['id'])
    next_url = _safe_next_url(data.get("next"), "/app")
    return jsonify({"success": True, "redirect_to": next_url})


