@app.route("/create-bot", methods=['GET', 'POST'])
@login_required
def create_bot():
    if request.method == 'POST':
        try:
            bot_id = str(uuid.uuid4())
            name = request.form['name']
            description = request.form.get('description', '')
            instructions = request.form.get('system_prompt', '')
            tagline = request.form.get('tagline', '')
            greeting_message = request.form.get('greeting_message', '')
            tags = request.form.get('tags', '')
            chat_starters = _serialize_chat_starters(request.form.get('chat_starters', ''))
            is_public = 1 if request.form.get('is_public') == 'true' else 0
            owner_id = session['user_id']
            photo_filename = ""

            if 'photo' in request.files:
                photo = request.files['photo']
                if photo.filename != '':
                    photo_filename = f"{bot_id}_{photo.filename}"
                    save_path = os.path.join(BOT_STORAGE, photo_filename)
                    print(f"📸 Attempting to save bot photo to: {save_path}")
                    photo.save(save_path)

            database.add_bot(bot_id, name, description, instructions, photo_filename, owner_id,
                             tagline=tagline, greeting_message=greeting_message, tags=tags,
                             is_public=is_public, chat_starters=chat_starters)
            return jsonify({"success": True})
        except Exception as e:
            print(f"❌ Error in create_bot route: {e}")
            return jsonify({"success": False, "error": str(e)}), 500

    
    return render_template_string(html_template, page='create_bot')

