# Workspace-backed execution routes

@app.route("/run-code-interactive", methods=["POST"])
@login_required
@rate_limit("workspace-interactive", 20, 60)
def run_code_interactive():
    data = request.json or {}
    user = current_user()
    try:
        conv_id = _resolve_conversation_id(data)
        workspace = _ensure_workspace(conv_id, user["id"])
        code = data.get("code", "")
        language = data.get("language", "python").lower()
        if not code:
            return jsonify({"success": False, "error": "No code provided"}), 400
        if language != "python":
            return jsonify({"success": False, "error": f"Execution of {language} is not supported yet."}), 400
        bootstrap = "cat > __interactive_runner.py <<'PY'\n" + code + "\nPY\npython3 -u __interactive_runner.py"
        runtime_result = workspace_runtime.start_process(workspace["id"], bootstrap)
        database.add_workspace_process(
            runtime_result["process_id"],
            workspace["id"],
            "python3 -u __interactive_runner.py",
            "",
            workspace_runtime.backend,
            status="running",
        )
        database.touch_workspace(workspace["id"])
        return jsonify({"success": True, "pid": runtime_result["process_id"], "workspace_id": workspace["id"]})
    except WorkspaceRuntimeError as e:
        return jsonify({"success": False, "error": str(e)}), 403
    except Exception as e:
        return jsonify({"success": False, "error": str(e)}), 500

@app.route("/process-output/<pid>", methods=["GET"])
@login_required
def process_output(pid):
    try:
        proc_row = database.get_workspace_process(pid)
        if not proc_row:
            return jsonify({"success": False, "error": "Process not found or expired", "running": False})
        workspace = database.get_workspace_by_id(proc_row["workspace_id"])
        if not workspace or workspace.get("owner_user_id") != session.get("user_id"):
            return jsonify({"success": False, "error": "Forbidden", "running": False}), 403
        workspace_output = workspace_runtime.read_process_output(pid)
        status = "running" if workspace_output["running"] else "completed"
        database.update_workspace_process(pid, status, workspace_output.get("exit_code"))
        return jsonify({
            "success": True,
            "output": workspace_output.get("output", ""),
            "running": workspace_output.get("running", False),
        })
    except WorkspaceRuntimeError as e:
        return jsonify({"success": False, "error": str(e), "running": False})

@app.route("/process-input/<pid>", methods=["POST"])
@login_required
def process_input(pid):
    data = request.json or {}
    input_text = data.get("input", "")
    if not input_text.endswith('\n'):
        input_text += '\n'
    try:
        proc_row = database.get_workspace_process(pid)
        workspace = database.get_workspace_by_id(proc_row["workspace_id"]) if proc_row else None
        if not workspace or workspace.get("owner_user_id") != session.get("user_id"):
            return jsonify({"success": False, "error": "Forbidden"}), 403
        workspace_runtime.send_process_input(pid, input_text)
        return jsonify({"success": True})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)})

