@app.route("/run-code", methods=["POST"])
@login_required
@rate_limit("workspace-exec", 40, 60)
def run_code():
    data = request.json or {}
    user = current_user()
    try:
        conv_id = _resolve_conversation_id(data)
        workspace = _ensure_workspace(conv_id, user["id"])
        code = data.get("code", "")
        language = data.get("language", "python").lower()
        if not code:
            return jsonify({"success": False, "error": "No code provided"}), 400
        if language != "python":
            return jsonify({"success": False, "error": f"Execution of {language} is not supported yet."}), 400
        command = "cat > __run_code.py <<'PY'\n" + code + "\nPY\npython3 __run_code.py"
        result = workspace_runtime.run_command(workspace["id"], command)
        process_id = str(uuid.uuid4())
        database.add_workspace_process(
            process_id,
            workspace["id"],
            "python3 __run_code.py",
            "",
            result.get("backend", workspace_runtime.backend),
            status=result.get("status", "completed"),
        )
        database.update_workspace_process(process_id, result.get("status", "completed"), result.get("exit_code"))
        output = result.get("output", "")
        return jsonify({
            "success": result.get("exit_code") == 0,
            "output": output if output.strip() else "[Execution completed with no output]",
            "error": output if result.get("exit_code") not in (0, None) else None,
            "workspace_id": workspace["id"],
        })
    except WorkspaceRuntimeError as e:
        return jsonify({"success": False, "error": str(e), "output": f"Workspace Error: {str(e)}"}), 403
    except Exception as e:
        return jsonify({"success": False, "error": str(e), "output": f"Internal Error: {str(e)}"}), 500


