@app.route('/diagnostic', methods=['GET', 'POST'])
@login_required
def diagnostic():
    user_id = session['user_id']
    user = database.get_user(user_id)
    is_retake = request.args.get('retake') == 'true'
    # If user record missing, clear session and show login
    if not user:
        session.pop('user_id', None)
        return redirect('/login')

    # Don't let users retake it accidentally if already done, UNLESS explicitly retaking
    if user.get('diagnostic_completed') and not is_retake and request.method == 'GET':
        return redirect('/app')
        
    if request.method == 'POST':
        familiarity = request.form.get('familiarity', 'Intermediate')
        persona = request.form.get('persona', 'Teaching Assistant')
        interests = request.form.get('interests', '')
        
        database.update_user_diagnostic(user_id, familiarity, persona, interests)
        return redirect('/app')
        
    return render_template_string(html_template, page='diagnostic')

# --- HELPER FOR TOOL PROMPTING ---
def construct_tool_followup(original_context, tool_name, tool_args, tool_result, user_q):
    # This creates a "Ghost" history that exists ONLY for this generation step
    # It tricks the model into thinking it just performed the action, but keeps the real history clean.
    temp_hist = original_context + f"\nBot: [Internal Thought: I will use {tool_name}({tool_args})]\nSystem: [Tool Output: {tool_result}]"
    
    # Strong instruction to prevent regurgitation
    final_prompt = (
        f"COMMAND: The tool has returned the following result: {tool_result}\n"
        f"INSTRUCTION: Answer the user's question ('{user_q}') naturally using this result. "
        f"DO NOT repeat the tool output verbatim. DO NOT say 'The tool returned'. Just give the answer."
    )
    return temp_hist, final_prompt



