# In your app.py, find the @app.route("/delete_message", ...) function

@app.route("/delete_message", methods=["POST"])
@login_required
def delete_message():
    try:
        user_id = session['user_id']
        data = request.get_json()
        message_index = data.get("message_index")
        conv_id = session.get("conversation_id")

        if not conv_id or message_index is None:
            return jsonify({"success": False, "error": "Missing parameters"}), 400

        try:
            message_index = int(message_index)
        except ValueError:
            return jsonify({"success": False, "error": "Invalid message index"}), 400

        conversation = database.get_conversation(conv_id)
        if not conversation:
            return jsonify({"success": False, "error": "Conversation not found"}), 404

        active_branch = conversation.get("active_branch", "main")
        history = conversation.get("branches", {}).get(active_branch, {}).get("history", [])

        if message_index < 0 or message_index >= len(history):
            return jsonify({"success": False, "error": "Invalid message index"}), 400

        # Remove the message
        del history[message_index]

        database.update_history(conv_id, active_branch, history)
        
        # Return updated history so the client can re-render
        return jsonify({"success": True, "history": history})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)}), 500


@app.route("/update_message_content", methods=["POST"])
@login_required
def update_message_content():
    try:
        user_id = session['user_id']
        data = request.get_json()
        message_index = data.get("message_index")
        new_content = data.get("content")
        conv_id = session.get("conversation_id")

        if not conv_id or message_index is None or new_content is None:
            return jsonify({"success": False, "error": "Missing parameters"}), 400

        try:
            message_index = int(message_index)
        except ValueError:
            return jsonify({"success": False, "error": "Invalid message index"}), 400

        conversation = database.get_conversation(conv_id)
        if not conversation:
            return jsonify({"success": False, "error": "Conversation not found"}), 404

        active_branch = conversation.get("active_branch", "main")
        history = conversation.get("branches", {}).get(active_branch, {}).get("history", [])

        if message_index < 0 or message_index >= len(history):
            return jsonify({"success": False, "error": "Invalid message index"}), 400

        # Update the message
        # Use 'sender' and 'bot' instead of 'role' and 'assistant' to match codebase
        if history[message_index]['sender'] == 'bot':
            history[message_index]['text'] = new_content
            # Optionally update versions if you want to track edits history
            if 'versions' in history[message_index]:
                 history[message_index]['versions'][-1] = new_content

            # --- NEW: Extract artifacts from manually edited content ---
            import re
            art_matches = re.findall(r'<artifact-card\s+data-id="([^"]*)"\s+data-title="([^"]*)"\s+data-content="([^"]*)"(?:[^>]*data-type="([^"]*)")?[^>]*>', new_content)
            for art_id, safe_title, tagged_content, art_type in art_matches:
                # Unescape HTML entities in title and content if necessary
                # For now, we assume the DB handle handles it or they are stored as provided
                title = safe_title.replace('&quot;', '"').replace('&lt;', '<').replace('&gt;', '>').replace('&amp;', '&')
                clean_code = re.sub(r'\n-[a-z0-9]{8,12}(-\d+)?$', '', tagged_content)
                clean_code = clean_code.replace('&quot;', '"').replace('&lt;', '<').replace('&gt;', '>').replace('&amp;', '&')
                
                art_type = art_type or "code"
                print(f"[DB DEBUG] update_message_content saving artifact: {art_id}, title={title}, conv_id={conv_id}")
                database.save_canvas_artifact(art_id, conv_id, active_branch, title, art_type, clean_code)
        
        database.update_history(conv_id, active_branch, history)
        return jsonify({"success": True})

    except Exception as e:
        app.logger.error(f"Error updating message: {e}")
        return jsonify({"success": False, "error": str(e)}), 500

        active_branch = conversation.get("active_branch", "main")
        branch = conversation["branches"][active_branch]
        history = branch["history"]
        
        if message_index < 0 or message_index >= len(history):
            return jsonify({"success": False, "error": "Invalid message index"}), 400

        new_history = history[:message_index]
        database.update_history(conv_id, active_branch, new_history)
        
        return jsonify({"success": True, "history": new_history})


    except Exception as e:
        app.logger.error(f"Delete error: {str(e)}")
        return jsonify({"success": False, "error": str(e)}), 500

