@app.route("/sync_branch_files", methods=["POST"])
@login_required
def sync_branch_files():
    try:
        user_id = session['user_id']
        data = request.get_json()
        target_filenames = set(data.get("filenames", []))
        
        all_attachments = database.load_user_attachments(user_id, 'pdf') + database.load_user_attachments(user_id, 'image')
        
        for att in all_attachments:
            should_be_active = 1 if att['filename'] in target_filenames else 0
            if att['active'] != should_be_active:
                database.update_attachment_status(user_id, att['filename'], att['file_type'], att.get('package_id'), att.get('sent', 0), should_be_active)
                
        return jsonify({"success": True})
    except Exception as e:
        app.logger.error(f"Sync error: {e}")
        return jsonify({"success": False, "error": str(e)}), 500





    
@app.route("/set_message_version", methods=["POST"])   
@login_required
def set_message_version():
    user_id = session['user_id']
    data = request.get_json()
    message_index = data.get("message_index")
    version_index = data.get("version_index")
    conv_id = session.get("conversation_id")

    if not conv_id or message_index is None or version_index is None:
        return jsonify({"success": False, "error": "Missing parameters"}), 400

    try:
        message_index = int(message_index)
        version_index = int(version_index)
    except ValueError:
        return jsonify({"success": False, "error": "Invalid indices"}), 400

    conversation = database.get_conversation(conv_id)
    if not conversation:
        return jsonify({"success": False, "error": "Conversation not found"}), 404
        
    active_branch = conversation.get("active_branch", "main")
    history = conversation["branches"][active_branch]["history"]

    if message_index < 0 or message_index >= len(history):
         return jsonify({"success": False, "error": "Invalid message index"}), 400

    message = history[message_index]
    if "versions" not in message or version_index < 0 or version_index >= len(message["versions"]):
        return jsonify({"success": False, "error": "Invalid version index"}), 400

    message["active_version"] = version_index
    message["text"] = message["versions"][version_index]

    new_bot_text = None
    if message["sender"] == "user" and message_index + 1 < len(history) and history[message_index + 1]["sender"] == "bot":
        system_prompt = conversation.get("system_prompt", "")
        
        chat_context = "\n".join([f"{msg['sender']}: {msg['text']}" for msg in history[:message_index]])
        
        prompt_content = f"""System: {system_prompt}
        
        Conversation History:
        {chat_context}
        
        Question: {message["text"]}
        
        Answer:"""
        
        try:
            client, current_model_name = get_openai_client()
            response = client.chat.completions.create(
                model=current_model_name,
                messages=[{"role": "user", "content": prompt_content}],
                stream=False
            )
            new_bot_text = format_text(response.choices[0].message.content)
            
            history[message_index + 1]["text"] = new_bot_text
            history[message_index + 1]["versions"] = [new_bot_text]
            history[message_index + 1]["active_version"] = 0
            
        except Exception as e:
            app.logger.error(f"Error regenerating bot response: {e}")
            return jsonify({"success": False, "error": str(e)}), 500

    database.update_history(conv_id, active_branch, history)

    return jsonify({
        "success": True, 
        "new_text": message["text"],
        "new_bot_text": new_bot_text
    })

# --- HELPER FUNCTION: Add this near your other helper functions ---
def find_last_canvas_state(history, limit_index):
    """
    Iterates backwards from limit_index - 1 to find the last known canvas state.
    Returns the content string or "" if no previous state is found.
    """
    import html
    import re
    
    # Iterate backwards starting from the message immediately before the target index
    for i in range(limit_index - 1, -1, -1):
        msg = history[i]
        text = msg.get('text', '') or ""
        
        # Priority 1: Check for <artifact-card> with data-content
        # We use a non-greedy match for the tag, then specific extraction for data-content
        # usage of [^"]* is risky if quotes are inside, even escaped. 
        # Better strategy: Find the start, find the nearest closing quote that isn't escaped?
        # Actually, standard HTML attributes use &quot; for internal quotes.
        match = re.search(r'data-content="([^"]*)"', text)
        if match:
            raw_content = match.group(1)
            # Unescape twice just to be safe (once for attribute, once for content)
            decoded = html.unescape(raw_content)
            if decoded.strip(): return decoded

        # Priority 2: Check for Markdown Code Blocks
        # We take the content of the *last* code block in the message
        code_matches = re.findall(r'```(?:\w+)?\n?(.*?)```', text, re.DOTALL)
        if code_matches and code_matches[-1].strip():
            return code_matches[-1]

        # Priority 3: Check for explicit tool outputs (edit_canvas)
        # If the history contains a successful edit_canvas call, we can try to reconstruct?
        # (For now, we assume the bot message text was updated with the artifact card, which is standard behavior)

    return ""

