@app.route("/history")
@login_required
def history():
    user_id = session['user_id']
    conv_id = session.get("conversation_id")
    
    if not conv_id:
        return jsonify({
            "history": [], 
            "bot_name": "Omni.ai", 
            "chat_code": None, 
            "canvas_content": "" 
        })
        
    run_strip_db("page reload")
    run_fix_polluted_artifacts("page reload")
    run_deduplicate_db("page reload")
    conversation = database.get_conversation(conv_id)
    if not conversation:
        return jsonify({"history": [], "bot_name": "Omni.ai", "chat_code": None, "canvas_content": ""})

    
    # 2. Safety check if conversation data is missing
    if not conversation:
        return jsonify({
            "history": [], 
            "bot_name": "Omni.ai", 
            "chat_code": None, 
            "canvas_content": ""
        })

    # 3. Get Active Branch History
    active_branch = conversation.get("active_branch", "main")
    # Default to main structure if branches are malformed
    branches = conversation.get("branches", {"main": {"history": []}})
    
    if active_branch not in branches:
        active_branch = "main"
        
    history_data = branches[active_branch]["history"]
    
    # 4. Determine Bot Name
    bot_name = conversation.get("bot_name")
    if not bot_name:
        bot_name_match = re.match(r"Chat with (.+)", conversation.get("title") or "")
        bot_name = bot_name_match.group(1) if bot_name_match else "Omni.ai"

    
    # 5. Inject Profile Photos
    user_record = database.get_user(user_id)
    all_bots = database.get_bots()

    for msg in history_data:
        if msg["sender"] == "user":
            user_photo = user_record.get('photo') if user_record else None
            msg["profile_photo"] = f"/storage/profiles/{user_photo}" if user_photo else ''
            
        elif msg["sender"] == "bot":
            bot_id = conversation.get("bot_id")
            if bot_id and bot_id in all_bots and all_bots[bot_id].get('photo'):
                msg["profile_photo"] = f"/storage/bots/{all_bots[bot_id]['photo']}"
            else:
                msg["profile_photo"] = ''

                msg["profile_photo"] = conversation.get("bot_photo") or ''

    # 6. Retrieve Canvas Content (New Feature - Database-driven)
    conn = database.get_db_connection()
    rows = conn.execute("SELECT * FROM canvas_artifacts WHERE conversation_id = %s ORDER BY created_at ASC", (conv_id,)).fetchall()
    conn.close()
    
    if rows:
        reconstructed_artifacts = {}
        active_id = None
        for row in rows:
            art_id = row['id']
            try:
                history = json.loads(row['history_json'])
            except Exception:
                history = []
            
            reconstructed_artifacts[art_id] = {
                "id": art_id,
                "title": row['title'],
                "type": row['type'],
                "lang": row['lang'],
                "history": history,
                "historyIndex": len(history) - 1 if history else -1
            }
            active_id = art_id
            
        c_data = {
            "version": 2,
            "artifacts": reconstructed_artifacts,
            "activeId": active_id
        }
        canvas_content = json.dumps(c_data)
    else:
        canvas_content = conversation.get("canvas_content", "")
    
    return jsonify({
        "history": history_data,
        "bot_name": bot_name,
        "chat_code": conversation.get("chat_code"),
        "canvas_content": canvas_content  # <--- Critical for Canvas persistence
    })

