@app.route("/new_chat_with_bot", methods=["POST"])
@login_required
def new_chat_with_bot():
    try:
        user_id = session['user_id']
        data = request.get_json()
        
        # 1. Try to get ID, fall back to Name check
        bot_id = data.get("bot_id")
        bot_name = data.get("bot_name")
        
        all_bots = database.get_bots()
        
        # If we only have a name (from the sidebar button), find the matching ID
        if not bot_id and bot_name:
            for b_id, b_data in all_bots.items():
                if b_data.get('name') == bot_name:
                    bot_id = b_id
                    break
        
        # Now try to get the bot
        if bot_id:
            bot = all_bots.get(bot_id)
        elif bot_name == 'Omni.ai':
            # Default Omni.ai bot
            bot = {"name": "Omni.ai", "id": None}
        else:
            bot = None

        if not bot:
            return jsonify({"error": "Bot not found"}), 404

        new_conversation_id = str(uuid.uuid4())
        chat_code = f"{random.randint(100000, 999999)}"
        bot_name = bot.get('name') or "AI"
        title = f"Chat with {bot_name}"
        chat_type = data.get("chat_type", "chat")

        database.add_conversation(new_conversation_id, user_id, bot_id, title, chat_code, chat_type=chat_type)
        session["conversation_id"] = new_conversation_id

        return jsonify({"success": True, "conversation_id": new_conversation_id, "chat_code": chat_code}), 200

    except Exception as e:
        app.logger.error(f"New chat error: {str(e)}")
        return jsonify({"error": f"Failed to create new chat: {str(e)}"}), 500


