@app.route("/upload_pdf", methods=["POST"])
@login_required
def upload_pdf():
    user_id = session['user_id']
    if 'pdf' not in request.files:
        return jsonify({"success": False, "error": "No PDF file provided"}), 400
    
    pdf_file = request.files['pdf']
    if pdf_file.filename == '':
        return jsonify({"success": False, "error": "No file selected"}), 400
    
    if not pdf_file.filename.lower().endswith('.pdf'):
        return jsonify({"success": False, "error": "Only PDF files are allowed"}), 400

    conv_id = session.get("conversation_id")
    chat_code = None
    if conv_id:
        conversation = database.get_conversation(conv_id)
        if conversation:
            chat_code = conversation.get("chat_code")
            
    original_filename = pdf_file.filename
    display_filename = original_filename
    if chat_code:
        name, ext = os.path.splitext(original_filename)
        display_filename = f"{name}-{chat_code}{ext}"

    # Save to workspace dir (per-user, per-conversation)
    ws_dir = os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default"))
    os.makedirs(ws_dir, exist_ok=True)
    ws_fname = secure_filename(original_filename)
    if not ws_fname:
        ws_fname = display_filename
    ws_path = os.path.join(ws_dir, ws_fname)
    if os.path.exists(ws_path):
        base, ext = os.path.splitext(ws_fname)
        counter = 1
        while os.path.exists(ws_path):
            ws_path = os.path.join(ws_dir, f"{base}_{counter}{ext}")
            counter += 1
        ws_fname = os.path.basename(ws_path)
    pdf_file.save(ws_path)
    file_path = ws_path

    pdfs = database.load_user_attachments(user_id, 'pdf')
    if pdfs:
        last_number = max(pdf.get('number', 0) for pdf in pdfs)
        new_number = last_number + 1
    else:
        new_number = 1

    database.save_user_attachment(user_id, display_filename, 'pdf', chat_code, None, 0, 0, file_path, {"number": new_number}, display_name=original_filename)

    if 'just_uploaded_pdfs' not in session:
        session['just_uploaded_pdfs'] = []
    session['just_uploaded_pdfs'].append(display_filename)
    session.modified = True
    
    return jsonify({
        "success": True, 
        "filename": display_filename, 
        "pdfNumber": new_number,
        "chat_code": chat_code
    })


@app.route("/upload_code", methods=["POST"])
@login_required
def upload_code():
    user_id = session['user_id']
    if 'code_zip' not in request.files:
        return jsonify({"success": False, "error": "No file provided"}), 400

    zip_file = request.files['code_zip']
    if not zip_file.filename.lower().endswith('.zip'):
        return jsonify({"success": False, "error": "Only ZIP files are allowed"}), 400

    conv_id = session.get("conversation_id")
    project_name = secure_filename(os.path.splitext(zip_file.filename)[0]) or "project"
    project_id = str(uuid.uuid4())[:8]

    ws_dir = os.path.join(WORKSPACE_STORAGE, str(user_id), str(conv_id or "default"), "code_projects", f"{project_name}_{project_id}")
    os.makedirs(ws_dir, exist_ok=True)

    try:
        with zipfile.ZipFile(zip_file, 'r') as zf:
            real_ws = os.path.realpath(ws_dir)
            for member in zf.namelist():
                member_path = os.path.realpath(os.path.join(ws_dir, member))
                if not member_path.startswith(real_ws):
                    continue
                zf.extract(member, ws_dir)
    except zipfile.BadZipFile:
        return jsonify({"success": False, "error": "Invalid or corrupted ZIP file"}), 400

    def build_tree(directory, base):
        tree = []
        try:
            entries = sorted(os.listdir(directory), key=lambda x: (os.path.isfile(os.path.join(directory, x)), x.lower()))
        except PermissionError:
            return tree
        for entry in entries:
            if entry.startswith('.') or entry in ('__pycache__', 'node_modules', '.git'):
                continue
            full_path = os.path.join(directory, entry)
            rel_path = os.path.relpath(full_path, base)
            if os.path.isdir(full_path):
                tree.append({"name": entry, "type": "dir", "path": rel_path, "children": build_tree(full_path, base)})
            else:
                tree.append({"name": entry, "type": "file", "path": rel_path})
        return tree

    file_tree = build_tree(ws_dir, ws_dir)

    chat_code = None
    if conv_id:
        conversation = database.get_conversation(conv_id)
        if conversation:
            chat_code = conversation.get("chat_code")

    database.save_user_attachment(
        user_id, project_name, 'code_project', chat_code,
        None, 0, 1, ws_dir,
        {"project_id": project_id, "file_tree": file_tree},
        display_name=project_name
    )

    return jsonify({
        "success": True,
        "project_name": project_name,
        "project_id": project_id,
        "file_tree": file_tree,
        "ws_dir": ws_dir
    })


@app.route("/get_code_file", methods=["POST"])
@login_required
def get_code_file():
    user_id = session['user_id']
    data = request.get_json()
    ws_dir = data.get("ws_dir", "")
    rel_path = data.get("rel_path", "")

    if not ws_dir or not rel_path:
        return jsonify({"success": False, "error": "Missing parameters"}), 400

    expected_base = os.path.realpath(os.path.join(WORKSPACE_STORAGE, str(user_id)))
    if not os.path.realpath(ws_dir).startswith(expected_base):
        return jsonify({"success": False, "error": "Unauthorized"}), 403

    full_path = os.path.realpath(os.path.join(ws_dir, rel_path))
    if not full_path.startswith(os.path.realpath(ws_dir)):
        return jsonify({"success": False, "error": "Path traversal blocked"}), 400

    try:
        with open(full_path, 'r', encoding='utf-8', errors='replace') as f:
            content = f.read()
        return jsonify({"success": True, "content": content, "filename": os.path.basename(full_path)})
    except Exception as e:
        return jsonify({"success": False, "error": str(e)}), 500


@app.route("/serve_code_project/<path:filepath>")
@login_required
def serve_code_project(filepath):
    """Serve files from a code project directory for iframe preview (HTML/CSS/JS).

    The ws_dir is stored in the session when runCodeProject is triggered,
    so that relative resource paths (CSS, JS, images) resolve automatically.
    """
    user_id = session['user_id']

    # ws_dir can come from query param (initial load) or session (sub-resources)
    ws_dir = request.args.get('ws_dir', '') or session.get('code_project_ws_dir', '')

    if not ws_dir:
        return "Missing ws_dir", 400

    # Store in session for subsequent relative resource loads
    session['code_project_ws_dir'] = ws_dir

    expected_base = os.path.realpath(os.path.join(WORKSPACE_STORAGE, str(user_id)))
    if not os.path.realpath(ws_dir).startswith(expected_base):
        return "Unauthorized", 403

    full_path = os.path.realpath(os.path.join(ws_dir, filepath))
    if not full_path.startswith(os.path.realpath(ws_dir)):
        return "Path traversal blocked", 400

    if not os.path.isfile(full_path):
        return "File not found", 404

    import mimetypes
    mime_type, _ = mimetypes.guess_type(full_path)
    if not mime_type:
        mime_type = 'application/octet-stream'

    return send_file(full_path, mimetype=mime_type)


