@app.route("/toggle_pdf", methods=["POST"])
@login_required
def toggle_pdf():
    user_id = session['user_id']
    data = request.get_json()
    pdf_name = data.get("pdf_name")
    active = data.get("active")
    
    if pdf_name is None or active is None:
        return jsonify({"success": False, "error": "Missing parameters"}), 400
    
    pdfs = database.load_user_attachments(user_id, 'pdf')
    target_pdf = None
    for pdf in pdfs:
        if pdf["name"] == pdf_name:
            target_pdf = pdf
            break
        name, ext = os.path.splitext(pdf["name"])
        if name.endswith("-x"):
            original_guess = name[:-2] + ext
            if original_guess == pdf_name:
                target_pdf = pdf
                break
                
    if target_pdf:
        database.update_attachment_status(user_id, target_pdf["name"], 'pdf', target_pdf.get('package_id'), target_pdf.get('sent', 0), active)
        return jsonify({"success": True})
    
    return jsonify({"success": False, "error": f"PDF '{pdf_name}' not found"}), 404


@app.route("/delete_pdf", methods=["POST"])
@login_required
def delete_pdf():
    user_id = session['user_id']
    data = request.get_json()
    pdf_name = data.get("pdf_name")
    
    if pdf_name is None:
        return jsonify({"success": False, "error": "Missing pdf_name parameter"}), 400
    
    pdfs = database.load_user_attachments(user_id, 'pdf')
    pdf_to_delete = next((pdf for pdf in pdfs if pdf["name"] == pdf_name), None)
    
    if not pdf_to_delete:
        return jsonify({"success": False, "error": "PDF not found"}), 404
    
    pdf_path = pdf_to_delete["path"]
    if os.path.exists(pdf_path):
        os.remove(pdf_path)
    
    conn = database.get_db_connection()
    conn.execute("DELETE FROM attachments WHERE user_id = %s AND filename = %s AND file_type = 'pdf'", (user_id, pdf_name))
    conn.commit()
    conn.close()
    
    return jsonify({"success": True})



