@app.route("/delete_code_project", methods=["POST"])
@login_required
def delete_code_project():
    user_id = session['user_id']
    data = request.get_json()
    project_name = data.get("project_name")

    if not project_name:
        return jsonify({"success": False, "error": "Missing project_name"}), 400

    projects = database.load_user_attachments(user_id, 'code_project')
    target = next((p for p in projects if p.get("name") == project_name or p.get("display_name") == project_name), None)

    if not target:
        return jsonify({"success": False, "error": "Project not found"}), 404

    # Delete project directory
    ws_dir = target.get("path", "")
    if ws_dir and os.path.isdir(ws_dir):
        import shutil
        shutil.rmtree(ws_dir, ignore_errors=True)

    # Delete from database
    conn = database.get_db_connection()
    conn.execute("DELETE FROM attachments WHERE user_id = %s AND filename = %s AND file_type = 'code_project'", (user_id, project_name))
    conn.commit()
    conn.close()

    return jsonify({"success": True})


