@app.route("/change-username", methods=["POST"])
@login_required
def change_username():
    user_id = session['user_id']
    data = request.get_json()
    new_username = data.get("new_username")
    
    if not new_username:
        return jsonify({"success": False, "error": "New username required"}), 400
    
    if database.get_user_by_username(new_username) and new_username != user_id:
        return jsonify({"success": False, "error": "Username already taken"}), 400
    
    conn = database.get_db_connection()
    conn.execute("UPDATE users SET username = %s WHERE id = %s", (new_username, user_id))
    conn.commit()
    conn.close()
    
    return jsonify({"success": True, "new_username": new_username})


@app.route("/delete-account", methods=["POST"])
@login_required
def delete_account():
    user_id = session['user_id']
    user = database.get_user(user_id)
    
    if user and user.get('photo'):
        photo_path = os.path.join(PROFILE_STORAGE, user['photo'])
        if os.path.exists(photo_path):
            os.remove(photo_path)
    
    # Remove user's attachments from disk
    attachments = database.load_user_attachments(user_id, 'pdf') + database.load_user_attachments(user_id, 'image')
    for att in attachments:
        if att.get("path") and os.path.exists(att["path"]):
            os.remove(att["path"])
            
    # Remove user's bots photos
    all_bots = database.get_bots()
    for bot_id, bot in all_bots.items():
        if bot['owner_id'] == user_id:
            if bot.get('photo'):
                photo_path = os.path.join(BOT_STORAGE, bot['photo'])
                if os.path.exists(photo_path):
                    os.remove(photo_path)

    conn = database.get_db_connection()
    # Explicitly delete to handle foreign key constraints if they aren't cascading
    conn.execute("DELETE FROM attachments WHERE user_id = %s", (user_id,))
    conn.execute("DELETE FROM branches WHERE conversation_id IN (SELECT id FROM conversations WHERE user_id = %s)", (user_id,))
    conn.execute("DELETE FROM conversations WHERE user_id = %s", (user_id,))
    conn.execute("DELETE FROM bots WHERE owner_id = %s", (user_id,))
    conn.execute("DELETE FROM tools WHERE owner_id = %s", (user_id,))
    conn.execute("DELETE FROM users WHERE id = %s", (user_id,))
    conn.commit()
    conn.close()

    session.clear()
    return jsonify({"success": True})





@app.route("/update_canvas", methods=["POST"])
@login_required
def update_canvas():
    user_id = session['user_id']
    data = request.get_json()
    # Prioritize ID sent by frontend to prevent race conditions during new chats
    conv_id = data.get("conversation_id") or session.get("conversation_id")
    content = data.get("content")

    if not conv_id:
        return jsonify({"success": False, "error": "No active conversation"}), 400

    # Ensure the user has permission to update this conversation
    conversation = database.get_conversation(conv_id)
    if not conversation or conversation.get("user_id") != user_id:
        return jsonify({"success": False, "error": "Unauthorized"}), 403

    if content:
        database.update_canvas_content(conv_id, content)

    artifacts = data.get("artifacts")
    if not artifacts and content:
        try:
            import json
            parsed = json.loads(content)
            if isinstance(parsed, dict) and "artifacts" in parsed:
                artifacts = parsed["artifacts"]
        except:
            pass

    print(f"[DEBUG] /update_canvas: conv_id={conv_id}, artifacts_count={len(artifacts) if artifacts else 0}")
    if artifacts and isinstance(artifacts, dict):
        # Get active branch to associate with these artifacts
        active_branch = "main"
        if conversation:
            active_branch = conversation.get("active_branch") or "main"
            
        for art_id, art in artifacts.items():
            title = art.get("title", "Untitled")
            art_type = art.get("type", "code")
            lang = art.get("lang")
            # Get latest content from history or content field
            art_content = ""
            if art.get("history") and isinstance(art.get("history"), list):
                art_content = art["history"][-1]
            elif art.get("content"):
                art_content = art["content"]
                
            print(f"[DEBUG] Processing artifact {art_id}: title={title}, content_len={len(art_content) if art_content else 0}")
            if art_content:
                # Guard: Don't overwrite if DB has more history versions (tool calls added versions the frontend doesn't have yet)
                _guard_conn = database.get_db_connection()
                _guard_row = _guard_conn.execute("SELECT history_json FROM canvas_artifacts WHERE id = %s", (art_id,)).fetchone()
                _guard_conn.close()
                if _guard_row and _guard_row['history_json']:
                    try:
                        _db_hist = json.loads(_guard_row['history_json'])
                        _fe_hist_len = len(art.get("history", [])) if art.get("history") else 0
                        if len(_db_hist) > _fe_hist_len:
                            print(f"[DEBUG] Skipping /update_canvas for {art_id}: DB has {len(_db_hist)} versions, frontend sent {_fe_hist_len}")
                            continue
                    except Exception:
                        pass
                database.save_canvas_artifact(art_id, conv_id, active_branch, title, art_type, art_content, lang=lang)

    return jsonify({"success": True})


